import { MealAnalysis } from "../../types";
import { callAiProxy, parseJSON } from "./client";

/**
 * カロリー丸め処理ロジック
 * ユーザー要望: 
 * - 10kcal未満: 1kcal単位 (そのまま)
 * - 10kcal以上: 25kcal単位に丸める
 */
const roundCalories = (val: number): number => {
  if (typeof val !== 'number' || isNaN(val)) return 0;

  // 10kcal未満は整数に丸めてそのまま返す
  // これにより、非食品(0kcal)の場合は0が返る
  if (val < 10) return Math.round(val);

  // 10kcal以上は25kcal刻みに四捨五入
  // 例: 112 -> 100, 113 -> 125, 130 -> 125, 140 -> 150
  const rounded = Math.round(val / 25) * 25;

  // 計算上0になってしまう場合（10~12kcalなど）は、最小単位の25kcal、または元の値を返す
  return rounded === 0 ? 25 : rounded;
};

/**
 * たべとっと。 食事解析サービス (v4.7 イラスト判定強化版)
 */
export const analyzeMeal = async (base64Image: string): Promise<MealAnalysis> => {
  const cleanBase64 = base64Image.replace(/^data:image\/[a-z]+;base64,/, "").trim();

  const systemInstruction = `あなたは食事写真の解析AIです。
目的は「写真からの料理名・合計カロリー・PFC比率の目安・やさしい一言」を返すことです。

【最重要判定：実物か、それ以外か】
カロリー計算を行うのは「実物の食べ物」だけです。
以下のものは、たとえ食べ物が描かれていても**絶対にカロリー計算してはいけません（0kcalとする）**。

1. **イラスト・絵画・漫画・アニメ画像**（たとえ美味しそうな料理が描かれていても不可）
2. **食品サンプル・模型・メニュー表の写真**
3. **画面のスクリーンショット**（料理が映っていても不可）
4. **食べ物以外の物体・風景・人物・ペット**

これらに該当する場合は、以下の形式で出力してください：
- numericCalories: 0 (固定)
- menuName: 画像の内容を表す名前（例：「美味しそうなイラスト」「食品サンプル」「かわいい猫」など）
- comment: ユーザーを和ませる、ユーモアと遊び心のあるコメントを1文で。
  - 例：「絵に描いた餅…ならぬ絵に描いたごはんは0kcalですね！🎨」
  - 例：「とってもリアルなサンプル！間違って食べないでくださいね笑」
  - 否定的な言葉は避ける。

【実物の食べ物の場合】
- 料理名を推測し、menuNameに設定（短く分かりやすく）。
- 一般的な1人前のカロリーを推測し、numericCaloriesに設定。
- PFCバランス（タンパク質・脂質・炭水化物）の比率(%)を推測。
- 健康的なアドバイスや、ポジティブな感想をcommentに設定。

【厳守：出力形式】
以下のJSON形式のみを出力してください。Markdownタグ（\`\`\`json）は不要です。
{
  "menuName": string,
  "numericCalories": number,
  "pfcRatio": { "p": number, "f": number, "c": number },
  "comment": string
}

※医療的なアドバイスは行わないでください。`;

  const promptText = `この画像を解析し、JSONのみを出力してください。イラストやサンプルの場合はカロリー0でユーモアのあるコメントを返してください。`;

  try {
    const res = await callAiProxy({
      kind: "food",
      text: promptText,
      systemInstruction: systemInstruction,
      images: [cleanBase64],
      model: "gemini-2.5-flash-lite",
      wantJson: true
    });

    const raw = parseJSON<any>(res.answer);

    if (raw.ok === false || raw.error) {
      throw new Error(raw.error?.message || "解析エラーが発生しました");
    }

    // AIの生データを取得し、アプリ側のロジックで丸める
    const rawCalories = typeof raw.numericCalories === 'number' ? raw.numericCalories : 0;
    const displayCalories = roundCalories(rawCalories);

    return {
      menuName: raw.menuName || "不明な料理",
      numericCalories: displayCalories,
      pfcRatio: raw.pfcRatio || { p: 30, f: 20, c: 50 },
      comment: raw.comment || "バランスよく食べていきましょう！",
      mealType: 'lunch'
    };
  } catch (error: any) {
    console.error("Meal analysis error:", error);
    throw error;
  }
};

