export const SharePreviewModal: React.FC<{
  isOpen: boolean;
  onClose: () => void;
  mealAnalysis: MealAnalysis;
  photoBase64: string;
  dateStr: string;
  initialBlob?: Blob | null;
}> = ({ isOpen, onClose, mealAnalysis, photoBase64, dateStr, initialBlob }) => {
  useEffect(() => {
    if (isOpen) {
        hideBanner();
        hideMrec(); // Ensure MREC is hidden
    } else if (Capacitor.isNativePlatform()) {
        showBanner();
    }
  }, [isOpen]);

  const [blob, setBlob] = useState<Blob | null>(initialBlob || null);
  const [previewUrl, setPreviewUrl] = useState<string | null>(null);
  const [isSharing, setIsSharing] = useState(false);
  const [hasSaved, setHasSaved] = useState(false);

  // photoBase64 が URI形式かどうか判定
  const isUriSource = photoBase64 && (photoBase64.startsWith('file:') || photoBase64.startsWith('content:') || photoBase64.startsWith('http'));

  useEffect(() => {
    let objectUrl: string | null = null;
    if (isOpen) {
        if (blob) {
            // 生成済みのBlobがある場合（手動生成フロー）
            objectUrl = URL.createObjectURL(blob);
            setPreviewUrl(objectUrl);
        } else if (isUriSource) {
            // 既にファイルとして保存されている場合（URIをそのまま使う）
            setPreviewUrl(Capacitor.convertFileSrc(photoBase64));
        } else if (photoBase64) {
            // 旧データ（Base64文字列）の場合 -> Blob生成してプレビュー
            const recordsStr = localStorage.getItem('tabetotto_records');
            let weight: number | undefined;
            if (recordsStr) {
              const records = JSON.parse(recordsStr);
              weight = records[dateStr]?.weight;
            }
            const userStr = localStorage.getItem('tabetotto_user');
            const user = userStr ? JSON.parse(userStr) : {};
            generateShareImageBlob(photoBase64, mealAnalysis, dateStr, weight, user.avatarImage, user.showMascotOnShare).then((generatedBlob) => {
                if (generatedBlob) {
                    objectUrl = URL.createObjectURL(generatedBlob);
                    setBlob(generatedBlob);
                    setPreviewUrl(objectUrl);
                }
            });
        }
    }
    return () => {
        if (objectUrl) URL.revokeObjectURL(objectUrl);
        if (blob && !initialBlob) setBlob(null); // Cleanup generated blob
    };
  }, [isOpen, blob, photoBase64, mealAnalysis, dateStr, initialBlob, isUriSource]);

  const handleShare = async () => {
    if ((!blob && !isUriSource) || isSharing) return;
    setIsSharing(true);

    try {
        if (isUriSource) {
            // 既にファイルがある場合はそのパスを直接シェア
            await Share.share({
                title: 'たべとっと。で食事を記録しました',
                text: '今日の食事記録です✨ #たべとっと',
                url: photoBase64, // file:// URI
            });
        } else if (Capacitor.isNativePlatform() && blob) {
            // Blobからファイル書き出し -> シェア
            const reader = new FileReader();
            const base64Promise = new Promise<string>((resolve) => {
                reader.onloadend = () => {
                    const base64String = reader.result as string;
                    resolve(base64String.split(',')[1]);
                };
                reader.readAsDataURL(blob);
            });
            const base64data = await base64Promise;
            const fileName = `tabetotto_share_${dateStr.replace(/-/g, '')}_${Date.now()}.jpg`;

            await Filesystem.writeFile({
                path: fileName,
                data: base64data,
                directory: Directory.Cache,
            });

            const { uri } = await Filesystem.getUri({
                directory: Directory.Cache,
                path: fileName
            });

            await Share.share({
                title: 'たべとっと。で食事を記録しました',
                text: '今日の食事記録です✨ #たべとっと',
                url: uri,
            });
        } else if (navigator.share && navigator.canShare && blob && navigator.canShare({ files: [new File([blob], "share.jpg", { type: "image/jpeg" })] })) {
            const file = new File([blob], "diet_record.jpg", { type: "image/jpeg" });
            await navigator.share({
                files: [file],
                title: 'たべとっと。で食事を記録しました',
                text: '今日の食事記録です✨ #たべとっと'
            });
        } else {
            handleDownload();
        }
    } catch (e: any) {
        if (e.name !== 'AbortError') handleDownload();
    } finally {
        setIsSharing(false);
    }
  };

  const handleDownload = () => {
      if (!previewUrl) return;
      const a = document.createElement('a');
      a.href = previewUrl;
      a.download = `tabetotto_${dateStr}.jpg`;
      a.click();
      setHasSaved(true);
  };

  if (!isOpen) return null;

  return (
    <Modal isOpen={isOpen} onClose={onClose} title="シェアして保存">
       <div className="flex flex-col items-center space-y-4 relative">
           <header className="w-full flex items-center justify-between mb-2">
                <div className="flex items-center gap-2">
                    <div className="w-7 h-7 rounded flex items-center justify-center shadow-sm" style={{ backgroundColor: THEME.colors.primary }}>
                        <Utensils size={14} className="text-white" strokeWidth={3} />
                    </div>
                    <h2 className="font-zen-maru font-black text-sm tracking-widest" style={{ color: THEME.colors.primary }}>たべとっと。</h2>
                </div>
           </header>

           {previewUrl ? (
               // 生成された画像サイズ(3:4)に合わせてコンテナも 3:4 に調整
               <div className="w-full aspect-[3/4] shadow-2xl rounded-2xl overflow-hidden border-4 border-white animate-in zoom-in-95">
                   <img src={previewUrl} className="w-full h-full object-contain bg-[#FFFDF5]" />
               </div>
           ) : (
               <div className="w-full aspect-[3/4] flex flex-col items-center justify-center bg-stone-100 rounded-2xl border" style={{ borderColor: THEME.colors.albumShadow }}>
                   <Loader2 className="animate-spin w-10 h-10 mb-2" style={{ color: THEME.colors.primary }} />
                   <p className="text-xs font-bold" style={{ color: THEME.colors.textLight }}>画像を生成中...</p>
               </div>
           )}

           <div className="grid grid-cols-2 gap-3 w-full pt-2">
               <Button onClick={handleShare} variant="secondary" isLoading={isSharing} disabled={!blob && !isUriSource} className="min-h-[56px] h-auto shadow-md !rounded-3xl py-3">
                   <Share2 size={18} className="mr-2" /> シェア
               </Button>
               <button 
                  onClick={handleDownload} 
                  disabled={!previewUrl}
                  className={`min-h-[56px] h-auto py-3 border-2 font-black text-sm rounded-3xl transition-all flex items-center justify-center shadow-sm active:scale-95 ${hasSaved ? 'bg-secondary text-white border-secondary' : 'bg-white text-stone-600 border-stone-200'}`}
                  style={hasSaved ? { backgroundColor: THEME.colors.secondary, borderColor: THEME.colors.secondary } : {}}
               >
                   {hasSaved ? (
                       <><Check size={18} className="mr-2" /> 保存済み</>
                   ) : (
                       <><Download size={18} className="mr-2" /> 保存</>
                   )}
               </button>
           </div>

           <div className="w-full pt-4">
              <Button onClick={onClose} variant="outline" className="w-full min-h-[48px] h-auto py-3 !border-dashed !rounded-2xl text-xs opacity-60">
                  完了してとじる
              </Button>
           </div>

           <p className="text-[9px] font-bold text-stone-400">※保存ボタンを押しても反応がない場合は、画像を長押しして保存してください</p>
       </div>
    </Modal>
  );
};

import React, { useState, useMemo, useEffect, useRef } from 'react';
import { Utensils, Calendar, Camera, ChevronRight, LayoutList, History as HistoryIcon, ArrowDown, Calculator, Flag, AlertTriangle, Stethoscope, Dumbbell, AlertCircle } from 'lucide-react';
import { 
  Line, 
  XAxis, 
  YAxis, 
  CartesianGrid, 
  ResponsiveContainer, 
  Bar,
  ComposedChart,
  Tooltip,
  Area,
  ReferenceArea,
  ReferenceLine
} from 'recharts';
import { DailyRecord, MealAnalysis, UserProfile } from '../../types';
import { THEME } from '../../theme';
import { Button } from '../UIComponents';
import { calculateCalorieTarget, getTodayString, calculateBMI } from '../../utils';
import { NativeAdCard } from '../AdComponents';
import { showMrec, hideMrec, showBanner, hideBanner } from '../../services/admobService';

interface HistoryViewProps {
  records: DailyRecord[];
  user: UserProfile;
  onMealClick: (meal: MealAnalysis, photo: string, date: string, index: number) => void;
  onPostureClick: (record: DailyRecord) => void;
  isMenuOpen: boolean; // 広告制御のため追加
}

const HistoryView: React.FC<HistoryViewProps> = ({ records, user, onMealClick, onPostureClick, isMenuOpen }) => {
  const [range, setRange] = useState<'7d' | '1m' | '3m' | 'all'>('1m');
  const [page, setPage] = useState(1);
  const ITEMS_PER_PAGE = 10;
  const MAX_RECORDS = 300; 

  // バナー⇄MREC切替ロジック (方式B)
  const bottomSentinelRef = useRef<HTMLDivElement>(null);
  const [isAtBottom, setIsAtBottom] = useState(false);
  const [isAtBottomStable, setIsAtBottomStable] = useState(false);
  const stableTimerRef = useRef<ReturnType<typeof setTimeout> | null>(null);

  // IntersectionObserverで最下部検知
  useEffect(() => {
      const observer = new IntersectionObserver(
          ([entry]) => {
              setIsAtBottom(entry.isIntersecting);
          },
          { threshold: 0.1 }
      );
      if (bottomSentinelRef.current) {
          observer.observe(bottomSentinelRef.current);
      }
      return () => observer.disconnect();
  }, []);

  // 到達後の安定化タイマー (300-500ms滞在で切替)
  useEffect(() => {
      if (isAtBottom) {
          stableTimerRef.current = setTimeout(() => {
              setIsAtBottomStable(true);
          }, 500);
      } else {
          if (stableTimerRef.current) clearTimeout(stableTimerRef.current);
          setIsAtBottomStable(false);
      }
      return () => {
          if (stableTimerRef.current) clearTimeout(stableTimerRef.current);
      };
  }, [isAtBottom]);

  // 広告切替実行 (メニューが開いているときは何もしない=App側で消す)
  useEffect(() => {
      if (isMenuOpen) {
          // メニュー展開中はApp.tsxが全消去するので、ここでは何もしない
          // (または明示的にタイマーリセットなどしても良いが、useEffectの依存関係により再評価される)
          return;
      }

      if (isAtBottomStable) {
          // 最下部で安定 -> Banner消してMREC表示
          showMrec();
      } else {
          // それ以外 -> MREC消してBanner表示
          // ※showBannerは内部でhideMrecを呼ぶが、明示的に呼ぶほうが安全
          showBanner();
      }

      // アンマウント時はBannerに戻す(App.tsxにお任せでも良いが安全策)
      return () => {
          // コンポーネントが消えるとき = 別タブへ移動など
          // cleanupでは何もしない（次の画面のuseEffectに任せる）
      };
  }, [isAtBottomStable, isMenuOpen]);


  const { targetRange, targetDateStr, dietSimulation } = useMemo(() => {
      const tRange = calculateCalorieTarget(user);
      const tDate = user.dietMode?.targetDate ? user.dietMode.targetDate.slice(5).replace('-', '/') : undefined;

      // ダイエットシミュレーション (減量モードのみ)
      let sim = null;
      if (user.dietMode?.enabled && user.dietMode.goal === 'loss' && user.targetWeight && user.dietMode.targetDate) {
          // 最新の体重を取得
          const sorted = [...records].sort((a, b) => new Date(b.date).getTime() - new Date(a.date).getTime());
          const latestWeight = sorted.find(r => r.weight)?.weight || 0;

          if (latestWeight > 0) {
              const weightDiff = latestWeight - user.targetWeight;
              // 1kg = 7400kcal換算
              const totalKcalToBurn = Math.max(0, weightDiff * 7400);

              const today = new Date();
              const target = new Date(user.dietMode.targetDate);
              const daysLeft = Math.ceil((target.getTime() - today.getTime()) / (1000 * 60 * 60 * 24));

              // 目標BMI計算
              const targetBMI = calculateBMI(user.height, user.targetWeight);

              if (daysLeft > 0 && totalKcalToBurn > 0) {
                  const dailyBurn = Math.round(totalKcalToBurn / daysLeft);
                  sim = {
                      latestWeight,
                      weightDiff,
                      daysLeft,
                      dailyBurn,
                      targetBMI,
                      isImpossible: dailyBurn > 1000, // 1000kcal以上は無謀
                      isHard: dailyBurn > 500, // 500kcal以上はきつい
                      isLowBMI: targetBMI < 18.5 // 低体重目標
                  };
              }
          }
      }

      return { 
          targetRange: tRange,
          targetDateStr: tDate,
          dietSimulation: sim
      };
  }, [user, records]);

  const sortedRecords = useMemo(() => {
    return [...records]
      .sort((a, b) => new Date(b.date).getTime() - new Date(a.date).getTime())
      .slice(0, MAX_RECORDS);
  }, [records]);

  const pagedRecords = useMemo(() => {
    return sortedRecords.slice(0, page * ITEMS_PER_PAGE);
  }, [sortedRecords, page]);

  // ネイティブ広告を挿入したリストを生成
  // 10件に1回の割合で挿入（最初の8件目以降）
  const listItemsWithAds = useMemo(() => {
      const items: (DailyRecord | { type: 'ad', id: string })[] = [];
      pagedRecords.forEach((record, index) => {
          items.push(record);
          if (index >= 7 && (index + 1) % 10 === 0) {
              items.push({ type: 'ad', id: `ad-${index}` });
          }
      });
      return items;
  }, [pagedRecords]);

  const chartData = useMemo(() => {
    const sorted = [...records].sort((a, b) => new Date(a.date).getTime() - new Date(b.date).getTime());
    if (sorted.length === 0) return [];
    const now = new Date();
    let cutoff = new Date(now);
    if (range === '7d') cutoff.setDate(now.getDate() - 7);
    else if (range === '1m') cutoff.setMonth(now.getMonth() - 1);
    else if (range === '3m') cutoff.setMonth(now.getMonth() - 3);
    else cutoff = new Date(1970, 0, 1);

    const cutoffStr = cutoff.toISOString().split('T')[0];
    const filtered = sorted.filter(r => r.date >= cutoffStr);

    const getCals = (r: DailyRecord) => r.mealAnalyses ? r.mealAnalyses.reduce((acc, m) => acc + m.numericCalories, 0) : 0;
    return filtered.map(r => ({
        date: r.date.slice(5).replace('-', '/'), // MM/DD
        fullDate: r.date,
        weight: r.weight,
        calories: getCals(r) > 0 ? getCals(r) : undefined,
    }));
  }, [records, range]);

  return (
    <div className="flex flex-col min-h-screen pb-72 w-full no-scrollbar overflow-x-hidden">
      <main className="space-y-4 mt-8 animate-in slide-in-from-bottom duration-300">
        <div className="mx-6 py-10 px-6 border-2 shadow-md overflow-hidden rounded-[48px] bg-white" style={{ borderColor: THEME.colors.border }}>
            <div className="flex justify-center mb-8">
                <div className="bg-stone-50 border-2 px-6 py-1.5 rounded-full transform rotate-1 shadow-sm" style={{ borderColor: THEME.colors.border }}>
                    <span className="font-black text-[10px] tracking-widest uppercase" style={{ color: THEME.colors.textLight }}>Weight & Calories推移</span>
                </div>
            </div>
            <div className="flex justify-center gap-2 mb-10 w-full">
                {(['7d', '1m', '3m', 'all'] as const).map(r => (
                    <button key={r} onClick={() => { setRange(r); setPage(1); }}
                        className={`text-[9px] font-black px-1 py-2 rounded-2xl transition-all border-2 flex-1 shadow-sm ${range === r ? 'text-white' : 'bg-white'}`}
                        style={range === r ? { backgroundColor: THEME.colors.primary, borderColor: THEME.colors.primary } : { color: THEME.colors.textLight, borderColor: THEME.colors.border }}
                    >
                        {r === '7d' ? '7日' : r === '1m' ? '1ヶ月' : r === '3m' ? '3ヶ月' : '全期間'}
                    </button>
                ))}
            </div>
            <div className="h-60 w-full relative">
                <ResponsiveContainer width="100%" height="100%">
                    <ComposedChart data={chartData} margin={{ top: 10, right: -15, left: -15, bottom: 0 }}>
                    <defs>
                      <linearGradient id="weightGradient" x1="0" y1="0" x2="0" y2="1">
                        <stop offset="5%" stopColor={THEME.colors.primary} stopOpacity={0.2}/>
                        <stop offset="95%" stopColor={THEME.colors.primary} stopOpacity={0}/>
                      </linearGradient>
                    </defs>
                    <CartesianGrid strokeDasharray="6 6" stroke="#F0EBE3" vertical={false} />
                    <XAxis dataKey="date" tick={{fontSize: 9, fill: THEME.colors.textLight, fontWeight: 900}} stroke="#E5DDD0" tickLine={false} axisLine={false} dy={10} />

                    <YAxis 
                      yAxisId="weight" 
                      domain={['dataMin - 2', 'dataMax + 2']} 
                      orientation="left" 
                      tick={{fontSize: 9, fill: THEME.colors.primary, fontWeight: 900}} 
                      stroke={THEME.colors.primary} 
                      width={35} 
                      axisLine={false} 
                      tickLine={false} 
                    />

                    <YAxis 
                      yAxisId="calories" 
                      domain={[0, 'auto']} 
                      orientation="right" 
                      tick={{fontSize: 9, fill: THEME.colors.secondary, fontWeight: 900}} 
                      stroke={THEME.colors.secondary} 
                      width={35} 
                      axisLine={false} 
                      tickLine={false} 
                    />

                    <Tooltip 
                      contentStyle={{ borderRadius: '20px', border: 'none', boxShadow: '0 10px 30px -5px rgba(0,0,0,0.15)', fontWeight: 900, fontSize: '11px', backgroundColor: 'white' }}
                      formatter={(value: any, name: string) => {
                        if (name === "weight") return [`${value}kg`, "体重"];
                        if (name === "calories") return [`${value}kcal`, "カロリー"];
                        return [value, name];
                      }}
                    />

                    {targetRange && (
                        <ReferenceArea 
                            yAxisId="calories"
                            y1={targetRange.min}
                            y2={targetRange.max} 
                            fill={THEME.colors.secondary} 
                            fillOpacity={0.1}
                        />
                    )}

                    {targetDateStr && (
                        <ReferenceLine
                            x={targetDateStr}
                            stroke={THEME.colors.secondary}
                            strokeDasharray="3 3"
                            label={{ position: 'top', value: '目標', fontSize: 9, fill: THEME.colors.secondary, fontWeight: 900 }}
                        />
                    )}

                    <Bar yAxisId="calories" dataKey="calories" name="calories" fill={THEME.colors.secondary} radius={[4, 4, 0, 0]} opacity={0.3} barSize={12} />
                    <Area yAxisId="weight" type="monotone" dataKey="weight" fill="url(#weightGradient)" stroke="none" connectNulls />
                    <Line yAxisId="weight" type="monotone" dataKey="weight" name="weight" stroke={THEME.colors.primary} strokeWidth={3} dot={{r: 4, fill: 'white', strokeWidth: 2, stroke: THEME.colors.primary}} connectNulls />
                    </ComposedChart>
                </ResponsiveContainer>
            </div>
            <div className="flex justify-center gap-6 mt-4 flex-wrap">
                <div className="flex items-center gap-1.5">
                    <div className="w-2 h-2 rounded-full" style={{ backgroundColor: THEME.colors.primary }}></div>
                    <span className="text-[8px] font-black opacity-50">体重 (kg)</span>
                </div>
                <div className="flex items-center gap-1.5">
                    <div className="w-2 h-2 rounded-full" style={{ backgroundColor: THEME.colors.secondary, opacity: 0.3 }}></div>
                    <span className="text-[8px] font-black opacity-50">摂取カロリー (kcal)</span>
                </div>
                {targetRange && (
                     <div className="flex items-center gap-1.5">
                        <div className="w-2 h-2 rounded-sm" style={{ backgroundColor: THEME.colors.secondary, opacity: 0.1 }}></div>
                        <span className="text-[8px] font-black opacity-50">目安帯</span>
                    </div>
                )}
            </div>
        </div>

        {/* Diet Mode Simulation Card */}
        {dietSimulation && (
            <div className="mx-6 p-6 rounded-[32px] bg-[#FFF8F0] border-2 border-[#FFE0B2] shadow-sm relative overflow-hidden">
                <div className="absolute top-0 right-0 w-24 h-24 bg-[#FFECB3] rounded-bl-full opacity-30"></div>
                <div className="relative z-10 space-y-4">
                    <div className="flex items-center gap-2 mb-2">
                        <Flag size={20} className="text-[#FFB74D]" />
                        <h3 className="text-sm font-black text-[#5D4037]">目標までの道のり</h3>
                    </div>

                    <div className="grid grid-cols-2 gap-4">
                        <div className="bg-white p-3 rounded-2xl border border-[#FFE0B2]">
                            <p className="text-[9px] font-bold text-[#A1887F] mb-1">あと</p>
                            <p className="text-xl font-black text-[#FFB74D]">{dietSimulation.weightDiff.toFixed(1)} <span className="text-xs">kg</span></p>
                        </div>
                        <div className="bg-white p-3 rounded-2xl border border-[#FFE0B2]">
                            <p className="text-[9px] font-bold text-[#A1887F] mb-1">目標日まで</p>
                            <p className="text-xl font-black text-[#FFB74D]">{dietSimulation.daysLeft} <span className="text-xs">日</span></p>
                        </div>
                    </div>

                    <div className="bg-white p-4 rounded-2xl border-2 border-dashed border-[#FFE0B2]">
                        <p className="text-[10px] font-black text-[#8D6E63] mb-2 flex items-center gap-1">
                            <Calculator size={12} /> 1日あたりの調整目安
                        </p>
                        <div className="flex items-baseline gap-1 mb-2">
                            <span className="text-2xl font-black text-[#FF9800]">約{dietSimulation.dailyBurn}</span>
                            <span className="text-xs font-bold text-[#A1887F]">kcal / 日</span>
                        </div>
                        <p className="text-[10px] font-bold text-[#8D6E63] leading-relaxed">
                            (脂肪1kgを7,400kcalとして計算)
                        </p>
                    </div>

                    {/* アラート・アドバイス表示エリア */}
                    {dietSimulation.isImpossible ? (
                        <div className="flex items-start gap-2 bg-[#FFEBEE] p-3 rounded-xl border border-[#FFCDD2]">
                             <AlertCircle size={20} className="text-[#D32F2F] shrink-0 mt-0.5" />
                             <div>
                                 <p className="text-[10px] font-black text-[#C62828] mb-1">
                                     設定に無理がある可能性があります（要確認）
                                 </p>
                                 <div className="text-[9px] font-bold text-[#C62828] leading-relaxed space-y-1">
                                     <p>計算上、1日 <strong>-{dietSimulation.dailyBurn}kcal</strong> の調整が必要です。これは「1ヶ月で10kg減」のような極端なペースです。</p>
                                     <p>⚠️ <strong>データ入力の間違いはありませんか？</strong>（目標体重や日付の再確認を推奨）</p>
                                     <p>極端な食事制限（摂取800kcal未満など）は、医師や専門家の指導なしに行うと危険です。代謝が落ち、リバウンドの原因にもなります。</p>
                                     <p>「設定」から目標日を延ばし、運動を併用した健康的な計画に修正してください。</p>
                                 </div>
                             </div>
                        </div>
                    ) : dietSimulation.isLowBMI ? (
                        <div className="flex items-start gap-2 bg-[#E3F2FD] p-3 rounded-xl border border-[#BBDEFB]">
                             <Dumbbell size={16} className="text-[#1976D2] shrink-0 mt-0.5" />
                             <div>
                                 <p className="text-[10px] font-black text-[#1565C0] mb-1">
                                     引き締め・ボディメイクのフェーズです
                                 </p>
                                 <p className="text-[9px] font-bold text-[#1976D2] leading-tight">
                                     目標BMIが18.5未満（{dietSimulation.targetBMI}）です。これ以上の食事制限は健康を損なう可能性があります。<br/>
                                     しっかり食べて運動し、筋肉をつけてボディラインを整えることを意識しましょう。
                                 </p>
                             </div>
                        </div>
                    ) : dietSimulation.isHard ? (
                        <div className="flex items-start gap-2 bg-[#FFF3E0] p-3 rounded-xl border border-[#FFE0B2]">
                             <AlertTriangle size={16} className="text-[#F57C00] shrink-0 mt-0.5" />
                             <div>
                                <p className="text-[10px] font-black text-[#EF6C00] mb-1">
                                    かなりハードなペースです（1日 -{dietSimulation.dailyBurn}kcal）
                                </p>
                                <p className="text-[9px] font-bold text-[#EF6C00] leading-tight">
                                    食事を減らすだけでなく、<strong>運動（筋トレや有酸素運動）</strong>を組み合わせないと、筋肉が落ちてリバウンドしやすくなります。<br/>
                                    無理なく続けるために、目標日を少し先に延ばすことも検討してください。
                                </p>
                             </div>
                        </div>
                    ) : (
                        <div className="flex items-start gap-2 bg-[#F1F8E9] p-3 rounded-xl border border-[#DCEDC8]">
                             <Stethoscope size={16} className="text-[#689F38] shrink-0 mt-0.5" />
                             <p className="text-[9px] font-bold text-[#558B2F] leading-tight">
                                 無理のない良いペースです。ご飯1杯分程度の調整や、運動で達成可能な範囲です✨<br/>
                                 体調に合わせて継続していきましょう！
                             </p>
                        </div>
                    )}
                </div>
            </div>
        )}

        <section className="px-6 space-y-4">
            <div className="flex items-center justify-between px-2">
                <div className="flex items-center gap-2">
                    <HistoryIcon size={18} className="text-stone-400" />
                    <h2 className="text-sm font-black" style={{ color: THEME.colors.text }}>きろく。</h2>
                </div>
                <span className="text-[9px] font-black opacity-30 tracking-widest uppercase">Max 300 Days</span>
            </div>

            {pagedRecords.length === 0 ? (
                <div className="py-16 text-center bg-white rounded-[40px] border-2 border-dashed" style={{ borderColor: THEME.colors.border }}>
                    <p className="text-xs font-bold text-stone-300">まだ記録がありません</p>
                </div>
            ) : (
                <div className="space-y-4">
                    {listItemsWithAds.map((item) => {
                        if ('type' in item && item.type === 'ad') {
                            // メニュー展開中はネイティブ広告も非表示（描画しない）
                            if (isMenuOpen) return null;
                            return <NativeAdCard key={item.id} />;
                        }
                        const record = item as DailyRecord;
                        return (
                        <div key={record.id} className="bg-white rounded-[32px] border-2 p-5 shadow-sm active:scale-[0.99] transition-all" style={{ borderColor: THEME.colors.border }}>
                            <div className="flex items-center justify-between mb-4 border-b border-dashed pb-3" style={{ borderColor: THEME.colors.border }}>
                                <div className="flex items-center gap-2">
                                    <Calendar size={14} className="text-stone-400" />
                                    <span className="text-xs font-black" style={{ color: THEME.colors.text }}>{record.date}</span>
                                </div>
                                {record.weight && (
                                    <div className="flex items-baseline gap-1 bg-stone-50 px-3 py-1 rounded-full border shadow-inner" style={{ borderColor: THEME.colors.border }}>
                                        <span className="text-sm font-black" style={{ color: THEME.colors.primary }}>{record.weight}</span>
                                        <span className="text-[8px] font-bold text-stone-400">kg</span>
                                    </div>
                                )}
                            </div>

                            <div className="space-y-3">
                                {record.postureAnalysis && (
                                    <button 
                                        onClick={() => onPostureClick(record)}
                                        className="w-full flex items-center justify-between p-3 rounded-2xl bg-stone-50 border border-stone-100 group active:bg-stone-100 transition-colors"
                                    >
                                        <div className="flex items-center gap-3">
                                            <div className="p-2 rounded-xl shadow-sm" style={{ backgroundColor: THEME.colors.primaryLight }}>
                                                <Camera size={16} style={{ color: THEME.colors.primary }} />
                                            </div>
                                            <div className="text-left">
                                                <p className="text-[11px] font-black" style={{ color: THEME.colors.text }}>姿勢チェック</p>
                                                <div className="flex items-center gap-2">
                                                    <span className="text-[9px] font-black px-1.5 py-0.5 rounded-md text-white" style={{ backgroundColor: record.postureAnalysis.level === 'OK' ? THEME.colors.secondary : THEME.colors.primary }}>
                                                        {record.postureAnalysis.level}
                                                    </span>
                                                    <p className="text-[9px] font-bold text-stone-400 truncate max-w-[150px]">{record.postureAnalysis.point}</p>
                                                </div>
                                            </div>
                                        </div>
                                        <ChevronRight size={16} className="text-stone-300 group-active:translate-x-1 transition-transform" />
                                    </button>
                                )}

