/**
 * たべとっと。 姿勢解析サービス (v4.4 マルチアングル対応強化版)
 */
export const analyzePosture = async (
  frontImage: string, 
  sideImage: string | null
): Promise<PostureAnalysis> => {
  const cleanBase64 = (b64: string) => b64.replace(/^data:image\/[a-z]+;base64,/, "").trim();

  const images = [cleanBase64(frontImage)];
  if (sideImage) {
    images.push(cleanBase64(sideImage));
  }

  // 1枚の場合と2枚の場合でコンテキストを切り替え
  const postureContext = sideImage 
    ? "画像は最大2枚（1枚目:正面、2枚目:側面）送られます。両方ある場合は立体的に分析し、もし1枚しかない場合でもエラーにせず、ある画像だけで解析を行ってください。ダイエットにおける体型変化の記録としても有用なアドバイスを求めます。" 
    : "正面1枚からの解析です。ダイエットの経過記録（Before/After比較）としての側面を重視してください。";

  const systemInstruction = `あなたは姿勢・体型解析のアシスタントです。
${postureContext}

【分析ルール】
1. 解析不能な画像（真っ暗、人物がいない等）の場合のみ、"isAnalyzable": false としてください。
2. 多少見切れていても、解析できる範囲でアドバイスを行ってください。
3. 出力は必ず以下のJSON形式のみとし、Markdownタグは含めないでください。

【出力JSON形式】
{
  "postureLevel": number, // 1(悪い) 〜 5(良い) の整数
  "comment": string // ユーザーへのフィードバック（1〜2文程度）
}`;

  const promptText = `現在の体型と姿勢を記録・チェックし、ダイエットや体型改善のモチベーション（長期的な比較の楽しみ）に繋がる回答をJSONでください。`;

  try {
    const res = await callAiProxy({
      kind: "posture", 
      text: promptText,
      systemInstruction: systemInstruction,
      images: images,
      model: "gemini-2.5-flash-lite",
      wantJson: true
    });

    const raw = parseJSON<any>(res.answer);

    // server.js 側のエラーチェック
    if (raw.ok === false || raw.error) {
      throw new Error(raw.error?.message || "解析エラー");
    }

    // レベルマッピングのロジック
    // 2.5-flash-liteは厳しめに出る傾向があるため、少し補正
    let levelMapping: 'OK' | 'CAUTION' | 'CHECK' = 'CHECK';

    // 数値が入っていない場合のガード
    const levelScore = typeof raw.postureLevel === 'number' ? raw.postureLevel : 3;

    if (levelScore >= 4) levelMapping = 'OK';
    else if (levelScore >= 2) levelMapping = 'CAUTION';

    return {
      isAnalyzable: true,
      level: levelMapping,
      point: raw.comment || "素晴らしい記録です！この調子で続けていきましょう。",
    };
  } catch (error) {
    console.error("Posture analysis error:", error);
    return {
      isAnalyzable: false,
      level: 'CHECK',
      point: "解析に失敗しました。通信環境の良い場所で、もう一度お試しください。",
    };
  }
};

