                try {
                   const result = await detectPose(img);
                   if (active && result && result.landmarks && canvasRef.current) {
                       drawPoseOnCanvas(canvasRef.current.getContext('2d')!, result.landmarks, canvasRef.current.width, canvasRef.current.height);
