  useEffect(() => {
    document.documentElement.setAttribute('data-theme', user.theme || 'default');
  }, [user.theme]);

  const safeSaveRecords = (newRecords: Record<string, DailyRecord>) => {
    if (!isLoaded) return;

    // 10日以上前の写真データを削除する処理
    const CLEANUP_DAYS = 10;
    const now = new Date();
    const cutoffDate = new Date(now);
    cutoffDate.setDate(now.getDate() - CLEANUP_DAYS);
    // UTCではなくローカル時間基準の日付文字列を使用
    const cutoffStr = toLocalDateString(cutoffDate);

    const recordsToSave = { ...newRecords };

    Object.keys(recordsToSave).forEach(date => {
        if (date < cutoffStr) {
            const record = recordsToSave[date];
            let modified = false;

            if (record.mealPhotoUrls && record.mealPhotoUrls.some(url => url !== "")) {
                record.mealPhotoUrls = record.mealPhotoUrls.map(() => "");
                modified = true;
            }
            if (record.posturePhotoUrl) {
                record.posturePhotoUrl = undefined;
                modified = true;
            }
            if (record.postureSidePhotoUrl) {
                record.postureSidePhotoUrl = undefined;
                modified = true;
            }
        }
    });

    try {
      localStorage.setItem(STORAGE_KEY_RECORDS, JSON.stringify(recordsToSave));
    } catch (e: any) {
      if (e.name === 'QuotaExceededError' || e.name === 'NS_ERROR_DOM_QUOTA_REACHED') {
        const sortedDates = Object.keys(recordsToSave).sort();
        if (sortedDates.length > 3) { 
          sortedDates.slice(0, 5).forEach(date => {
            recordsToSave[date].mealPhotoUrls = recordsToSave[date].mealPhotoUrls.map(() => "");
            recordsToSave[date].posturePhotoUrl = undefined;
            recordsToSave[date].postureSidePhotoUrl = undefined;
          });
          try {
             localStorage.setItem(STORAGE_KEY_RECORDS, JSON.stringify(recordsToSave));
          } catch(retryE) {
             console.error("Storage full even after cleanup", retryE);
          }
        }
      }
    }
  };

  useEffect(() => {
    if (isLoaded) localStorage.setItem(STORAGE_KEY_USER, JSON.stringify(user));
  }, [user, isLoaded]);

  useEffect(() => {
    safeSaveRecords(records);
  }, [records]);

  useEffect(() => {
    if (isLoaded) {
      localStorage.setItem(STORAGE_KEY_TOKENS, tokens.toString());
      localStorage.setItem(STORAGE_KEY_LAST_RECOVERY, lastRecovery.toString());
    }
  }, [tokens, lastRecovery, isLoaded]);

  useEffect(() => {
    const timer = setInterval(() => {
      if (tokens < AUTO_MAX_TOKENS) {
        const now = Date.now();
        if (now - lastRecovery >= RECOVERY_TIME_MS) {
          setTokens(prev => Math.min(AUTO_MAX_TOKENS, prev + 1));
          setLastRecovery(prev => prev + RECOVERY_TIME_MS);
        }
      }
    }, 60000);
    return () => clearInterval(timer);
  }, [tokens, lastRecovery]);

  const handleTouchStart = (e: React.TouchEvent) => {
    setTouchStart({ x: e.touches[0].clientX, y: e.touches[0].clientY });
  };

  const handleTouchEnd = (e: React.TouchEvent) => {
    if (!touchStart) return;
    const endX = e.changedTouches[0].clientX;
    const endY = e.changedTouches[0].clientY;
    const diffX = touchStart.x - endX;
    const diffY = touchStart.y - endY;

    if (Math.abs(diffX) > 70 && Math.abs(diffY) < 50) {
      const mainViews = [AppView.DASHBOARD, AppView.HISTORY, AppView.MEAL, AppView.POSTURE, AppView.SETTINGS];
      const currentIndex = mainViews.indexOf(view);

      if (currentIndex !== -1) {
        if (diffX > 0) { 
           const next = mainViews[currentIndex + 1];
           if (next) setView(next);
        } else { 
           const prev = mainViews[currentIndex - 1];
           if (prev) setView(prev);
        }
      }
    }
    setTouchStart(null);
  };

  const useToken = useCallback((): boolean => {
    if (tokens > 0) {
      setTokens(prev => {
        const next = prev - 1;
        if (prev >= AUTO_MAX_TOKENS && next < AUTO_MAX_TOKENS) {
          setLastRecovery(Date.now());
        }
        return next;
      });
      return true;
    }
    return false;
  }, [tokens]);

  const restoreTokens = async (): Promise<boolean> => {
    const success = await showRewardedInterstitialAd();
    if (success) {
      setTokens(prev => Math.min(MAX_TOKENS, prev + REWARD_TOKENS));
      setLastRecovery(Date.now());
      return true;
    }
    return false;
  };

  const todayKey = getTodayString();
  const todayRecord = useMemo(() => records[todayKey] || { id: todayKey, date: todayKey, mealPhotoUrls: [], mealAnalyses: [] }, [records, todayKey]);

  useEffect(() => {
    if (!isLoaded) return;
    const fetchAdvice = async () => {
        try { const advice = await generateDailyAdvice(user, todayRecord); setDailyAdvice(advice); } catch (e) { }
    };
    fetchAdvice();
  }, [user.nickname, todayRecord.weight, todayRecord.mealAnalyses.length, isLoaded]);

  const lastPostureDate = useMemo(() => {
    const sortedDates = Object.keys(records).sort().reverse();
    for (const d of sortedDates) { if (records[d].postureAnalysis?.isAnalyzable) return d; }
    return null;
  }, [records]);

  const lastPostureRecord = lastPostureDate ? records[lastPostureDate] : null;

  const handleWeightUpdate = (weight: number) => {
    setRecords(prev => ({ ...prev, [todayKey]: { ...todayRecord, weight } }));
  };

  const handleMealSave = (analysis: MealAnalysis, photo: string, date: string) => {
    setRecords(prev => {
      const targetRecord = prev[date] || { id: date, date, mealPhotoUrls: [], mealAnalyses: [] };
      return { ...prev, [date]: { ...targetRecord, mealPhotoUrls: [...targetRecord.mealPhotoUrls, photo], mealAnalyses: [...targetRecord.mealAnalyses, analysis] } };
    });
  };

  const handleUpdateExternalUrl = (url: string) => {
    if (!selectedMeal) return;
    setRecords(prev => {
        const r = { ...prev[selectedMeal.date] };
        r.mealAnalyses[selectedMeal.index].externalUrl = url;
        return { ...prev, [selectedMeal.date]: r };
    });
  };

  const handlePostureSave = (photo: string, analysis: PostureAnalysis, date: string, sidePhoto?: string | null) => {
    setRecords(prev => {
      const targetRecord = prev[date] || { id: date, date: date, mealPhotoUrls: [], mealAnalyses: [] };
      return { ...prev, [date]: { ...targetRecord, posturePhotoUrl: photo, postureSidePhotoUrl: sidePhoto || undefined, postureAnalysis: analysis } };
    });
  };

  const handleComparisonSave = (comparison: PostureComparison) => {
    if (!comparingDate) return;
    setRecords(prev => {
        const targetRecord = prev[comparingDate];
        if (!targetRecord) return prev;
        return {
            ...prev,
            [comparingDate]: {
                ...targetRecord,
                postureComparison: comparison
            }
        };
    });
  };

  const renderContent = () => {
    if (!isLoaded) return (
      <div className="flex flex-col items-center justify-center h-screen space-y-4">
        <div className="w-16 h-16 bg-primary rounded-2xl animate-sway flex items-center justify-center text-white text-2xl font-black">🍱</div>
        <p className="font-black text-primary animate-pulse">読み込み中...</p>
      </div>
    );

    switch (view) {
      case AppView.DASHBOARD:
        return <DashboardView user={user} todayRecord={todayRecord} records={records} lastPostureDate={lastPostureDate} lastPosturePhoto={lastPostureRecord?.posturePhotoUrl || null} setView={setView} onWeightUpdate={handleWeightUpdate} dailyAdvice={dailyAdvice} onMealClick={(m, p, d, i) => { setPreGeneratedBlob(null); setSelectedMeal({ analysis: m, photo: p, date: d, index: i }); }} onPostureClick={() => lastPostureDate ? (setShowingPostureDate(lastPostureDate), setIsPostureModalOpen(true)) : setView(AppView.POSTURE)} openKeypad={openKeypad} tokens={tokens} />;
      case AppView.MEAL:
        return <MealView user={user} tokens={tokens} useToken={useToken} restoreTokens={restoreTokens} onSave={handleMealSave} onClose={() => setView(AppView.DASHBOARD)} onShareClick={(blob) => { setPreGeneratedBlob(blob || null); setShareModalOpen(true); }} openKeypad={openKeypad} openCalendar={openCalendar} onOpenGuide={() => setView(AppView.NUTRITION_GUIDE)} onMenuOpen={() => setIsMenuOpen(true)} isMenuOpen={isMenuOpen} />;
      case AppView.HISTORY:
        return <HistoryView records={Object.values(records)} user={user} onMealClick={(m, p, d, i) => { setPreGeneratedBlob(null); setSelectedMeal({ analysis: m, photo: p, date: d, index: i }); }} onPostureClick={(r) => { setShowingPostureDate(r.date); setIsPostureModalOpen(true); }} isMenuOpen={isMenuOpen} />;
      case AppView.POSTURE:
        return <PostureView tokens={tokens} useToken={useToken} restoreTokens={restoreTokens} lastAnalysis={lastPostureRecord?.postureAnalysis || null} onSave={handlePostureSave} onClose={() => setView(AppView.DASHBOARD)} onShowPoints={() => setView(AppView.POSTURE_POINTS)} todayWeight={todayRecord.weight} openCalendar={openCalendar} onMenuOpen={() => setIsMenuOpen(true)} onCompare={() => { setComparingDate(getTodayString()); setIsCompareModalOpen(true); }} isMenuOpen={isMenuOpen} />;
      case AppView.SETTINGS:
        return <SettingsView user={user} onSave={setUser} openKeypad={openKeypad} />;
      case AppView.POSTURE_POINTS:
        return <PosturePointsView onBack={() => setView(AppView.POSTURE)} />;
      case AppView.NUTRITION_GUIDE:
        return <NutritionGuideView onBack={() => setView(AppView.MEAL)} />;
      default:
        return null;
    }
  };

  const showGlobalHeader = [AppView.DASHBOARD, AppView.HISTORY, AppView.SETTINGS].includes(view);

  return (
    <div 
        className="min-h-screen font-zen-maru pb-safe selection:text-white overflow-x-hidden relative w-full flex justify-center items-start" 
        style={{ color: THEME.colors.text, backgroundColor: THEME.colors.bg }}
        onTouchStart={handleTouchStart}
        onTouchEnd={handleTouchEnd}
    >
      <div className="fixed top-0 left-0 w-full h-full pointer-events-none z-0 opacity-40" 
           style={{ backgroundImage: 'radial-gradient(rgba(0,0,0,0.05) 1px, transparent 1px)', backgroundSize: '24px 24px' }}>
      </div>

      <div className="relative z-10 w-full min-h-screen shadow-xl md:max-w-md bg-transparent flex flex-col overflow-x-hidden">

          {showGlobalHeader && (
             <header className="sticky top-0 z-[100] pt-safe backdrop-blur-md border-b w-full shadow-sm" style={{ backgroundColor: `${THEME.colors.bg}E6`, borderColor: THEME.colors.border }}>
               <div className="px-6 py-3 flex items-center justify-between">
                   <div className="flex items-center gap-2">
                       <div className="w-8 h-8 rounded-lg flex items-center justify-center shadow-lg animate-sway" style={{ backgroundColor: THEME.colors.primary }}>
                           <Utensils size={16} className="text-white" strokeWidth={3} />
                       </div>
                       <div className="flex flex-col">
                         <h1 className="text-xl font-black tracking-widest leading-none" style={{ color: THEME.colors.primary }}>たべとっと。</h1>
                         <span className="text-[8px] font-black tracking-tighter opacity-70" style={{ color: THEME.colors.primary }}>Re:ポスチャーDiet</span>
                       </div>
                   </div>
                   <button onClick={() => setIsMenuOpen(true)} className="pl-4 pr-3 py-2 -mr-2 rounded-full shadow-md active:scale-95 transition-all flex items-center gap-2 border-2 border-white ring-2" style={{ backgroundColor: THEME.colors.primary, color: 'white', borderColor: 'white', ['--tw-ring-color' as any]: `${THEME.colors.primary}33` }}>
                       <span className="text-sm font-black tracking-wide">Menu</span>
                       <Menu size={20} strokeWidth={2.5} />
                   </button>
               </div>
             </header>
          )}

          {renderContent()}

          {/* 下固定バナー用スペース確保 (MRECの場合は不要だが、共通レイアウトとして残すか判断。バナー用なのでMREC時は余白になる) */}
          <AdBelt />
      </div>

      <SideMenu isOpen={isMenuOpen} onClose={() => setIsMenuOpen(false)} currentView={view} setView={setView} />

      {/* ... (Modals omitted for brevity, identical to previous) ... */}
      {selectedMeal && (
        <MealDetailModal isOpen={!!selectedMeal} onClose={() => setSelectedMeal(null)} recordDate={selectedMeal.date} meal={selectedMeal.analysis} photoBase64={selectedMeal.photo} onDelete={() => { if(confirm('この記録を削除しますか？')){ setRecords(prev => { const r = { ...prev[selectedMeal.date] }; r.mealPhotoUrls.splice(selectedMeal.index, 1); r.mealAnalyses.splice(selectedMeal.index, 1); return { ...prev, [selectedMeal.date]: r }; }); setSelectedMeal(null); } }} onShare={() => setShareModalOpen(true)} onDeletePhoto={() => {
          setRecords(prev => { 
            const r = { ...prev[selectedMeal.date] }; 
            r.mealPhotoUrls[selectedMeal.index] = ""; 
            return { ...prev, [selectedMeal.date]: r }; 
          });
          setSelectedMeal(prev => prev ? { ...prev, photo: "" } : null);
        }} onUpdateExternalUrl={handleUpdateExternalUrl} />
      )}

      {shareModalOpen && (selectedMeal || (view === AppView.MEAL)) && (
          <SharePreviewModal 
            isOpen={shareModalOpen} 
            onClose={() => setShareModalOpen(false)} 
            mealAnalysis={selectedMeal ? selectedMeal.analysis : (selectedMeal || { menuName: '解析中', numericCalories: 0, pfcRatio: {p:0, f:0, c:0}, comment: '' } as any)} 
            photoBase64={selectedMeal ? selectedMeal.photo : ''} 
            dateStr={selectedMeal ? selectedMeal.date : getTodayString()} 
            initialBlob={preGeneratedBlob}
          />
      )}

      <PostureDetailModal 
         isOpen={isPostureModalOpen} 
         onClose={() => setIsPostureModalOpen(false)} 
         recordDate={showingPostureDate || ''} 
         analysis={showingPostureDate ? records[showingPostureDate]?.postureAnalysis || null : null} 
         photoBase64={showingPostureDate ? records[showingPostureDate]?.posturePhotoUrl || null : null} 
         sidePhotoBase64={showingPostureDate ? records[showingPostureDate]?.postureSidePhotoUrl : null}
         onCompare={() => {
            setComparingDate(showingPostureDate);
            setIsCompareModalOpen(true);
            setIsPostureModalOpen(false);
         }}
      />

      {isCompareModalOpen && comparingDate && records[comparingDate] && (
          <CompareModal 
              isOpen={isCompareModalOpen}
              onClose={() => setIsCompareModalOpen(false)}
              currentRecord={records[comparingDate]}
              records={records}
              onSaveNote={handleComparisonSave}
          />
      )}

      {keypadConfig && (
        <CuteKeypad initialValue={keypadConfig.initialValue} unit={keypadConfig.unit} onConfirm={(val) => { keypadConfig.onConfirm(val); setKeypadConfig(null); }} onCancel={() => setKeypadConfig(null)} />
      )}

      {calendarConfig && (
        <CuteCalendar initialDate={calendarConfig.initialDate} onConfirm={(date) => { calendarConfig.onConfirm(date); setCalendarConfig(null); }} onCancel={() => setCalendarConfig(null)} />
      )}
    </div>
  );
};

