import { Camera, CameraResultType, CameraSource, CameraDirection } from '@capacitor/camera';
import { Capacitor } from '@capacitor/core';

export interface PhotoResult {
  base64: string;
  mimeType: string;
  format: string;
  source: 'camera' | 'file';
  width: number;
  height: number;
}

// 履歴の高速表示と保存容量の最小化、AI解析の高速化のためにサイズを制限
const MAX_LONG_SIDE = 640; // Reduced from 720 to 640 for better performance

/**
 * 画像を指定サイズ以下にリサイズしBase64で返却
 */
const processImage = (img: HTMLImageElement, source: 'camera' | 'file'): PhotoResult => {
  let width = img.width;
  let height = img.height;

  if (width > height) {
    if (width > MAX_LONG_SIDE) {
      height = Math.round((height * MAX_LONG_SIDE) / width);
      width = MAX_LONG_SIDE;
    }
  } else {
    if (height > MAX_LONG_SIDE) {
      width = Math.round((width * MAX_LONG_SIDE) / height);
      height = MAX_LONG_SIDE;
    }
  }

  const canvas = document.createElement('canvas');
  canvas.width = width;
  canvas.height = height;
  const ctx = canvas.getContext('2d');
  if (!ctx) throw new Error("Canvas context creation failed");

  ctx.drawImage(img, 0, 0, width, height);
  const mimeType = 'image/jpeg';
  // 圧縮率を0.3に設定。実機テストで十分な視認性と最小のデータ量を両立。
  const dataUrl = canvas.toDataURL(mimeType, 0.3);
  const base64 = dataUrl.split(',')[1];

  return {
    base64,
    mimeType,
    format: 'jpeg',
    source,
    width,
    height
  };
};

/**
 * Base64画像を圧縮して再取得するユーティリティ
 * FileInputからの画像など、未圧縮のデータを小さくするために使用
 */
export const compressImage = (base64: string): Promise<string> => {
  return new Promise((resolve, reject) => {
    const img = new Image();
    img.onload = () => {
      try {
        const res = processImage(img, 'file');
        resolve(res.base64);
      } catch (e) {
        reject(e);
      }
    };
    img.onerror = () => reject(new Error("Image processing failed"));
    img.src = base64.startsWith('data:') ? base64 : `data:image/jpeg;base64,${base64}`;
  });
};

/**
 * 写真を撮影または選択
 */
export const takePhoto = async (source: CameraSource = CameraSource.Prompt, direction: 'front' | 'rear' = 'rear'): Promise<PhotoResult> => {
  try {
    const image = await Camera.getPhoto({
      quality: 50, 
      allowEditing: false,
      resultType: CameraResultType.Base64,
      source: source,
      direction: direction === 'front' ? CameraDirection.Front : CameraDirection.Rear,
      correctOrientation: true,
      // ネイティブ側でリサイズを行うことで、JS側のメモリ負荷を劇的に下げる
      width: 1024, 
    });

    if (!image.base64String) throw new Error("No image data returned from camera.");

    return new Promise((resolve, reject) => {
      const img = new Image();
      img.onload = () => resolve(processImage(img, 'camera'));
      img.onerror = () => reject(new Error("Image processing failed."));
      img.src = `data:image/${image.format};base64,${image.base64String}`;
    });
  } catch (e: any) {
    if (e.message?.includes("User cancelled") || e.message === "CANCELLED") throw new Error("CANCELLED");
    throw new Error(`Camera Error: ${e.message}`);
  }
};

import React, { useState, useMemo, useEffect, useRef } from 'react';
import { Utensils, Calendar, Camera, ChevronRight, LayoutList, History as HistoryIcon, ArrowDown, Calculator, Flag, AlertTriangle, Stethoscope, Dumbbell, AlertCircle } from 'lucide-react';
