                        <div className="bg-white p-3 rounded-2xl border border-[#FFE0B2]">
                            <p className="text-[9px] font-bold text-[#A1887F] mb-1">目標日まで</p>
                            <p className="text-xl font-black text-[#FFB74D]">{dietSimulation.daysLeft} <span className="text-xs">日</span></p>
                        </div>
                    </div>

                    <div className="bg-white p-4 rounded-2xl border-2 border-dashed border-[#FFE0B2]">
                        <p className="text-[10px] font-black text-[#8D6E63] mb-2 flex items-center gap-1">
                            <Calculator size={12} /> 1日あたりの調整目安
                        </p>
                        <div className="flex items-baseline gap-1 mb-2">
                            <span className="text-2xl font-black text-[#FF9800]">約{dietSimulation.dailyBurn}</span>
                            <span className="text-xs font-bold text-[#A1887F]">kcal / 日</span>
                        </div>
                        <p className="text-[10px] font-bold text-[#8D6E63] leading-relaxed">
                            (脂肪1kgを7,400kcalとして計算)
                        </p>
                    </div>

                    {/* アラート・アドバイス表示エリア */}
                    {dietSimulation.isImpossible ? (
                        <div className="flex items-start gap-2 bg-[#FFEBEE] p-3 rounded-xl border border-[#FFCDD2]">
                             <AlertCircle size={20} className="text-[#D32F2F] shrink-0 mt-0.5" />
                             <div>
                                 <p className="text-[10px] font-black text-[#C62828] mb-1">
                                     設定に無理がある可能性があります（要確認）
                                 </p>
                                 <div className="text-[9px] font-bold text-[#C62828] leading-relaxed space-y-1">
                                     <p>計算上、1日 <strong>-{dietSimulation.dailyBurn}kcal</strong> の調整が必要です。これは「1ヶ月で10kg減」のような極端なペースです。</p>
                                     <p>⚠️ <strong>データ入力の間違いはありませんか？</strong>（目標体重や日付の再確認を推奨）</p>
                                     <p>極端な食事制限（摂取800kcal未満など）は、医師や専門家の指導なしに行うと危険です。代謝が落ち、リバウンドの原因にもなります。</p>
                                     <p>「設定」から目標日を延ばし、運動を併用した健康的な計画に修正してください。</p>
                                 </div>
                             </div>
                        </div>
                    ) : dietSimulation.isLowBMI ? (
                        <div className="flex items-start gap-2 bg-[#E3F2FD] p-3 rounded-xl border border-[#BBDEFB]">
                             <Dumbbell size={16} className="text-[#1976D2] shrink-0 mt-0.5" />
                             <div>
                                 <p className="text-[10px] font-black text-[#1565C0] mb-1">
                                     引き締め・ボディメイクのフェーズです
                                 </p>
                                 <p className="text-[9px] font-bold text-[#1976D2] leading-tight">
                                     目標BMIが18.5未満（{dietSimulation.targetBMI}）です。これ以上の食事制限は健康を損なう可能性があります。<br/>
                                     しっかり食べて運動し、筋肉をつけてボディラインを整えることを意識しましょう。
                                 </p>
                             </div>
                        </div>
                    ) : dietSimulation.isHard ? (
                        <div className="flex items-start gap-2 bg-[#FFF3E0] p-3 rounded-xl border border-[#FFE0B2]">
                             <AlertTriangle size={16} className="text-[#F57C00] shrink-0 mt-0.5" />
                             <div>
                                <p className="text-[10px] font-black text-[#EF6C00] mb-1">
                                    かなりハードなペースです（1日 -{dietSimulation.dailyBurn}kcal）
                                </p>
                                <p className="text-[9px] font-bold text-[#EF6C00] leading-tight">
                                    食事を減らすだけでなく、<strong>運動（筋トレや有酸素運動）</strong>を組み合わせないと、筋肉が落ちてリバウンドしやすくなります。<br/>
                                    無理なく続けるために、目標日を少し先に延ばすことも検討してください。
                                </p>
                             </div>
                        </div>
                    ) : (
                        <div className="flex items-start gap-2 bg-[#F1F8E9] p-3 rounded-xl border border-[#DCEDC8]">
                             <Stethoscope size={16} className="text-[#689F38] shrink-0 mt-0.5" />
                             <p className="text-[9px] font-bold text-[#558B2F] leading-tight">
                                 無理のない良いペースです。ご飯1杯分程度の調整や、運動で達成可能な範囲です✨<br/>
                                 体調に合わせて継続していきましょう！
                             </p>
                        </div>
                    )}
                </div>
            </div>
        )}

        <section className="px-6 space-y-4">
            <div className="flex items-center justify-between px-2">
                <div className="flex items-center gap-2">
                    <HistoryIcon size={18} className="text-stone-400" />
                    <h2 className="text-sm font-black" style={{ color: THEME.colors.text }}>きろく。</h2>
                </div>
                <span className="text-[9px] font-black opacity-30 tracking-widest uppercase">Max 300 Days</span>
            </div>

            {pagedRecords.length === 0 ? (
                <div className="py-16 text-center bg-white rounded-[40px] border-2 border-dashed" style={{ borderColor: THEME.colors.border }}>
                    <p className="text-xs font-bold text-stone-300">まだ記録がありません</p>
                </div>
            ) : (
                <div className="space-y-4">
                    {listItemsWithAds.map((item) => {
                        if ('type' in item && item.type === 'ad') {
                            // メニュー展開中はネイティブ広告も非表示（描画しない）
                            if (isMenuOpen) return null;
                            return <NativeAdCard key={item.id} />;
                        }
                        const record = item as DailyRecord;
                        return (
                        <div key={record.id} className="bg-white rounded-[32px] border-2 p-5 shadow-sm active:scale-[0.99] transition-all" style={{ borderColor: THEME.colors.border }}>
                            <div className="flex items-center justify-between mb-4 border-b border-dashed pb-3" style={{ borderColor: THEME.colors.border }}>
                                <div className="flex items-center gap-2">
                                    <Calendar size={14} className="text-stone-400" />
                                    <span className="text-xs font-black" style={{ color: THEME.colors.text }}>{record.date}</span>
                                </div>
                                {record.weight && (
                                    <div className="flex items-baseline gap-1 bg-stone-50 px-3 py-1 rounded-full border shadow-inner" style={{ borderColor: THEME.colors.border }}>
                                        <span className="text-sm font-black" style={{ color: THEME.colors.primary }}>{record.weight}</span>
                                        <span className="text-[8px] font-bold text-stone-400">kg</span>
                                    </div>
                                )}
                            </div>

                            <div className="space-y-3">
                                {record.postureAnalysis && (
                                    <button 
                                        onClick={() => onPostureClick(record)}
                                        className="w-full flex items-center justify-between p-3 rounded-2xl bg-stone-50 border border-stone-100 group active:bg-stone-100 transition-colors"
                                    >
                                        <div className="flex items-center gap-3">
                                            <div className="p-2 rounded-xl shadow-sm" style={{ backgroundColor: THEME.colors.primaryLight }}>
                                                <Camera size={16} style={{ color: THEME.colors.primary }} />
                                            </div>
                                            <div className="text-left">
                                                <p className="text-[11px] font-black" style={{ color: THEME.colors.text }}>姿勢チェック</p>
                                                <div className="flex items-center gap-2">
                                                    <span className="text-[9px] font-black px-1.5 py-0.5 rounded-md text-white" style={{ backgroundColor: record.postureAnalysis.level === 'OK' ? THEME.colors.secondary : THEME.colors.primary }}>
                                                        {record.postureAnalysis.level}
                                                    </span>
                                                    <p className="text-[9px] font-bold text-stone-400 truncate max-w-[150px]">{record.postureAnalysis.point}</p>
                                                </div>
                                            </div>
                                        </div>
                                        <ChevronRight size={16} className="text-stone-300 group-active:translate-x-1 transition-transform" />
                                    </button>
                                )}

                                {record.mealAnalyses.length > 0 && (
                                    <div className="space-y-2">
                                        {record.mealAnalyses.map((meal, idx) => (
                                            <button 
                                                key={`${record.id}-meal-${idx}`}
                                                onClick={() => onMealClick(meal, record.mealPhotoUrls[idx], record.date, idx)}
                                                className="w-full flex items-center justify-between p-3 rounded-2xl bg-white border border-stone-100 group active:bg-stone-50 transition-colors shadow-sm"
                                            >
                                                <div className="flex items-center gap-3">
                                                    <div className="p-2 rounded-xl shadow-sm" style={{ backgroundColor: THEME.colors.secondaryLight }}>
                                                        <Utensils size={16} style={{ color: THEME.colors.secondary }} />
                                                    </div>
                                                    <div className="text-left">
                                                        <p className="text-[11px] font-black truncate max-w-[160px]" style={{ color: THEME.colors.text }}>{meal.menuName}</p>
                                                        <div className="flex items-baseline gap-1">
                                                            <span className="text-[10px] font-black" style={{ color: THEME.colors.secondary }}>{meal.numericCalories}</span>
                                                            <span className="text-[8px] font-bold text-stone-400">kcal</span>
                                                        </div>
                                                    </div>
                                                </div>
                                                <ChevronRight size={16} className="text-stone-300 group-active:translate-x-1 transition-transform" />
                                            </button>
                                        ))}
                                    </div>
                                )}
                            </div>
                        </div>
                    );
                    })}

                    {sortedRecords.length > pagedRecords.length && (
                        <div className="pt-2">
                            <Button 
                                variant="outline" 
                                onClick={() => setPage(p => p + 1)}
                                className="w-full min-h-[56px] h-auto py-3 !rounded-3xl !border-dashed opacity-60 hover:opacity-100 flex items-center justify-center gap-2"
                            >
                                <ArrowDown size={16} className="animate-bounce" />
                                もっと前の記録を見る
                            </Button>
                        </div>
                    )}
                </div>
            )}
        </section>

        <div className="pt-10 pb-20">
            <div className="px-6 mb-4 flex items-center gap-3 opacity-30">
                <div className="h-[1px] flex-1 bg-stone-400"></div>
                <span className="text-[10px] font-black uppercase tracking-widest">End of History</span>
                <div className="h-[1px] flex-1 bg-stone-400"></div>
            </div>
            {/* Sentinel for MREC triggering & MREC space reservation */}
            <div ref={bottomSentinelRef} style={{ height: '300px', width: '100%' }} />
        </div>
      </main>
    </div>
  );
};

