    if (!frontImage) return;
    if (!useToken()) { setStep('ad_wait'); return; }

    await hideBanner();
    await hideMrec();

    setSideImage(sImg);
    setStep('analyze');
    try {
      const result = await analyzePosture(frontImage, sImg);
      setAnalysis(result);
      setStep('result');
    } catch (e: any) {
      alert("解析に失敗しました。");
      setStep('intro');
    }
  };

  const handleStartSide = async () => {
    await hideBanner();
    await hideMrec();
    try {
      const result = await takePhoto(CameraSource.Camera, 'rear');
      startAnalysis(result.base64);
    } catch (e: any) { 
        if (e.message !== "CANCELLED") alert(e.message); 
    }
  };

  const handleRestore = async () => {
    await hideBanner();
    await hideMrec();
    const success = await restoreTokens();
    if (success) {
      setStep('intro');
    }
  };

  const handleSaveAll = async () => {
    if (frontImage && analysis && !isSaving && !hasSaved) {
      setIsSaving(true);
