export const FileInput: React.FC<{ label: string; onFileSelect: (base64: string, mimeType: string) => void; className?: string }> = ({ label, onFileSelect, className = "" }) => {
  const fileInputRef = useRef<HTMLInputElement>(null);

  const handleFileChange = (e: React.ChangeEvent<HTMLInputElement>) => {
    const file = e.target.files?.[0];
    if (!file) return;

    // メモリ負荷対策: readAsDataURLを使用せず、createObjectURL -> Canvas縮小 -> DataURL の順で処理
    const objectUrl = URL.createObjectURL(file);
    const img = new Image();

    img.onload = () => {
      URL.revokeObjectURL(objectUrl);

      let width = img.width;
      let height = img.height;

      // リサイズ計算 (MAX_LONG_SIDE = 640)
      if (width > height) {
        if (width > MAX_LONG_SIDE) {
          height = Math.round((height * MAX_LONG_SIDE) / width);
          width = MAX_LONG_SIDE;
        }
      } else {
        if (height > MAX_LONG_SIDE) {
          width = Math.round((width * MAX_LONG_SIDE) / height);
          height = MAX_LONG_SIDE;
        }
      }

      const canvas = document.createElement('canvas');
      canvas.width = width;
      canvas.height = height;
      const ctx = canvas.getContext('2d');

      if (ctx) {
        ctx.drawImage(img, 0, 0, width, height);
        // 圧縮 (Quality 0.3)
        const dataUrl = canvas.toDataURL('image/jpeg', COMPRESS_QUALITY);

        // "data:image/jpeg;base64," を除去して渡す
        const parts = dataUrl.split(',');
        const base64 = parts[1];
        const mimeType = 'image/jpeg';
        onFileSelect(base64, mimeType);
      }
    };

    img.onerror = () => {
        URL.revokeObjectURL(objectUrl);
        // エラー時は何もしない
    };

    img.src = objectUrl;
    e.target.value = '';
  };

  return (
    <div className={className}>
      <input type="file" ref={fileInputRef} onChange={handleFileChange} accept="image/*" className="hidden" />
      <Button variant="album" onClick={() => fileInputRef.current?.click()} className="w-full min-h-[64px] h-auto py-3">
        <ImageIcon size={20} className="mr-2 shrink-0" style={{ color: THEME.colors.textLight }} />
        {label}
      </Button>
    </div>
  );
};

export const CuteKeypad: React.FC<{ initialValue: string; unit: string; onConfirm: (val: string) => void; onCancel: () => void; }> = ({ initialValue, unit, onConfirm, onCancel }) => {
  const [value, setValue] = useState(initialValue || '0');
  const handlePress = (num: string) => {
    if (num === '.' && value.includes('.')) return;
    setValue(prev => (prev === '0' && num !== '.') ? num : prev + num);
  };
  return createPortal(
    <div className="fixed inset-0 z-[200] flex items-end justify-center bg-black/40 backdrop-blur-sm p-4 pb-28 animate-in fade-in">
      <div className="w-full max-w-md rounded-[40px] p-8 border-4 shadow-2xl animate-in slide-in-from-bottom duration-300" style={{ backgroundColor: THEME.colors.bg, borderColor: THEME.colors.albumShadow }}>
        <div className="flex justify-between items-center mb-8">
          <div className="text-left">
            <span className="text-[10px] font-black uppercase tracking-widest block mb-1" style={{ color: THEME.colors.textLight }}>数値入力</span>
            <div className="flex items-baseline gap-2">
              <span className="text-4xl font-black tracking-tighter" style={{ color: THEME.colors.text }}>{value}</span>
              <span className="text-xs font-black" style={{ color: THEME.colors.textLight }}>{unit}</span>
            </div>
          </div>
          <button onClick={onCancel} className="p-2 rounded-full transition-colors" style={{ color: THEME.colors.textLight }}><X size={28} /></button>
        </div>
        <div className="grid grid-cols-3 gap-3 mb-8">
          {[1, 2, 3, 4, 5, 6, 7, 8, 9].map((num) => (
            <button key={num} onClick={() => handlePress(num.toString())} className="h-16 rounded-2xl bg-white border-2 text-2xl font-black active:scale-95 transition-all shadow-sm" style={{ borderColor: THEME.colors.albumShadow, color: THEME.colors.text }}>{num}</button>
          ))}
          <button 
            onClick={() => setValue('0')} 
            className="h-16 rounded-2xl border-2 flex flex-col items-center justify-center active:scale-95 transition-all shadow-sm leading-tight group"
            style={{ backgroundColor: THEME.colors.dangerLight, borderColor: '#FFD6D6', color: THEME.colors.danger }}
          >
            <Trash2 size={20} className="mb-0.5 group-active:scale-110 transition-transform" />
            <span className="text-[10px] font-black">クリア</span>
          </button>
          <button onClick={() => handlePress('0')} className="h-16 rounded-2xl bg-white border-2 text-2xl font-black active:scale-95 transition-all shadow-sm" style={{ borderColor: THEME.colors.albumShadow, color: THEME.colors.text }}>0</button>
          <button onClick={() => setValue(prev => prev.length > 1 ? prev.slice(0, -1) : '0')} className="h-16 rounded-2xl bg-white border-2 flex items-center justify-center active:scale-95 transition-all shadow-sm" style={{ borderColor: THEME.colors.albumShadow, color: THEME.colors.text }}>
            <Delete size={28} />
          </button>
        </div>
        <Button onClick={() => onConfirm(value)} className="w-full text-lg">確定する</Button>
      </div>
    </div>, document.body
  );
};

