package com.revo.tabetotto

import android.content.ContentValues
import android.graphics.Bitmap
import android.graphics.BitmapFactory
import android.os.Build
import android.os.Environment
import android.provider.MediaStore
import android.util.Base64
import com.getcapacitor.JSObject
import com.getcapacitor.Plugin
import com.getcapacitor.PluginCall
import com.getcapacitor.PluginMethod
import com.getcapacitor.annotation.CapacitorPlugin
import java.io.OutputStream

@CapacitorPlugin(name = "GallerySaver")
class GallerySaverPlugin : Plugin() {

    @PluginMethod
    fun saveImage(call: PluginCall) {
        val base64 = call.getString("base64")
        val fileName = call.getString("fileName") ?: "image_${System.currentTimeMillis()}.jpg"
        val album = call.getString("album") ?: "Tabetotto"

        if (base64 == null) {
            call.reject("No base64 data provided")
            return
        }

        try {
            // Base64デコード
            val decodedBytes = Base64.decode(base64, Base64.DEFAULT)
            val bitmap = BitmapFactory.decodeByteArray(decodedBytes, 0, decodedBytes.size)

            if (bitmap == null) {
                call.reject("Failed to decode bitmap")
                return
            }

            // ギャラリー保存処理
            val savedUri = saveBitmapToGallery(bitmap, fileName, album)
            if (savedUri != null) {
                val ret = JSObject()
                ret.put("saved", true)
                ret.put("uri", savedUri)
                call.resolve(ret)
            } else {
                call.reject("Failed to save image to gallery")
            }
        } catch (e: Exception) {
            call.reject("Error saving image: ${e.message}")
        }
    }

    private fun saveBitmapToGallery(bitmap: Bitmap, fileName: String, albumName: String): String? {
        var outputStream: OutputStream? = null
        return try {
            val contentResolver = context.contentResolver
            val contentValues = ContentValues().apply {
                put(MediaStore.MediaColumns.DISPLAY_NAME, fileName)
                put(MediaStore.MediaColumns.MIME_TYPE, "image/jpeg")
                if (Build.VERSION.SDK_INT >= Build.VERSION_CODES.Q) {
                    // Android 10以上: Pictures/AlbumName に保存
                    put(MediaStore.MediaColumns.RELATIVE_PATH, Environment.DIRECTORY_PICTURES + "/" + albumName)
                    put(MediaStore.MediaColumns.IS_PENDING, 1)
                }
            }

            val imageUri = contentResolver.insert(MediaStore.Images.Media.EXTERNAL_CONTENT_URI, contentValues)
            if (imageUri != null) {
                outputStream = contentResolver.openOutputStream(imageUri)
                if (outputStream != null) {
                    bitmap.compress(Bitmap.CompressFormat.JPEG, 100, outputStream)
                    outputStream.close()

                    if (Build.VERSION.SDK_INT >= Build.VERSION_CODES.Q) {
                        contentValues.clear()
                        contentValues.put(MediaStore.MediaColumns.IS_PENDING, 0)
                        contentResolver.update(imageUri, contentValues, null, null)
                    }
                    return imageUri.toString()
                }
            }
            null
        } catch (e: Exception) {
            e.printStackTrace()
            null
        } finally {
            outputStream?.close()
        }
    }
}

import { Camera, CameraResultType, CameraSource, CameraDirection } from '@capacitor/camera';
import { Capacitor } from '@capacitor/core';

export interface PhotoResult {
  base64: string;
  mimeType: string;
  format: string;
  source: 'camera' | 'file';
  width: number;
  height: number;
}

// 履歴の高速表示と保存容量の最小化、AI解析の高速化のためにサイズを制限
const MAX_LONG_SIDE = 640; // Reduced from 720 to 640 for better performance

/**
 * 画像を指定サイズ以下にリサイズしBase64で返却
 */
const processImage = (img: HTMLImageElement, source: 'camera' | 'file'): PhotoResult => {
  let width = img.width;
  let height = img.height;

  if (width > height) {
    if (width > MAX_LONG_SIDE) {
      height = Math.round((height * MAX_LONG_SIDE) / width);
      width = MAX_LONG_SIDE;
    }
  } else {
    if (height > MAX_LONG_SIDE) {
      width = Math.round((width * MAX_LONG_SIDE) / height);
      height = MAX_LONG_SIDE;
    }
  }

  const canvas = document.createElement('canvas');
  canvas.width = width;
  canvas.height = height;
  const ctx = canvas.getContext('2d');
  if (!ctx) throw new Error("Canvas context creation failed");

  ctx.drawImage(img, 0, 0, width, height);
  const mimeType = 'image/jpeg';
  // 圧縮率を0.3に設定。実機テストで十分な視認性と最小のデータ量を両立。
  const dataUrl = canvas.toDataURL(mimeType, 0.3);
  const base64 = dataUrl.split(',')[1];

  return {
    base64,
    mimeType,
    format: 'jpeg',
    source,
    width,
    height
  };
};

/**
 * Base64画像を圧縮して再取得するユーティリティ
 * FileInputからの画像など、未圧縮のデータを小さくするために使用
 */
export const compressImage = (base64: string): Promise<string> => {
  return new Promise((resolve, reject) => {
    const img = new Image();
    img.onload = () => {
      try {
        const res = processImage(img, 'file');
        resolve(res.base64);
      } catch (e) {
        reject(e);
      }
    };
    img.onerror = () => reject(new Error("Image processing failed"));
    img.src = base64.startsWith('data:') ? base64 : `data:image/jpeg;base64,${base64}`;
  });
};

/**
 * タイムアウト付きFetch
 */
const fetchWithTimeout = (url: string, ms: number): Promise<Blob> => {
    return new Promise((resolve, reject) => {
        const controller = new AbortController();
        const timeoutId = setTimeout(() => {
            controller.abort();
            reject(new Error("Fetch timeout"));
        }, ms);

        fetch(url, { signal: controller.signal })
            .then(res => {
                if (!res.ok) throw new Error(`Fetch error: ${res.status}`);
                return res.blob();
            })
            .then(blob => {
                clearTimeout(timeoutId);
                resolve(blob);
            })
            .catch(err => {
                clearTimeout(timeoutId);
                reject(err);
            });
    });
};

/**
 * Blobから画像を処理
 */
const processBlobToResult = (blob: Blob, source: 'camera' | 'file'): Promise<PhotoResult> => {
    return new Promise((resolve, reject) => {
        const img = new Image();
        const objectUrl = URL.createObjectURL(blob);
        img.onload = () => {
            URL.revokeObjectURL(objectUrl);
            try {
                const res = processImage(img, source);
                resolve(res);
            } catch (err) {
                reject(err);
            }
        };
        img.onerror = (err) => {
            URL.revokeObjectURL(objectUrl);
            reject(new Error("Failed to load image from blob"));
        };
        img.src = objectUrl;
    });
};

/**
 * 写真を撮影または選択
 * 堅牢性向上のため、Uriモードで失敗・タイムアウトした場合はBase64モードにフォールバックする
 */
export const takePhoto = async (source: CameraSource = CameraSource.Prompt, direction: 'front' | 'rear' = 'rear'): Promise<PhotoResult> => {
  // 1. まずはUriモードで試みる（高画質・低メモリ）
  try {
    const image = await Camera.getPhoto({
      quality: 50,
      allowEditing: false,
      resultType: CameraResultType.Uri,
      source: source,
      direction: direction === 'front' ? CameraDirection.Front : CameraDirection.Rear,
      correctOrientation: true,
      width: 1024,
    });

    const imagePath = image.webPath || image.path;
    if (imagePath) {
      // タイムアウト付きでBlob取得を試みる (6000ms)
      // 低スペ端末のWebViewでfetchが固まる現象への対策
      const blob = await fetchWithTimeout(imagePath, 6000);
      return await processBlobToResult(blob, 'camera');
    }
  } catch (e: any) {
    // ユーザーキャンセル時は即終了（フォールバックしない）
    if (e.message?.includes("User cancelled") || e.message === "CANCELLED") {
       throw new Error("CANCELLED");
    }
    // それ以外のエラー（タイムアウト含む）はログを出してBase64フォールバックへ
    console.warn("Uri mode failed or timed out, falling back to Base64:", e);
  }

  // 2. Base64モードでのフォールバック (低スペ端末・WebView不調時用)
  try {
    const image = await Camera.getPhoto({
      quality: 50, // 画質は維持
      allowEditing: false,
      resultType: CameraResultType.Base64,
      source: source,
      direction: direction === 'front' ? CameraDirection.Front : CameraDirection.Rear,
      correctOrientation: true,
      width: 640, // Base64転送負荷軽減のためサイズダウン (1024 -> 640)
    });

    if (image.base64String) {
      return new Promise((resolve, reject) => {
        const img = new Image();
        img.onload = () => {
            try {
                resolve(processImage(img, 'camera'));
            } catch (pErr) {
                reject(pErr);
            }
        };
        img.onerror = () => reject(new Error("Image processing failed (Base64)."));
        img.src = `data:image/${image.format};base64,${image.base64String}`;
      });
    }
  } catch (e: any) {
    if (e.message?.includes("User cancelled") || e.message === "CANCELLED") {
        throw new Error("CANCELLED");
    }
    throw new Error(`Camera Error (Backup): ${e.message}`);
  }

  throw new Error("No image data returned.");
};

import { Download, Gift, Heart, Loader2, PlayCircle, Save, ShieldAlert, Smile, Sparkles, UserCircle, Utensils, X, CheckSquare, Square, ChevronDown, ChevronUp, Scale, Activity, CalendarClock, Shuffle, AlertCircle } from 'lucide-react';
import React, { useEffect, useState } from 'react';
import { showRewardedInterstitialAd } from '../../services/admobService';
import { generateMascot } from '../../services/gemini/character';
import { THEME } from '../../theme';
import { UserProfile } from '../../types';
import { 
    APP_VERSION, 
    BUILD_ID, 
    ICON_RECOVERY_TIME_MS, 
    MAX_ICON_TOKENS, 
    STORAGE_KEY_ICON_LAST_RECOVERY, 
    STORAGE_KEY_ICON_TOKENS,
    calculateBMI,
    toLocalDateString
} from '../../utils';
import { Button, Card, NumberInputDisplay, CuteCalendar } from '../UIComponents';

interface SettingsViewProps {
    user: UserProfile;
    onSave: (u: UserProfile) => void;
    openKeypad: (initialValue: string, unit: string, onConfirm: (val: string) => void) => void;
}

const SettingsView: React.FC<SettingsViewProps> = ({ user, onSave, openKeypad }) => {
    const [nickname, setNickname] = useState(user.nickname || '');
    const [age, setAge] = useState<number | undefined>(user.age);
    const [height, setHeight] = useState(user.height);
    const [targetWeight, setTargetWeight] = useState(user.targetWeight || 0);
    const [showMascotOnShare, setShowMascotOnShare] = useState(user.showMascotOnShare ?? true);
    const [isProfileSaved, setIsProfileSaved] = useState(false);

    const [gender, setGender] = useState<UserProfile['gender']>(user.gender);
    const [activityLevel, setActivityLevel] = useState<UserProfile['activityLevel']>(user.activityLevel);

    // テーマ設定
    const [theme, setTheme] = useState<'default' | 'matte-blue'>(user.theme || 'default');

    const [dietEnabled, setDietEnabled] = useState(user.dietMode?.enabled ?? false);
    const [dietGoal, setDietGoal] = useState<UserProfile['dietMode']['goal']>(user.dietMode?.goal ?? 'maintain');
    const [dietIntensity, setDietIntensity] = useState<UserProfile['dietMode']['intensity']>(user.dietMode?.intensity ?? 'loose');
    const [dietTargetDate, setDietTargetDate] = useState<string | undefined>(user.dietMode?.targetDate);

    const [isDietAccordionOpen, setIsDietAccordionOpen] = useState(false);

    const [calendarOpen, setCalendarOpen] = useState(false);

    const [avatarImage, setAvatarImage] = useState(user.avatarImage || '');
    const [tempAvatarImage, setTempAvatarImage] = useState<string | null>(null);
    const [isGenerating, setIsGenerating] = useState(false);

    // プロンプトはユーザー入力ではなく内部生成用IDとして扱う
    const [mascotPrompt, setMascotPrompt] = useState(user.mascotPrompt || '');

    const [isAvatarApplied, setIsAvatarApplied] = useState(false);
    const [showAdWait, setShowAdWait] = useState(false);
    const [isAdLoading, setIsAdLoading] = useState(false);

    const [iconTokens, setIconTokens] = useState<number>(MAX_ICON_TOKENS);
    const [iconLastRecovery, setIconLastRecovery] = useState<number>(Date.now());

    useEffect(() => {
        const storedTokens = localStorage.getItem(STORAGE_KEY_ICON_TOKENS);
        const storedLast = localStorage.getItem(STORAGE_KEY_ICON_LAST_RECOVERY);
        let t = storedTokens !== null ? parseInt(storedTokens) : MAX_ICON_TOKENS;
        let last = storedLast !== null ? parseInt(storedLast) : Date.now();
        const now = Date.now();
        if (t < MAX_ICON_TOKENS) {
            const elapsed = now - last;
            const recoveredAmount = Math.floor(elapsed / ICON_RECOVERY_TIME_MS);
            if (recoveredAmount > 0) {
                t = Math.min(MAX_ICON_TOKENS, t + recoveredAmount);
                last = last + (recoveredAmount * ICON_RECOVERY_TIME_MS);
            }
        }
        setIconTokens(t);
        setIconLastRecovery(last);
    }, []);

    useEffect(() => {
        localStorage.setItem(STORAGE_KEY_ICON_TOKENS, iconTokens.toString());
        localStorage.setItem(STORAGE_KEY_ICON_LAST_RECOVERY, iconLastRecovery.toString());
    }, [iconTokens, iconLastRecovery]);

    useEffect(() => {
        const timer = setInterval(() => {
            if (iconTokens < MAX_ICON_TOKENS) {
                const now = Date.now();
                if (now - iconLastRecovery >= ICON_RECOVERY_TIME_MS) {
                    setIconTokens(prev => Math.min(MAX_ICON_TOKENS, prev + 1));
                    setIconLastRecovery(prev => prev + ICON_RECOVERY_TIME_MS);
                }
            }
        }, 30000);
        return () => clearInterval(timer);
    }, [iconTokens, iconLastRecovery]);

    const handleSaveProfile = () => {
        onSave({ 
            ...user, 
            nickname, 
            age,
            height, 
            targetWeight, 
            showMascotOnShare,
            gender,
            activityLevel,
            mascotPrompt, 
            theme, // テーマ設定を保存
            dietMode: {
                enabled: dietEnabled,
                goal: dietGoal || 'maintain',
                intensity: dietIntensity || 'loose',
                targetDate: dietTargetDate
            }
        });
        setIsProfileSaved(true);
        setTimeout(() => setIsProfileSaved(false), 2000);
    };

    const handleApplyAvatar = () => {
        if (!tempAvatarImage) return;
        const cleanBase64 = tempAvatarImage.replace(/^data:image\/[a-z]+;base64,/, "");
        onSave({ 
            ...user, 
            avatarImage: cleanBase64, 
            mascotPrompt: mascotPrompt,
            showMascotOnShare 
        });
        setAvatarImage(cleanBase64);
        setTempAvatarImage(null);
        setIsAvatarApplied(true);
        setTimeout(() => setIsAvatarApplied(false), 2000);
    };

    const handleRestoreIconTokens = async () => {
        setIsAdLoading(true);
        try {
            const success = await showRewardedInterstitialAd();
            if (success) {
                setIconTokens(MAX_ICON_TOKENS);
                setIconLastRecovery(Date.now());
                setShowAdWait(false);
            }
        } catch (e) {
            alert("広告の読み込みに失敗しました。時間をおいて再度お試しください。");
        } finally {
            setIsAdLoading(false);
        }
    };

    const handleStartGeneration = () => {
        // ランダムなシードを生成して渡す
        const newSeed = Math.random().toString(36).substring(7) + Date.now().toString();
        setMascotPrompt(newSeed);
        handleGenerateMascot(newSeed);
    };

    const handleGenerateMascot = async (seed: string) => {
        setIsGenerating(true);
        try {
            const base64 = await generateMascot(seed);
            const displayUrl = base64.startsWith('data:') ? base64 : `data:image/png;base64,${base64}`;
            setTempAvatarImage(displayUrl);
        } catch (e: any) {
            alert(e.message || "生成に失敗しました。");
        } finally {
            setIsGenerating(false);
