export default SettingsView;

import { CameraSource } from '@capacitor/camera';
import { Loader2, Utensils, X, Camera, CalendarPlus, Share2, Sparkles, Check, Gift, PlayCircle, BookOpen, Menu, Drumstick, Droplet, Wheat, Download, Edit2, Smile, User, PenTool, Save, RotateCcw, HardDrive } from 'lucide-react';
import React, { useEffect, useState, useCallback, useRef } from 'react';
import { PieChart, Pie, Cell, ResponsiveContainer } from 'recharts';
import { hideBanner, showBannerForCamera, showBanner, hideMrec, showMrec } from '../../services/admobService';
import { takePhoto, compressImage } from '../../services/cameraService';
import { analyzeMeal } from '../../services/gemini/meal';
import { THEME } from '../../theme';
import { MealAnalysis, MealType, UserProfile } from '../../types';
import { getTodayString, addToCalendar, generateShareImageBlob, MEAL_TYPE_LABELS, PFC_COLORS, resolveMealImageSrc } from '../../utils';
import { Button, FileInput, Card } from '../UIComponents';
import { Share } from '@capacitor/share';
import { Filesystem, Directory } from '@capacitor/filesystem';
import { Capacitor } from '@capacitor/core';
import { renderMealResultToBlob } from '../../services/renderers/mealResultRenderer';
import { GallerySaver } from '../../src/plugins/GallerySaver';

interface MealViewProps {
  user: UserProfile;
  tokens: number;
  useToken: () => boolean;
  restoreTokens: () => Promise<boolean>;
  onSave: (analysis: MealAnalysis, photo: string, date: string) => void;
  onClose: () => void;
  onShareClick: (preGeneratedBlob?: Blob) => void;
  openKeypad: (initialValue: string, unit: string, onConfirm: (val: string) => void) => void;
  openCalendar: (initialDate: string, onConfirm: (date: string) => void) => void;
  onOpenGuide?: () => void;
  onMenuOpen: () => void;
  isMenuOpen: boolean; // Added for ad control
}

const MealView: React.FC<MealViewProps> = ({ user, tokens, useToken, restoreTokens, onSave, onClose, onShareClick, onOpenGuide, onMenuOpen, openKeypad, isMenuOpen }) => {
  const [step, setStep] = useState<'intro' | 'ad_wait' | 'analyze' | 'result'>('intro');
  const [image, setImage] = useState<string | null>(null);
  const [analysis, setAnalysis] = useState<MealAnalysis | null>(null);

  // 編集用のState
  const [editedMenuName, setEditedMenuName] = useState('');
  const [isEditingName, setIsEditingName] = useState(false); 
  const [editedCalories, setEditedCalories] = useState(0);

  const [selectedMealType, setSelectedMealType] = useState<MealType>('lunch');
  const [isSaving, setIsSaving] = useState(false);
  const [hasSaved, setHasSaved] = useState(false);
  const [isSharing, setIsSharing] = useState(false);
  const [previewBlob, setPreviewBlob] = useState<Blob | null>(null);

  const recordDate = getTodayString();

  // 画面遷移・ステップに応じた広告制御
  useEffect(() => {
    // メニューが開いているときはApp.tsxが全広告を消すので、ここでは何もしない
    // メニューが閉じている時だけ制御する
    if (isMenuOpen) return;

    if (step === 'analyze' || step === 'ad_wait') {
        // 解析中・待機中は全広告禁止
        hideBanner();
        hideMrec();
    } else if (step === 'result') {
        // 結果画面はMRECだとコンテンツを隠すため、通常バナーに戻す
        hideMrec();
        showBanner();
    } else {
        // intro (通常画面) は MRECを表示
        hideBanner();
        showMrec();
    }

    return () => { 
        // 制御はApp.tsx側に戻る
    };
  }, [step, isMenuOpen]);

  // トークン切れでad_waitになった場合の特別処理 (上記useEffectでカバー済み)

  const handleImageProcess = async (base64: string) => {
    if (!useToken()) { setStep('ad_wait'); return; }
    // 解析開始直前に広告を消す念押し
    await hideBanner();
    await hideMrec();

    setImage(base64);
    setStep('analyze');
    try {
      const result = await analyzeMeal(base64);
      setAnalysis(result);
      setEditedMenuName(result.menuName);
      setEditedCalories(result.numericCalories);
      setStep('result');
    } catch (e: any) {
      alert("解析に失敗しました。電波環境を確認してください。");
      setStep('intro');
    }
  };

  const handleManualInput = async () => {
    // 広告制御
    await hideBanner();
    await hideMrec();

    setImage(null);
    const initialAnalysis: MealAnalysis = {
        menuName: '手入力メモ',
        numericCalories: 0,
        pfcRatio: { p: 0, f: 0, c: 0 },
        comment: '自分で記録しました',
        mealType: 'lunch'
    };
    setAnalysis(initialAnalysis);
    setEditedMenuName(initialAnalysis.menuName);
    setEditedCalories(initialAnalysis.numericCalories);
    setStep('result');
  };

  const getCurrentAnalysis = useCallback((): MealAnalysis => {
      if (!analysis) throw new Error("No analysis");
      return {
          ...analysis,
          menuName: editedMenuName,
          numericCalories: editedCalories,
          mealType: selectedMealType
      };
  }, [analysis, editedMenuName, editedCalories, selectedMealType]);

  useEffect(() => {
      if (step === 'result' && image && analysis) {
          const updatePreview = async () => {
              const current = getCurrentAnalysis();
              const blob = await renderMealResultToBlob(
                  image, 
                  current, 
                  recordDate, 
                  { showMascot: user.showMascotOnShare ?? true, avatarBase64: user.avatarImage }
              );
              setPreviewBlob(blob);
          };
          updatePreview();
      } else if (step === 'result' && !image) {
          setPreviewBlob(null);
      }
  }, [step, image, analysis, editedMenuName, editedCalories, selectedMealType, user.showMascotOnShare, user.avatarImage, getCurrentAnalysis]);


  const handleStartCapture = async () => {
    if (tokens <= 0) { setStep('ad_wait'); return; }

    // カメラ起動前にも広告を消す
    await hideBanner();
    await hideMrec();

    try {
      const result = await takePhoto(CameraSource.Camera, 'rear');
      handleImageProcess(result.base64);
    } catch (e: any) { 
      if (e.message !== "CANCELLED") alert(e.message); 
      // キャンセル時はIntroに戻るので、広告復帰はStep変更useEffectで行われる
    }
  };

  const handleRestore = async () => {
    // リワード広告表示時はAdMobプラグインが全画面を覆うが、念のため既存バナーは非表示に
    await hideBanner();
    await hideMrec();
    const success = await restoreTokens();
    if (success) {
      setStep('intro');
    }
  };

  const handleRetake = () => {
    // ユーザーからのフィードバック対応: 確認ダイアログを削除し、即座に戻る
    setImage(null);
    setAnalysis(null);
    setStep('intro');
  };

  const handleSaveToApp = async () => {
    if (!analysis || isSaving || hasSaved) return;
    // 画像がある場合はプレビュー生成を待つ
    if (image && !previewBlob) return;

    setIsSaving(true);

    try {
        let fileUri = "";

        // 画像がある場合のみ、画像生成・保存処理を行う
        if (image && previewBlob) {
            const blob = previewBlob;
            const reader = new FileReader();
            const base64Promise = new Promise<string>((resolve) => {
                reader.onloadend = () => {
                    const base64String = reader.result as string;
                    resolve(base64String.split(',')[1]);
                };
                reader.readAsDataURL(blob);
            });
            const base64data = await base64Promise;
            const fileName = `tabetotto_${recordDate.replace(/-/g, '')}_${Date.now()}.jpg`;

            let gallerySaved = false;
            if (Capacitor.getPlatform() === 'android') {
                try {
                    const res = await GallerySaver.saveImage({
                        base64: base64data,
                        fileName: fileName,
                        album: 'たべとっと。'
                    });
                    if (res.saved) {
                        gallerySaved = true;
                    }
                } catch (e) {
                    console.warn("Gallery save failed:", e);
                }
            }

            if (!gallerySaved) {
                if (Capacitor.isNativePlatform()) {
                     try {
                        await Filesystem.writeFile({
                            path: fileName,
                            data: base64data,
                            directory: Directory.Documents,
                        });
                     } catch (fsError) {
                        console.error("Device documents save failed", fsError);
                     }
                } else {
                     const url = URL.createObjectURL(blob);
                     const a = document.createElement('a');
                     a.href = url;
                     a.download = fileName;
                     a.click();
                     URL.revokeObjectURL(url);
                }
            }

            const savedFile = await Filesystem.writeFile({
                path: fileName,
                data: base64data,
                directory: Directory.Data,
            });
            fileUri = savedFile.uri;
        }

        // 手入力の場合、fileUriは空文字で保存
        onSave(getCurrentAnalysis(), fileUri, recordDate);
        setHasSaved(true);

    } catch (e) {
        console.error("Save error:", e);
        alert("保存中にエラーが発生しました");
        setIsSaving(false);
    } finally {
        setIsSaving(false);
    }
  };

  const handleDirectShare = async () => {
    if (!analysis || !image || isSharing || !previewBlob) return;
    setIsSharing(true);

    try {
        const blob = previewBlob;

        if (Capacitor.isNativePlatform()) {
            const reader = new FileReader();
            const base64Promise = new Promise<string>((resolve) => {
                reader.onloadend = () => {
                    const base64String = reader.result as string;
                    resolve(base64String.split(',')[1]);
                };
                reader.readAsDataURL(blob);
            });
            const base64data = await base64Promise;
            const fileName = `tabetotto_share_${recordDate.replace(/-/g, '')}_${Date.now()}.jpg`;

            await Filesystem.writeFile({
                path: fileName,
                data: base64data,
                directory: Directory.Cache,
            });

            const { uri } = await Filesystem.getUri({
                directory: Directory.Cache,
                path: fileName
            });

            await Share.share({
                title: 'たべとっと。で食事を記録しました',
                text: '今日の食事記録です✨ #たべとっと',
                url: uri,
            });
        } else if (navigator.share && navigator.canShare && navigator.canShare({ files: [new File([blob], "share.jpg", { type: "image/jpeg" })] })) {
            const file = new File([blob], "diet_record.jpg", { type: "image/jpeg" });
            await navigator.share({
                files: [file],
                title: 'たべとっと。で食事を記録しました',
