import React, { useState, useRef } from 'react';
import { createPortal } from 'react-dom';
import { Loader2, X, Delete, ImageIcon, Eraser, Trash2 } from 'lucide-react';
import { THEME } from '../theme';

// 圧縮設定 (Project Standard)
const MAX_LONG_SIDE = 640;
const COMPRESS_QUALITY = 0.3;

interface ButtonProps extends React.ButtonHTMLAttributes<HTMLButtonElement> {
  variant?: 'primary' | 'secondary' | 'album' | 'danger' | 'outline';
  isLoading?: boolean;
}

export const Button: React.FC<ButtonProps> = ({ children, variant = 'primary', isLoading, className = '', disabled, ...props }) => {
  // 文字サイズ拡大時にボタンが崩れないよう、固定高さh-14を廃止し、min-h-[56px]とパディングで高さを確保
  const baseStyles = "btn-paper min-h-[56px] h-auto py-3 text-lg px-6 disabled:opacity-50 disabled:cursor-not-allowed flex items-center justify-center break-words whitespace-normal leading-tight";

  let dynamicStyles = {};
  if (variant === 'primary') {
    dynamicStyles = {
      backgroundColor: THEME.colors.primary,
      color: 'white',
      borderRadius: THEME.shapes.paperPrimary,
      border: `1px solid ${THEME.colors.primaryShadow}`,
      boxShadow: `${THEME.colors.primaryShadow} ${THEME.shadows.deep}`,
    };
  } else if (variant === 'secondary') {
    dynamicStyles = {
      backgroundColor: THEME.colors.secondary,
      color: 'white',
      borderRadius: THEME.shapes.paperSecondary,
      border: `1px solid ${THEME.colors.secondaryShadow}`,
      boxShadow: `${THEME.colors.secondaryShadow} ${THEME.shadows.deep}`,
    };
  } else if (variant === 'album') {
    dynamicStyles = {
      backgroundColor: THEME.colors.album,
      color: THEME.colors.text,
      borderRadius: THEME.shapes.paperAlbum,
      border: `3px solid ${THEME.colors.albumShadow}`,
      boxShadow: `${THEME.colors.albumShadow} ${THEME.shadows.deep.replace('5px', '4px')}`,
    };
  } else if (variant === 'outline') {
    dynamicStyles = {
      backgroundColor: 'transparent',
      color: THEME.colors.text,
      borderRadius: THEME.shapes.paperAlbum,
      border: `2px solid ${THEME.colors.albumShadow}`,
    };
  } else if (variant === 'danger') {
    dynamicStyles = {
      backgroundColor: THEME.colors.dangerLight,
      color: THEME.colors.danger,
      borderRadius: THEME.shapes.paperAlbum,
      border: `2px solid #FFD6D6`,
    };
  }

  return (
    <button 
      className={`${baseStyles} ${className}`} 
      style={dynamicStyles}
      disabled={disabled || isLoading}
      {...props}
    >
      {isLoading && <Loader2 className="w-5 h-5 mr-2 animate-spin shrink-0" />}
      {children}
    </button>
  );
};

