        </div>
        <div className="grid grid-cols-3 gap-3 mb-8">
          {[1, 2, 3, 4, 5, 6, 7, 8, 9].map((num) => (
            <button key={num} onClick={() => handlePress(num.toString())} className="h-16 rounded-2xl bg-white border-2 text-2xl font-black active:scale-95 transition-all shadow-sm" style={{ borderColor: THEME.colors.albumShadow, color: THEME.colors.text }}>{num}</button>
          ))}
          <button 
            onClick={() => setValue('0')} 
            className="h-16 rounded-2xl border-2 flex flex-col items-center justify-center active:scale-95 transition-all shadow-sm leading-tight group"
            style={{ backgroundColor: THEME.colors.dangerLight, borderColor: '#FFD6D6', color: THEME.colors.danger }}
