export const SharePreviewModal: React.FC<{
  isOpen: boolean;
  onClose: () => void;
  mealAnalysis: MealAnalysis;
  photoBase64: string;
  dateStr: string;
  initialBlob?: Blob | null;
}> = ({ isOpen, onClose, mealAnalysis, photoBase64, dateStr, initialBlob }) => {
  // モーダルが開いている間は全広告を非表示にする
  useEffect(() => {
    if (isOpen) {
        hideBanner();
        hideMrec(); // Ensure MREC is hidden
    } else if (Capacitor.isNativePlatform()) {
        showBanner();
    }
  }, [isOpen]);

  const [blob, setBlob] = useState<Blob | null>(initialBlob || null);
  const [previewUrl, setPreviewUrl] = useState<string | null>(null);
  const [isSharing, setIsSharing] = useState(false);
  const [hasSaved, setHasSaved] = useState(false);

  // photoBase64 が URI形式かどうか判定
  const isUriSource = photoBase64 && (photoBase64.startsWith('file:') || photoBase64.startsWith('content:') || photoBase64.startsWith('http'));

  useEffect(() => {
    let objectUrl: string | null = null;
    if (isOpen) {
        if (blob) {
            // 生成済みのBlobがある場合（手動生成フロー）
            objectUrl = URL.createObjectURL(blob);
            setPreviewUrl(objectUrl);
        } else if (isUriSource) {
            // 既にファイルとして保存されている場合（URIをそのまま使う）
            setPreviewUrl(Capacitor.convertFileSrc(photoBase64));
        } else if (photoBase64) {
            // 旧データ（Base64文字列）の場合 -> Blob生成してプレビュー
            const recordsStr = localStorage.getItem('tabetotto_records');
            let weight: number | undefined;
            if (recordsStr) {
              const records = JSON.parse(recordsStr);
              weight = records[dateStr]?.weight;
            }
            const userStr = localStorage.getItem('tabetotto_user');
            const user = userStr ? JSON.parse(userStr) : {};
            generateShareImageBlob(photoBase64, mealAnalysis, dateStr, weight, user.avatarImage, user.showMascotOnShare).then((generatedBlob) => {
                if (generatedBlob) {
                    objectUrl = URL.createObjectURL(generatedBlob);
                    setBlob(generatedBlob);
                    setPreviewUrl(objectUrl);
                }
            });
        }
    }
    return () => {
        if (objectUrl) URL.revokeObjectURL(objectUrl);
        if (blob && !initialBlob) setBlob(null); // Cleanup generated blob
    };
  }, [isOpen, blob, photoBase64, mealAnalysis, dateStr, initialBlob, isUriSource]);

  const handleShare = async () => {
    if ((!blob && !isUriSource) || isSharing) return;
    setIsSharing(true);

    try {
        if (isUriSource) {
            // 既にファイルがある場合はそのパスを直接シェア
            await Share.share({
                title: 'たべとっと。で食事を記録しました',
                text: '今日の食事記録です✨ #たべとっと',
                url: photoBase64, // file:// URI
            });
        } else if (Capacitor.isNativePlatform() && blob) {
            // Blobからファイル書き出し -> シェア
            const reader = new FileReader();
            const base64Promise = new Promise<string>((resolve) => {
                reader.onloadend = () => {
                    const base64String = reader.result as string;
                    resolve(base64String.split(',')[1]);
                };
                reader.readAsDataURL(blob);
            });
            const base64data = await base64Promise;
            const fileName = `tabetotto_share_${dateStr.replace(/-/g, '')}_${Date.now()}.jpg`;

            await Filesystem.writeFile({
                path: fileName,
                data: base64data,
                directory: Directory.Cache,
            });

            const { uri } = await Filesystem.getUri({
                directory: Directory.Cache,
                path: fileName
            });

            await Share.share({
                title: 'たべとっと。で食事を記録しました',
                text: '今日の食事記録です✨ #たべとっと',
                url: uri,
            });
        } else if (navigator.share && navigator.canShare && blob && navigator.canShare({ files: [new File([blob], "share.jpg", { type: "image/jpeg" })] })) {
            const file = new File([blob], "diet_record.jpg", { type: "image/jpeg" });
            await navigator.share({
                files: [file],
                title: 'たべとっと。で食事を記録しました',
                text: '今日の食事記録です✨ #たべとっと'
            });
        } else {
            handleDownload();
        }
    } catch (e: any) {
        if (e.name !== 'AbortError') handleDownload();
    } finally {
        setIsSharing(false);
    }
  };

  const handleDownload = () => {
      if (!previewUrl) return;
      const a = document.createElement('a');
      a.href = previewUrl;
      a.download = `tabetotto_${dateStr}.jpg`;
      a.click();
      setHasSaved(true);
  };

  if (!isOpen) return null;

  return (
    <Modal isOpen={isOpen} onClose={onClose} title="シェアして保存">
       <div className="flex flex-col items-center space-y-4 relative">
           <header className="w-full flex items-center justify-between mb-2">
                <div className="flex items-center gap-2">
                    <div className="w-7 h-7 rounded flex items-center justify-center shadow-sm" style={{ backgroundColor: THEME.colors.primary }}>
                        <Utensils size={14} className="text-white" strokeWidth={3} />
                    </div>
                    <h2 className="font-zen-maru font-black text-sm tracking-widest" style={{ color: THEME.colors.primary }}>たべとっと。</h2>
                </div>
           </header>

           {previewUrl ? (
               // 生成された画像サイズ(3:4)に合わせてコンテナも 3:4 に調整
               <div className="w-full aspect-[3/4] shadow-2xl rounded-2xl overflow-hidden border-4 border-white animate-in zoom-in-95">
                   <img src={previewUrl} className="w-full h-full object-contain bg-[#FFFDF5]" />
               </div>
           ) : (
               <div className="w-full aspect-[3/4] flex flex-col items-center justify-center bg-stone-100 rounded-2xl border" style={{ borderColor: THEME.colors.albumShadow }}>
                   <Loader2 className="animate-spin w-10 h-10 mb-2" style={{ color: THEME.colors.primary }} />
                   <p className="text-xs font-bold" style={{ color: THEME.colors.textLight }}>画像を生成中...</p>
               </div>
           )}

           <div className="grid grid-cols-2 gap-3 w-full pt-2">
               <Button onClick={handleShare} variant="secondary" isLoading={isSharing} disabled={!blob && !isUriSource} className="min-h-[56px] h-auto shadow-md !rounded-3xl py-3">
                   <Share2 size={18} className="mr-2" /> シェア
               </Button>
               <button 
                  onClick={handleDownload} 
                  disabled={!previewUrl}
                  className={`min-h-[56px] h-auto py-3 border-2 font-black text-sm rounded-3xl transition-all flex items-center justify-center shadow-sm active:scale-95 ${hasSaved ? 'bg-secondary text-white border-secondary' : 'bg-white text-stone-600 border-stone-200'}`}
                  style={hasSaved ? { backgroundColor: THEME.colors.secondary, borderColor: THEME.colors.secondary } : {}}
               >
                   {hasSaved ? (
                       <><Check size={18} className="mr-2" /> 保存済み</>
                   ) : (
                       <><Download size={18} className="mr-2" /> 保存</>
                   )}
               </button>
           </div>

           <div className="w-full pt-4">
              <Button onClick={onClose} variant="cancel" className="w-full min-h-[48px] h-auto py-3 !border-dashed !rounded-2xl text-xs opacity-60">
                  完了してとじる
              </Button>
           </div>

           <p className="text-[9px] font-bold text-stone-400">※保存ボタンを押しても反応がない場合は、画像を長押しして保存してください</p>
       </div>
    </Modal>
  );
};

