import { CameraSource } from '@capacitor/camera';
import { Loader2, Utensils, X, Camera, CalendarPlus, Share2, Sparkles, Check, Gift, PlayCircle, BookOpen, Menu, Drumstick, Droplet, Wheat, Download, Edit2, Smile, User, PenTool, Save, RotateCcw, HardDrive } from 'lucide-react';
import React, { useEffect, useState, useCallback, useRef } from 'react';
import { PieChart, Pie, Cell, ResponsiveContainer } from 'recharts';
import { hideBanner, showBannerForCamera, showBanner, hideMrec, showMrec } from '../../services/admobService';
import { takePhoto, compressImage } from '../../services/cameraService';
import { analyzeMeal } from '../../services/gemini/meal';
import { THEME } from '../../theme';
import { MealAnalysis, MealType, UserProfile } from '../../types';
import { getTodayString, addToCalendar, generateShareImageBlob, MEAL_TYPE_LABELS, PFC_COLORS, resolveMealImageSrc } from '../../utils';
import { Button, FileInput, Card } from '../UIComponents';
import { Share } from '@capacitor/share';
import { Filesystem, Directory } from '@capacitor/filesystem';
import { Capacitor } from '@capacitor/core';
import { renderMealResultToBlob } from '../../services/renderers/mealResultRenderer';
import { GallerySaver } from '../../src/plugins/GallerySaver';

interface MealViewProps {
  user: UserProfile;
  tokens: number;
  useToken: () => boolean;
  restoreTokens: () => Promise<boolean>;
  onSave: (analysis: MealAnalysis, photo: string, date: string) => void;
  onClose: () => void;
  onShareClick: (preGeneratedBlob?: Blob) => void;
  openKeypad: (initialValue: string, unit: string, onConfirm: (val: string) => void) => void;
  openCalendar: (initialDate: string, onConfirm: (date: string) => void) => void;
  onOpenGuide?: () => void;
  onMenuOpen: () => void;
  isMenuOpen: boolean; // Added for ad control
}

const MealView: React.FC<MealViewProps> = ({ user, tokens, useToken, restoreTokens, onSave, onClose, onShareClick, onOpenGuide, onMenuOpen, openKeypad, isMenuOpen }) => {
  const [step, setStep] = useState<'intro' | 'ad_wait' | 'analyze' | 'result'>('intro');
  const [image, setImage] = useState<string | null>(null);
  const [analysis, setAnalysis] = useState<MealAnalysis | null>(null);

  // 編集用のState
  const [editedMenuName, setEditedMenuName] = useState('');
  const [isEditingName, setIsEditingName] = useState(false); 
  const [editedCalories, setEditedCalories] = useState(0);

  const [selectedMealType, setSelectedMealType] = useState<MealType>('lunch');
  const [isSaving, setIsSaving] = useState(false);
  const [hasSaved, setHasSaved] = useState(false);
  const [isSharing, setIsSharing] = useState(false);
  const [previewBlob, setPreviewBlob] = useState<Blob | null>(null);

  const recordDate = getTodayString();

  // 画面遷移・ステップに応じた広告制御
  useEffect(() => {
    // メニューが開いているときはApp.tsxが全広告を消すので、ここでは何もしない
    // メニューが閉じている時だけ制御する
    if (isMenuOpen) return;

    if (step === 'analyze' || step === 'ad_wait') {
        // 解析中・待機中は全広告禁止
        hideBanner();
        hideMrec();
    } else if (step === 'result') {
        // 結果画面はMRECだとコンテンツを隠すため、通常バナーに戻す
        hideMrec();
        showBanner();
    } else {
        // intro (通常画面) は MRECを表示
        hideBanner();
        showMrec();
    }

    return () => { 
        // 制御はApp.tsx側に戻る
    };
  }, [step, isMenuOpen]);

  // トークン切れでad_waitになった場合の特別処理 (上記useEffectでカバー済み)

  const handleImageProcess = async (base64: string) => {
    if (!useToken()) { setStep('ad_wait'); return; }
    // 解析開始直前に広告を消す念押し
    await hideBanner();
    await hideMrec();

    setImage(base64);
    setStep('analyze');
    try {
      const result = await analyzeMeal(base64);
      setAnalysis(result);
      setEditedMenuName(result.menuName);
      setEditedCalories(result.numericCalories);
      setStep('result');
    } catch (e: any) {
      alert("解析に失敗しました。電波環境を確認してください。");
      setStep('intro');
    }
  };

  const handleManualInput = async () => {
    // 広告制御
    await hideBanner();
    await hideMrec();

    setImage(null);
    const initialAnalysis: MealAnalysis = {
        menuName: '手入力メモ',
        numericCalories: 0,
        pfcRatio: { p: 0, f: 0, c: 0 },
        comment: '自分で記録しました',
        mealType: 'lunch'
    };
    setAnalysis(initialAnalysis);
    setEditedMenuName(initialAnalysis.menuName);
    setEditedCalories(initialAnalysis.numericCalories);
    setStep('result');
  };

  const getCurrentAnalysis = useCallback((): MealAnalysis => {
      if (!analysis) throw new Error("No analysis");
      return {
          ...analysis,
          menuName: editedMenuName,
          numericCalories: editedCalories,
          mealType: selectedMealType
      };
  }, [analysis, editedMenuName, editedCalories, selectedMealType]);

  useEffect(() => {
      if (step === 'result' && image && analysis) {
          const updatePreview = async () => {
              const current = getCurrentAnalysis();
              const blob = await renderMealResultToBlob(
                  image, 
                  current, 
                  recordDate, 
                  { showMascot: user.showMascotOnShare ?? true, avatarBase64: user.avatarImage }
              );
              setPreviewBlob(blob);
          };
          updatePreview();
      } else if (step === 'result' && !image) {
          setPreviewBlob(null);
      }
  }, [step, image, analysis, editedMenuName, editedCalories, selectedMealType, user.showMascotOnShare, user.avatarImage, getCurrentAnalysis]);


  const handleStartCapture = async () => {
    if (tokens <= 0) { setStep('ad_wait'); return; }

    // カメラ起動前にも広告を消す
    await hideBanner();
    await hideMrec();

    try {
      const result = await takePhoto(CameraSource.Camera, 'rear');
      handleImageProcess(result.base64);
    } catch (e: any) { 
      if (e.message !== "CANCELLED") alert(e.message); 
      // キャンセル時はIntroに戻るので、広告復帰はStep変更useEffectで行われる
    }
  };

  const handleRestore = async () => {
    // リワード広告表示時はAdMobプラグインが全画面を覆うが、念のため既存バナーは非表示に
    await hideBanner();
    await hideMrec();
    const success = await restoreTokens();
    if (success) {
      setStep('intro');
    }
  };

  const handleRetake = () => {
    // ユーザーからのフィードバック対応: 確認ダイアログを削除し、即座に戻る
    setImage(null);
    setAnalysis(null);
    setStep('intro');
  };

  const handleSaveToApp = async () => {
    if (!analysis || isSaving || hasSaved) return;
    // 画像がある場合はプレビュー生成を待つ
    if (image && !previewBlob) return;

    setIsSaving(true);

    try {
        let fileUri = "";

        // 画像がある場合のみ、画像生成・保存処理を行う
        if (image && previewBlob) {
            const blob = previewBlob;
            const reader = new FileReader();
            const base64Promise = new Promise<string>((resolve) => {
                reader.onloadend = () => {
                    const base64String = reader.result as string;
                    resolve(base64String.split(',')[1]);
                };
                reader.readAsDataURL(blob);
            });
            const base64data = await base64Promise;
            const fileName = `tabetotto_${recordDate.replace(/-/g, '')}_${Date.now()}.jpg`;

            let gallerySaved = false;
            if (Capacitor.getPlatform() === 'android') {
                try {
                    const res = await GallerySaver.saveImage({
                        base64: base64data,
                        fileName: fileName,
                        album: 'たべとっと。'
                    });
                    if (res.saved) {
                        gallerySaved = true;
                    }
                } catch (e) {
                    console.warn("Gallery save failed:", e);
                }
            }

            if (!gallerySaved) {
                if (Capacitor.isNativePlatform()) {
                     try {
                        await Filesystem.writeFile({
                            path: fileName,
                            data: base64data,
                            directory: Directory.Documents,
                        });
                     } catch (fsError) {
                        console.error("Device documents save failed", fsError);
                     }
                } else {
                     const url = URL.createObjectURL(blob);
                     const a = document.createElement('a');
                     a.href = url;
                     a.download = fileName;
                     a.click();
                     URL.revokeObjectURL(url);
                }
            }

            const savedFile = await Filesystem.writeFile({
                path: fileName,
                data: base64data,
                directory: Directory.Data,
            });
            fileUri = savedFile.uri;
        }

        // 手入力の場合、fileUriは空文字で保存
        onSave(getCurrentAnalysis(), fileUri, recordDate);
        setHasSaved(true);

    } catch (e) {
        console.error("Save error:", e);
        alert("保存中にエラーが発生しました");
        setIsSaving(false);
    } finally {
        setIsSaving(false);
    }
  };

  const handleDirectShare = async () => {
    if (!analysis || !image || isSharing || !previewBlob) return;
    setIsSharing(true);

    try {
        const blob = previewBlob;

        if (Capacitor.isNativePlatform()) {
            const reader = new FileReader();
            const base64Promise = new Promise<string>((resolve) => {
                reader.onloadend = () => {
                    const base64String = reader.result as string;
                    resolve(base64String.split(',')[1]);
                };
                reader.readAsDataURL(blob);
            });
            const base64data = await base64Promise;
            const fileName = `tabetotto_share_${recordDate.replace(/-/g, '')}_${Date.now()}.jpg`;

            await Filesystem.writeFile({
                path: fileName,
                data: base64data,
                directory: Directory.Cache,
            });

            const { uri } = await Filesystem.getUri({
                directory: Directory.Cache,
                path: fileName
            });

            await Share.share({
                title: 'たべとっと。で食事を記録しました',
                text: '今日の食事記録です✨ #たべとっと',
                url: uri,
            });
        } else if (navigator.share && navigator.canShare && navigator.canShare({ files: [new File([blob], "share.jpg", { type: "image/jpeg" })] })) {
            const file = new File([blob], "diet_record.jpg", { type: "image/jpeg" });
            await navigator.share({
                files: [file],
                title: 'たべとっと。で食事を記録しました',
                text: '今日の食事記録です✨ #たべとっと'
            });
        } else {
            const url = URL.createObjectURL(blob);
            const a = document.createElement('a');
            a.href = url;
            a.download = `tabetotto_share_${recordDate}.jpg`;
            a.click();
            URL.revokeObjectURL(url);
            alert("画像を保存しました");
        }
    } catch (e) {
        alert("シェアに失敗しました");
    } finally {
        setIsSharing(false);
    }
  };

  return (
    <div className="flex flex-col min-h-screen pb-44 w-full no-scrollbar overflow-x-hidden relative">
      {/* Background Decor */}
      <div className="organic-blob w-80 h-80 top-20 -right-40 animate-float-slow will-change-transform" style={{ backgroundColor: THEME.colors.primaryLight }}></div>
      <div className="organic-blob w-64 h-64 bottom-60 -left-32 animate-float-slow will-change-transform" style={{ backgroundColor: THEME.colors.secondaryLight, animationDelay: '2s' }}></div>

      <header className="sticky top-0 z-[60] pt-safe backdrop-blur-md border-b w-full shadow-sm" style={{ backgroundColor: `${THEME.colors.bg}E6`, borderColor: THEME.colors.border }}>
         <div className="px-6 py-3 flex justify-between items-center w-full">
            <div className="flex items-center gap-2">
                <div className="w-11 h-11 rounded-full flex items-center justify-center shadow-[0_15px_35px_-8px_rgba(248,141,141,0.5)] animate-sway transition-transform will-change-transform" style={{ backgroundColor: THEME.colors.primary }}>
                    <Utensils size={22} className="text-white" strokeWidth={3} />
                </div>
                <div className="flex flex-col">
                  <h1 className="text-xl font-black tracking-widest leading-none" style={{ color: THEME.colors.primary }}>たべとっと。</h1>
                  <span className="text-[8px] font-black tracking-tighter opacity-70" style={{ color: THEME.colors.primary }}>Meal Record</span>
                </div>
            </div>
            <div className="flex items-center gap-3">
                <button onClick={onMenuOpen} className="pl-4 pr-3 py-2 rounded-full shadow-md active:scale-95 transition-all flex items-center gap-2 border-2 border-white ring-2" style={{ backgroundColor: THEME.colors.primary, color: 'white', borderColor: 'white', ['--tw-ring-color' as any]: `${THEME.colors.primary}33` }}>
                    <span className="text-sm font-black tracking-wide">Menu</span>
                    <Menu size={20} strokeWidth={2.5} />
                </button>
            </div>
         </div>
      </header>

      {isEditingName && (
          <div className="fixed inset-0 z-[999] flex items-center justify-center bg-black/60 px-6 animate-in fade-in backdrop-blur-sm">
              <div className="bg-white p-6 rounded-[32px] w-full max-w-sm shadow-2xl animate-in zoom-in-95 border-4 border-[#FDFBF7]">
                  <h3 className="font-black text-xl mb-6 text-[#5D5745] text-center">料理名を変更</h3>
                  <input 
                    autoFocus
                    value={editedMenuName}
                    onChange={(e) => setEditedMenuName(e.target.value)}
                    className="w-full p-4 bg-stone-50 rounded-2xl border-2 font-bold mb-6 outline-none focus:border-[#F88D8D] text-lg text-center"
                    placeholder="例: 牛丼"
                  />
                  <div className="flex gap-3">
                      <Button onClick={() => setIsEditingName(false)} variant="cancel" className="flex-1 py-4 font-bold rounded-2xl transition-colors">キャンセル</Button>
                      <button onClick={() => setIsEditingName(false)} className="flex-1 py-4 bg-[#F88D8D] text-white rounded-2xl font-black shadow-lg active:scale-95 transition-transform">決定</button>
                  </div>
              </div>
          </div>
      )}

      <main className="mt-8 animate-in slide-in-from-bottom duration-300 relative z-10">
        {step === 'intro' && (
          <div className="px-6 flex flex-col items-center space-y-8 pt-4">
               {/* Intro UI */}
               <div className="flex items-center justify-center relative w-full mb-4">
                   <div className="relative">
                       {onOpenGuide && (
                           <div className="absolute -left-32 top-1/2 -translate-y-1/2 w-28">
                               <Button 
                                   variant="guide" 
                                   onClick={onOpenGuide}
                                   className="w-full px-2 py-2 text-[10px] min-h-[48px] h-auto flex flex-col items-center gap-0.5 shadow-sm active:scale-95 transition-transform"
                               >
                                   <BookOpen size={18} strokeWidth={2.5} />
                                   <span className="whitespace-nowrap font-black">栄養ガイド</span>
                               </Button>
                           </div>
                       )}

                       <div className="w-24 h-24 rounded-full flex items-center justify-center bg-primary shadow-[0_20px_45px_-12px_rgba(248,141,141,0.6)] animate-sway relative group will-change-transform z-10">
                          <Utensils size={44} className="text-white" strokeWidth={3} />
                          <div className="absolute -top-1 -right-1 w-8 h-8 rounded-full bg-white flex items-center justify-center shadow-lg border-2 border-primary/20">
                             <Sparkles size={16} className="text-primary animate-pulse" />
                          </div>
                       </div>
                   </div>
               </div>

               <div className="text-center space-y-2">
                  <h2 className="text-2xl font-black">ごはんを記録</h2>
                  <p className="text-xs font-bold opacity-50">写真を撮るだけでAIがカロリー推定</p>
                  <p className="text-[10px] font-bold text-stone-400 mt-1">※写っている料理は全て合算されます（1人前で撮影）</p>
               </div>

               <div className="w-full space-y-4 pt-4">
                 <div className="relative group">
                   <Button onClick={handleStartCapture} className="w-full min-h-[80px] h-auto py-2 text-xl font-black shadow-xl overflow-hidden relative">
                      <div className="absolute top-0 left-0 w-full h-full bg-black/5 -skew-x-12 translate-x-4 pointer-events-none"></div>
                      <Camera size={26} className="mr-3 relative z-10 shrink-0" /> <span className="relative z-10">撮影をはじめる</span>
                   </Button>
                 </div>

                 {/* アルバムと手入力を横並びにする */}
                 <div className="grid grid-cols-2 gap-3">
                    <div className="relative group">
                        <FileInput 
                          label="アルバム" 
                          onFileSelect={async (b64) => {
                            try {
                              const compressed = await compressImage(b64);
                              handleImageProcess(compressed);
                            } catch(e) {
                              alert("画像の読み込みに失敗しました");
                            }
                          }}
                          className="w-full h-full" 
                        />
                    </div>
                    <div className="relative group">
                        <Button variant="album" onClick={handleManualInput} className="w-full h-full min-h-[64px] py-3">
                            <PenTool size={20} className="mr-2 shrink-0" style={{ color: 'white' }} />
                            手入力
                        </Button>
                    </div>
                 </div>
               </div>
          </div>
        )}

        {step === 'ad_wait' && (
          <div className="px-6 py-10 animate-in zoom-in-95">
             <div className="w-full p-8 rounded-[40px] bg-white border-4 shadow-xl relative overflow-hidden" style={{ borderColor: THEME.colors.border }}>
                <div className="absolute top-0 left-0 w-full h-2" style={{ backgroundColor: THEME.colors.primary }}></div>
                <button onClick={() => setStep('intro')} className="absolute top-4 right-4 p-2 text-stone-300"><X size={20}/></button>
                <div className="flex flex-col items-center space-y-6 text-center">
                    <div className="w-20 h-20 rounded-3xl flex items-center justify-center shadow-lg transform rotate-3" style={{ backgroundColor: THEME.colors.primaryLight }}>
                        <Gift size={40} className="animate-bounce" style={{ color: THEME.colors.primary }} />
                    </div>
                    <div className="space-y-4">
                        <h3 className="text-xl font-black">記録回数がゼロです</h3>
                        <div className="space-y-1">
                            <p className="text-xs font-bold text-stone-600">2時間待つと1回分回復（最大2回まで）</p>
                            <p className="text-xs font-bold text-stone-600">広告を見ると4回分まとめて回復（最大4回）</p>
                        </div>
                    </div>
                    <Button onClick={handleRestore} variant="primary" className="w-full min-h-[56px] h-auto py-3 shadow-lg font-black rounded-2xl">
                        <PlayCircle size={20} className="mr-2 shrink-0" /> 広告を見て回復
                    </Button>
                </div>
            </div>
          </div>
        )}

        {step === 'analyze' && (
          <div className="px-6 flex flex-col items-center justify-center space-y-10 py-32">
             <Loader2 className="animate-spin" style={{ color: THEME.colors.primary }} size={80} strokeWidth={3} />
             <p className="font-black text-xl animate-bounce">AIが分析中...</p>
          </div>
        )}

        {step === 'result' && analysis && (
          // バナー広告が下部に固定されるため、コンテンツが隠れないようにpadding-bottomを十分確保 (40=160px)
          <div className="space-y-6 animate-in zoom-in-95 pb-40">
            <div className="px-6 space-y-6">

              <div 
                 className="relative w-full aspect-[3/4] shadow-2xl rounded-[32px] overflow-hidden border-2 border-[#E5DDD0] bg-[#FFFDF5]"
              >
                 {previewBlob ? (
                    <img src={URL.createObjectURL(previewBlob)} className="w-full h-full object-contain" />
                 ) : image ? (
                    <div className="w-full h-full flex flex-col items-center justify-center bg-stone-100">
                        <Loader2 className="animate-spin mb-2" style={{ color: THEME.colors.primary }} />
                        <span className="text-xs font-bold text-stone-400">カード生成中...</span>
                    </div>
                 ) : (
                    <div className="w-full h-full flex flex-col items-center justify-center bg-stone-50 border-2 border-dashed" style={{ borderColor: THEME.colors.albumShadow, color: THEME.colors.textLight }}>
                        <HardDrive size={32} className="mb-2 opacity-30"/>
                        <span className="text-xs font-bold">画像なし（手入力）</span>
                    </div>
                 )}
              </div>

              <div className="space-y-4">
                  <div className="flex items-center gap-2">
                      <Button 
                        variant="cancel"
                        onClick={handleRetake}
                        className="min-h-[48px] h-auto py-2 min-w-[56px] w-auto px-2 flex flex-col items-center justify-center rounded-2xl shadow-sm active:scale-95 transition-all shrink-0"
                      >
                          <RotateCcw size={18} className="mb-0.5" />
                          <span className="text-[8px] font-black whitespace-nowrap">戻る</span>
                      </Button>

                      <button 
                        onClick={() => setIsEditingName(true)}
                        className="flex-1 min-h-[48px] h-auto py-2 bg-white border-2 rounded-2xl shadow-sm flex items-center justify-center gap-2 active:scale-95 transition-all"
                        style={{ borderColor: THEME.colors.border }}
                      >
                          <Edit2 size={16} className="text-stone-500 shrink-0" />
                          <span className="text-[10px] font-black text-stone-600 whitespace-normal">名称変更</span>
                      </button>

                      <button 
                        onClick={() => openKeypad(editedCalories.toString(), 'kcal', (val) => setEditedCalories(Number(val)))}
                        className="flex-1 min-h-[48px] h-auto py-2 bg-white border-2 rounded-2xl shadow-sm flex items-center justify-center gap-2 active:scale-95 transition-all"
                        style={{ borderColor: THEME.colors.border }}
                      >
                          <PenTool size={16} className="text-stone-500 shrink-0" />
                          <span className="text-[10px] font-black text-stone-600 whitespace-normal">カロリー変更</span>
                      </button>
                  </div>

                  <div className="bg-white p-1.5 rounded-[24px] border-2 flex justify-between gap-1 shadow-sm" style={{ borderColor: THEME.colors.border }}>
                    {(Object.keys(MEAL_TYPE_LABELS) as MealType[]).map((type) => {
                      const info = MEAL_TYPE_LABELS[type];
                      const isActive = selectedMealType === type;
                      return (
                        <button 
                            key={type} 
                            onClick={() => !hasSaved && setSelectedMealType(type)} 
                            className={`flex-1 flex flex-col items-center justify-center py-3 rounded-[20px] transition-all duration-300 ${isActive ? info.activeColor + ' shadow-md transform scale-[1.02]' : 'text-stone-300 hover:bg-stone-50 hover:text-stone-400'}`}
                        >
                          <info.icon size={18} strokeWidth={2.5} className="mb-0.5" />
                          <span className="text-[9px] font-black tracking-tight">{info.label}</span>
                        </button>
                      );
                    })}
                  </div>

                  <Card className="!p-5 bg-white border-2 border-dashed shadow-sm relative overflow-hidden" style={{ borderColor: THEME.colors.border }}>
                      <div className="absolute -right-2 -top-2 opacity-5 rotate-12">
                           <Sparkles size={60} className="text-stone-500" />
                      </div>
                      <p className="font-black text-xs mb-2 flex items-center gap-1.5" style={{ color: THEME.colors.primary }}>
                        <div className="w-5 h-5 rounded-full bg-red-50 flex items-center justify-center">
                            <Sparkles size={10} className="text-primary" />
                        </div>
                        アドバイス
                      </p>
                      <p className="text-xs font-bold leading-relaxed text-stone-600 relative z-10 break-words whitespace-normal">{analysis.comment}</p>
                  </Card>
              </div>

              <div className="space-y-4 pt-4">
                  <div className="grid grid-cols-2 gap-3">
                       <button 
                        onClick={handleSaveToApp} 
                        disabled={isSaving || hasSaved || (image && !previewBlob)}
                        className={`w-full min-h-[64px] h-auto py-2 text-sm font-black rounded-[24px] shadow-lg transition-all flex flex-col items-center justify-center border-2 ${hasSaved ? 'bg-stone-100 border-stone-200 text-stone-400' : 'bg-white border-primary text-primary active:scale-95'}`}
                      >
                         {isSaving ? <Loader2 className="animate-spin mb-1" /> : hasSaved ? <Check className="mb-1" /> : <Save className="mb-1" />}
                         {isSaving ? '保存中...' : hasSaved ? 'アプリに保存済' : 'アプリに保存'}
                      </button>

                      <button 
                        onClick={handleDirectShare}
                        disabled={isSharing || !previewBlob || !image}
                        className={`w-full min-h-[64px] h-auto py-2 text-sm font-black rounded-[24px] shadow-lg transition-all flex flex-col items-center justify-center border-2 ${(!previewBlob || !image) ? 'bg-stone-100 border-stone-200 text-stone-400' : 'bg-secondary border-secondary text-white active:scale-95'}`}
                      >
                         {isSharing ? <Loader2 className="animate-spin mb-1" /> : <Share2 className="mb-1" />}
                         {isSharing ? '作成中...' : 'シェアする'}
                      </button>
                  </div>

                  <div className="text-center">
                      <p className="text-[9px] font-bold text-stone-400">
                          {image ? "※「アプリに保存」を押すと、スマホのギャラリーにも画像が保存されます。" : "※手入力モードのため、写真は保存されません。"}
                      </p>
                  </div>

                  {hasSaved && (
                    <Button 
                      variant="cancel"
                      onClick={onClose} 
                      className="w-full min-h-[56px] h-auto py-2 text-lg font-black rounded-[28px] shadow-sm transition-all flex items-center justify-center border-2 active:scale-95"
                    >
                       とじる
                    </Button>
                  )}
              </div>
            </div>
          </div>
        )}
      </main>
    </div>
  );
};

export default MealView;

import { CameraSource } from '@capacitor/camera';
import { Loader2, Utensils, X, Camera, CalendarPlus, Share2, Sparkles, Check, Gift, PlayCircle, BookOpen, Menu, Drumstick, Droplet, Wheat, Download, Edit2, Smile, User, PenTool, Save, RotateCcw, HardDrive } from 'lucide-react';
import React, { useEffect, useState, useCallback, useRef } from 'react';
import { PieChart, Pie, Cell, ResponsiveContainer } from 'recharts';
import { hideBanner, showBannerForCamera, showBanner, hideMrec, showMrec } from '../../services/admobService';
import { takePhoto, compressImage } from '../../services/cameraService';
import { analyzeMeal } from '../../services/gemini/meal';
import { THEME } from '../../theme';
import { MealAnalysis, MealType, UserProfile } from '../../types';
import { getTodayString, addToCalendar, generateShareImageBlob, MEAL_TYPE_LABELS, PFC_COLORS, resolveMealImageSrc } from '../../utils';
import { Button, FileInput, Card } from '../UIComponents';
import { Share } from '@capacitor/share';
import { Filesystem, Directory } from '@capacitor/filesystem';
import { Capacitor } from '@capacitor/core';
import { renderMealResultToBlob } from '../../services/renderers/mealResultRenderer';
import { GallerySaver } from '../../src/plugins/GallerySaver';

interface MealViewProps {
  user: UserProfile;
  tokens: number;
  useToken: () => boolean;
  restoreTokens: () => Promise<boolean>;
  onSave: (analysis: MealAnalysis, photo: string, date: string) => void;
  onClose: () => void;
  onShareClick: (preGeneratedBlob?: Blob) => void;
  openKeypad: (initialValue: string, unit: string, onConfirm: (val: string) => void) => void;
  openCalendar: (initialDate: string, onConfirm: (date: string) => void) => void;
  onOpenGuide?: () => void;
  onMenuOpen: () => void;
  isMenuOpen: boolean; // Added for ad control
}

const MealView: React.FC<MealViewProps> = ({ user, tokens, useToken, restoreTokens, onSave, onClose, onShareClick, onOpenGuide, onMenuOpen, openKeypad, isMenuOpen }) => {
  const [step, setStep] = useState<'intro' | 'ad_wait' | 'analyze' | 'result'>('intro');
  const [image, setImage] = useState<string | null>(null);
  const [analysis, setAnalysis] = useState<MealAnalysis | null>(null);

  // 編集用のState
  const [editedMenuName, setEditedMenuName] = useState('');
  const [isEditingName, setIsEditingName] = useState(false); 
  const [editedCalories, setEditedCalories] = useState(0);

  const [selectedMealType, setSelectedMealType] = useState<MealType>('lunch');
  const [isSaving, setIsSaving] = useState(false);
  const [hasSaved, setHasSaved] = useState(false);
  const [isSharing, setIsSharing] = useState(false);
  const [previewBlob, setPreviewBlob] = useState<Blob | null>(null);

  const recordDate = getTodayString();

  // 画面遷移・ステップに応じた広告制御
  useEffect(() => {
    // メニューが開いているときはApp.tsxが全広告を消すので、ここでは何もしない
    // メニューが閉じている時だけ制御する
    if (isMenuOpen) return;

    if (step === 'analyze' || step === 'ad_wait') {
        // 解析中・待機中は全広告禁止
        hideBanner();
        hideMrec();
    } else if (step === 'result') {
        // 結果画面はMRECだとコンテンツを隠すため、通常バナーに戻す
        hideMrec();
        showBanner();
    } else {
        // intro (通常画面) は MRECを表示
        hideBanner();
        showMrec();
    }

    return () => { 
        // 制御はApp.tsx側に戻る
    };
  }, [step, isMenuOpen]);

  // トークン切れでad_waitになった場合の特別処理 (上記useEffectでカバー済み)

  const handleImageProcess = async (base64: string) => {
    if (!useToken()) { setStep('ad_wait'); return; }
    // 解析開始直前に広告を消す念押し
    await hideBanner();
    await hideMrec();

    setImage(base64);
    setStep('analyze');
    try {
      const result = await analyzeMeal(base64);
      setAnalysis(result);
      setEditedMenuName(result.menuName);
      setEditedCalories(result.numericCalories);
      setStep('result');
    } catch (e: any) {
      alert("解析に失敗しました。電波環境を確認してください。");
      setStep('intro');
    }
  };

  const handleManualInput = async () => {
    // 広告制御
    await hideBanner();
    await hideMrec();

    setImage(null);
    const initialAnalysis: MealAnalysis = {
        menuName: '手入力メモ',
        numericCalories: 0,
        pfcRatio: { p: 0, f: 0, c: 0 },
        comment: '自分で記録しました',
        mealType: 'lunch'
    };
    setAnalysis(initialAnalysis);
    setEditedMenuName(initialAnalysis.menuName);
    setEditedCalories(initialAnalysis.numericCalories);
    setStep('result');
  };

  const getCurrentAnalysis = useCallback((): MealAnalysis => {
      if (!analysis) throw new Error("No analysis");
      return {
          ...analysis,
          menuName: editedMenuName,
          numericCalories: editedCalories,
          mealType: selectedMealType
      };
  }, [analysis, editedMenuName, editedCalories, selectedMealType]);

  useEffect(() => {
      if (step === 'result' && image && analysis) {
          const updatePreview = async () => {
              const current = getCurrentAnalysis();
              const blob = await renderMealResultToBlob(
                  image, 
                  current, 
                  recordDate, 
                  { showMascot: user.showMascotOnShare ?? true, avatarBase64: user.avatarImage }
              );
              setPreviewBlob(blob);
          };
          updatePreview();
      } else if (step === 'result' && !image) {
          setPreviewBlob(null);
      }
  }, [step, image, analysis, editedMenuName, editedCalories, selectedMealType, user.showMascotOnShare, user.avatarImage, getCurrentAnalysis]);


  const handleStartCapture = async () => {
    if (tokens <= 0) { setStep('ad_wait'); return; }

    // カメラ起動前にも広告を消す
    await hideBanner();
    await hideMrec();

    try {
      const result = await takePhoto(CameraSource.Camera, 'rear');
      handleImageProcess(result.base64);
    } catch (e: any) { 
      if (e.message !== "CANCELLED") alert(e.message); 
      // キャンセル時はIntroに戻るので、広告復帰はStep変更useEffectで行われる
    }
  };

  const handleRestore = async () => {
    // リワード広告表示時はAdMobプラグインが全画面を覆うが、念のため既存バナーは非表示に
    await hideBanner();
    await hideMrec();
    const success = await restoreTokens();
    if (success) {
      setStep('intro');
    }
  };

  const handleRetake = () => {
    // ユーザーからのフィードバック対応: 確認ダイアログを削除し、即座に戻る
    setImage(null);
    setAnalysis(null);
    setStep('intro');
  };

  const handleSaveToApp = async () => {
    if (!analysis || isSaving || hasSaved) return;
    // 画像がある場合はプレビュー生成を待つ
    if (image && !previewBlob) return;

    setIsSaving(true);

    try {
        let fileUri = "";

        // 画像がある場合のみ、画像生成・保存処理を行う
        if (image && previewBlob) {
            const blob = previewBlob;
            const reader = new FileReader();
            const base64Promise = new Promise<string>((resolve) => {
                reader.onloadend = () => {
                    const base64String = reader.result as string;
                    resolve(base64String.split(',')[1]);
                };
                reader.readAsDataURL(blob);
            });
            const base64data = await base64Promise;
            const fileName = `tabetotto_${recordDate.replace(/-/g, '')}_${Date.now()}.jpg`;

            let gallerySaved = false;
            if (Capacitor.getPlatform() === 'android') {
                try {
                    const res = await GallerySaver.saveImage({
                        base64: base64data,
                        fileName: fileName,
                        album: 'たべとっと。'
                    });
                    if (res.saved) {
                        gallerySaved = true;
                    }
                } catch (e) {
                    console.warn("Gallery save failed:", e);
                }
            }

            if (!gallerySaved) {
                if (Capacitor.isNativePlatform()) {
                     try {
                        await Filesystem.writeFile({
                            path: fileName,
                            data: base64data,
                            directory: Directory.Documents,
                        });
                     } catch (fsError) {
                        console.error("Device documents save failed", fsError);
                     }
                } else {
                     const url = URL.createObjectURL(blob);
                     const a = document.createElement('a');
                     a.href = url;
                     a.download = fileName;
                     a.click();
                     URL.revokeObjectURL(url);
                }
            }

            const savedFile = await Filesystem.writeFile({
                path: fileName,
                data: base64data,
                directory: Directory.Data,
            });
            fileUri = savedFile.uri;
        }

        // 手入力の場合、fileUriは空文字で保存
        onSave(getCurrentAnalysis(), fileUri, recordDate);
        setHasSaved(true);

    } catch (e) {
        console.error("Save error:", e);
        alert("保存中にエラーが発生しました");
        setIsSaving(false);
    } finally {
        setIsSaving(false);
    }
  };

  const handleDirectShare = async () => {
    if (!analysis || !image || isSharing || !previewBlob) return;
    setIsSharing(true);

    try {
        const blob = previewBlob;

        if (Capacitor.isNativePlatform()) {
            const reader = new FileReader();
            const base64Promise = new Promise<string>((resolve) => {
                reader.onloadend = () => {
                    const base64String = reader.result as string;
                    resolve(base64String.split(',')[1]);
                };
                reader.readAsDataURL(blob);
            });
            const base64data = await base64Promise;
            const fileName = `tabetotto_share_${recordDate.replace(/-/g, '')}_${Date.now()}.jpg`;

            await Filesystem.writeFile({
                path: fileName,
                data: base64data,
                directory: Directory.Cache,
            });

            const { uri } = await Filesystem.getUri({
                directory: Directory.Cache,
                path: fileName
            });

            await Share.share({
                title: 'たべとっと。で食事を記録しました',
                text: '今日の食事記録です✨ #たべとっと',
                url: uri,
            });
        } else if (navigator.share && navigator.canShare && navigator.canShare({ files: [new File([blob], "share.jpg", { type: "image/jpeg" })] })) {
            const file = new File([blob], "diet_record.jpg", { type: "image/jpeg" });
            await navigator.share({
                files: [file],
                title: 'たべとっと。で食事を記録しました',
                text: '今日の食事記録です✨ #たべとっと'
            });
        } else {
            const url = URL.createObjectURL(blob);
            const a = document.createElement('a');
            a.href = url;
            a.download = `tabetotto_share_${recordDate}.jpg`;
            a.click();
            URL.revokeObjectURL(url);
            alert("画像を保存しました");
        }
    } catch (e) {
        alert("シェアに失敗しました");
    } finally {
        setIsSharing(false);
    }
  };

  return (
    <div className="flex flex-col min-h-screen pb-44 w-full no-scrollbar overflow-x-hidden relative">
      {/* Background Decor */}
      <div className="organic-blob w-80 h-80 top-20 -right-40 animate-float-slow will-change-transform" style={{ backgroundColor: THEME.colors.primaryLight }}></div>
      <div className="organic-blob w-64 h-64 bottom-60 -left-32 animate-float-slow will-change-transform" style={{ backgroundColor: THEME.colors.secondaryLight, animationDelay: '2s' }}></div>

      <header className="sticky top-0 z-[60] pt-safe backdrop-blur-md border-b w-full shadow-sm" style={{ backgroundColor: `${THEME.colors.bg}E6`, borderColor: THEME.colors.border }}>
         <div className="px-6 py-3 flex justify-between items-center w-full">
            <div className="flex items-center gap-2">
                <div className="w-11 h-11 rounded-full flex items-center justify-center shadow-[0_15px_35px_-8px_rgba(248,141,141,0.5)] animate-sway transition-transform will-change-transform" style={{ backgroundColor: THEME.colors.primary }}>
                    <Utensils size={22} className="text-white" strokeWidth={3} />
                </div>
                <div className="flex flex-col">
                  <h1 className="text-xl font-black tracking-widest leading-none" style={{ color: THEME.colors.primary }}>たべとっと。</h1>
                  <span className="text-[8px] font-black tracking-tighter opacity-70" style={{ color: THEME.colors.primary }}>Meal Record</span>
                </div>
            </div>
            <div className="flex items-center gap-3">
                <button onClick={onMenuOpen} className="pl-4 pr-3 py-2 rounded-full shadow-md active:scale-95 transition-all flex items-center gap-2 border-2 border-white ring-2" style={{ backgroundColor: THEME.colors.primary, color: 'white', borderColor: 'white', ['--tw-ring-color' as any]: `${THEME.colors.primary}33` }}>
                    <span className="text-sm font-black tracking-wide">Menu</span>
                    <Menu size={20} strokeWidth={2.5} />
                </button>
            </div>
         </div>
      </header>

      {isEditingName && (
          <div className="fixed inset-0 z-[999] flex items-center justify-center bg-black/60 px-6 animate-in fade-in backdrop-blur-sm">
              <div className="bg-white p-6 rounded-[32px] w-full max-w-sm shadow-2xl animate-in zoom-in-95 border-4 border-[#FDFBF7]">
                  <h3 className="font-black text-xl mb-6 text-[#5D5745] text-center">料理名を変更</h3>
                  <input 
                    autoFocus
                    value={editedMenuName}
                    onChange={(e) => setEditedMenuName(e.target.value)}
                    className="w-full p-4 bg-stone-50 rounded-2xl border-2 font-bold mb-6 outline-none focus:border-[#F88D8D] text-lg text-center"
                    placeholder="例: 牛丼"
                  />
                  <div className="flex gap-3">
                      <Button onClick={() => setIsEditingName(false)} variant="cancel" className="flex-1 py-4 font-bold rounded-2xl transition-colors">キャンセル</Button>
                      <button onClick={() => setIsEditingName(false)} className="flex-1 py-4 bg-[#F88D8D] text-white rounded-2xl font-black shadow-lg active:scale-95 transition-transform">決定</button>
                  </div>
              </div>
          </div>
      )}

      <main className="mt-8 animate-in slide-in-from-bottom duration-300 relative z-10">
        {step === 'intro' && (
          <div className="px-6 flex flex-col items-center space-y-8 pt-4">
               {/* Intro UI */}
               <div className="flex items-center justify-center relative w-full mb-4">
                   <div className="relative">
                       {onOpenGuide && (
                           <div className="absolute -left-32 top-1/2 -translate-y-1/2 w-28">
                               <Button 
                                   variant="guide" 
                                   onClick={onOpenGuide}
                                   className="w-full px-2 py-2 text-[10px] min-h-[48px] h-auto flex flex-col items-center gap-0.5 shadow-sm active:scale-95 transition-transform"
                               >
                                   <BookOpen size={18} strokeWidth={2.5} />
                                   <span className="whitespace-nowrap font-black">栄養ガイド</span>
                               </Button>
                           </div>
                       )}

                       <div className="w-24 h-24 rounded-full flex items-center justify-center bg-primary shadow-[0_20px_45px_-12px_rgba(248,141,141,0.6)] animate-sway relative group will-change-transform z-10">
                          <Utensils size={44} className="text-white" strokeWidth={3} />
                          <div className="absolute -top-1 -right-1 w-8 h-8 rounded-full bg-white flex items-center justify-center shadow-lg border-2 border-primary/20">
                             <Sparkles size={16} className="text-primary animate-pulse" />
                          </div>
                       </div>
                   </div>
               </div>

               <div className="text-center space-y-2">
                  <h2 className="text-2xl font-black">ごはんを記録</h2>
                  <p className="text-xs font-bold opacity-50">写真を撮るだけでAIがカロリー推定</p>
                  <p className="text-[10px] font-bold text-stone-400 mt-1">※写っている料理は全て合算されます（1人前で撮影）</p>
               </div>

               <div className="w-full space-y-4 pt-4">
                 <div className="relative group">
                   <Button onClick={handleStartCapture} className="w-full min-h-[80px] h-auto py-2 text-xl font-black shadow-xl overflow-hidden relative">
                      <div className="absolute top-0 left-0 w-full h-full bg-black/5 -skew-x-12 translate-x-4 pointer-events-none"></div>
                      <Camera size={26} className="mr-3 relative z-10 shrink-0" /> <span className="relative z-10">撮影をはじめる</span>
                   </Button>
                 </div>

                 {/* アルバムと手入力を横並びにする */}
                 <div className="grid grid-cols-2 gap-3">
                    <div className="relative group">
                        <Button variant="outline" onClick={handleManualInput} className="w-full h-full min-h-[64px] py-3 bg-white border-2 border-stone-200">
                            <PenTool size={20} className="mr-2 shrink-0" style={{ color: THEME.colors.textLight }} />
                            <span style={{ color: THEME.colors.textLight }}>手入力</span>
                        </Button>
                    </div>
                    <div className="relative group">
                        <FileInput 
                          label="アルバム" 
                          onFileSelect={async (b64) => {
                            try {
                              const compressed = await compressImage(b64);
                              handleImageProcess(compressed);
                            } catch(e) {
                              alert("画像の読み込みに失敗しました");
                            }
                          }}
                          className="w-full h-full" 
                        />
                    </div>
                 </div>
               </div>
          </div>
        )}

        {step === 'ad_wait' && (
          <div className="px-6 py-10 animate-in zoom-in-95">
             <div className="w-full p-8 rounded-[40px] bg-white border-4 shadow-xl relative overflow-hidden" style={{ borderColor: THEME.colors.border }}>
                <div className="absolute top-0 left-0 w-full h-2" style={{ backgroundColor: THEME.colors.primary }}></div>
                <button onClick={() => setStep('intro')} className="absolute top-4 right-4 p-2 text-stone-300"><X size={20}/></button>
                <div className="flex flex-col items-center space-y-6 text-center">
                    <div className="w-20 h-20 rounded-3xl flex items-center justify-center shadow-lg transform rotate-3" style={{ backgroundColor: THEME.colors.primaryLight }}>
                        <Gift size={40} className="animate-bounce" style={{ color: THEME.colors.primary }} />
                    </div>
                    <div className="space-y-4">
                        <h3 className="text-xl font-black">記録回数がゼロです</h3>
                        <div className="space-y-1">
                            <p className="text-xs font-bold text-stone-600">2時間待つと1回分回復（最大2回まで）</p>
                            <p className="text-xs font-bold text-stone-600">広告を見ると4回分まとめて回復（最大4回）</p>
                        </div>
                    </div>
                    <Button onClick={handleRestore} variant="primary" className="w-full min-h-[56px] h-auto py-3 shadow-lg font-black rounded-2xl">
                        <PlayCircle size={20} className="mr-2 shrink-0" /> 広告を見て回復
                    </Button>
                </div>
            </div>
          </div>
        )}

        {step === 'analyze' && (
          <div className="px-6 flex flex-col items-center justify-center space-y-10 py-32">
             <Loader2 className="animate-spin" style={{ color: THEME.colors.primary }} size={80} strokeWidth={3} />
             <p className="font-black text-xl animate-bounce">AIが分析中...</p>
          </div>
        )}

        {step === 'result' && analysis && (
          // バナー広告が下部に固定されるため、コンテンツが隠れないようにpadding-bottomを十分確保 (40=160px)
          <div className="space-y-6 animate-in zoom-in-95 pb-40">
            <div className="px-6 space-y-6">

              <div 
                 className="relative w-full aspect-[3/4] shadow-2xl rounded-[32px] overflow-hidden border-2 border-[#E5DDD0] bg-[#FFFDF5]"
              >
                 {previewBlob ? (
                    <img src={URL.createObjectURL(previewBlob)} className="w-full h-full object-contain" />
                 ) : image ? (
                    <div className="w-full h-full flex flex-col items-center justify-center bg-stone-100">
                        <Loader2 className="animate-spin mb-2" style={{ color: THEME.colors.primary }} />
                        <span className="text-xs font-bold text-stone-400">カード生成中...</span>
                    </div>
                 ) : (
                    <div className="w-full h-full flex flex-col items-center justify-center bg-stone-50 border-2 border-dashed" style={{ borderColor: THEME.colors.albumShadow, color: THEME.colors.textLight }}>
                        <HardDrive size={32} className="mb-2 opacity-30"/>
                        <span className="text-xs font-bold">画像なし（手入力）</span>
                    </div>
                 )}
              </div>

              <div className="space-y-4">
                  <div className="flex items-center gap-2">
                      <Button 
                        variant="cancel"
                        onClick={handleRetake}
                        className="min-h-[48px] h-auto py-2 min-w-[56px] w-auto px-2 flex flex-col items-center justify-center rounded-2xl shadow-sm active:scale-95 transition-all shrink-0"
                      >
                          <RotateCcw size={18} className="mb-0.5" />
                          <span className="text-[8px] font-black whitespace-nowrap">戻る</span>
                      </Button>

                      <button 
                        onClick={() => setIsEditingName(true)}
                        className="flex-1 min-h-[48px] h-auto py-2 bg-white border-2 rounded-2xl shadow-sm flex items-center justify-center gap-2 active:scale-95 transition-all"
                        style={{ borderColor: THEME.colors.border }}
                      >
                          <Edit2 size={16} className="text-stone-500 shrink-0" />
                          <span className="text-[10px] font-black text-stone-600 whitespace-normal">名称変更</span>
                      </button>

                      <button 
                        onClick={() => openKeypad(editedCalories.toString(), 'kcal', (val) => setEditedCalories(Number(val)))}
                        className="flex-1 min-h-[48px] h-auto py-2 bg-white border-2 rounded-2xl shadow-sm flex items-center justify-center gap-2 active:scale-95 transition-all"
                        style={{ borderColor: THEME.colors.border }}
                      >
                          <PenTool size={16} className="text-stone-500 shrink-0" />
                          <span className="text-[10px] font-black text-stone-600 whitespace-normal">カロリー変更</span>
                      </button>
                  </div>

                  <div className="bg-white p-1.5 rounded-[24px] border-2 flex justify-between gap-1 shadow-sm" style={{ borderColor: THEME.colors.border }}>
                    {(Object.keys(MEAL_TYPE_LABELS) as MealType[]).map((type) => {
                      const info = MEAL_TYPE_LABELS[type];
                      const isActive = selectedMealType === type;
                      return (
                        <button 
                            key={type} 
                            onClick={() => !hasSaved && setSelectedMealType(type)} 
                            className={`flex-1 flex flex-col items-center justify-center py-3 rounded-[20px] transition-all duration-300 ${isActive ? info.activeColor + ' shadow-md transform scale-[1.02]' : 'text-stone-300 hover:bg-stone-50 hover:text-stone-400'}`}
                        >
                          <info.icon size={18} strokeWidth={2.5} className="mb-0.5" />
                          <span className="text-[9px] font-black tracking-tight">{info.label}</span>
                        </button>
                      );
                    })}
                  </div>

                  <Card className="!p-5 bg-white border-2 border-dashed shadow-sm relative overflow-hidden" style={{ borderColor: THEME.colors.border }}>
                      <div className="absolute -right-2 -top-2 opacity-5 rotate-12">
                           <Sparkles size={60} className="text-stone-500" />
                      </div>
                      <p className="font-black text-xs mb-2 flex items-center gap-1.5" style={{ color: THEME.colors.primary }}>
                        <div className="w-5 h-5 rounded-full bg-red-50 flex items-center justify-center">
                            <Sparkles size={10} className="text-primary" />
                        </div>
                        アドバイス
                      </p>
                      <p className="text-xs font-bold leading-relaxed text-stone-600 relative z-10 break-words whitespace-normal">{analysis.comment}</p>
                  </Card>
              </div>

              <div className="space-y-4 pt-4">
                  <div className="grid grid-cols-2 gap-3">
                       <button 
                        onClick={handleSaveToApp} 
                        disabled={isSaving || hasSaved || (image && !previewBlob)}
                        className={`w-full min-h-[64px] h-auto py-2 text-sm font-black rounded-[24px] shadow-lg transition-all flex flex-col items-center justify-center border-2 ${hasSaved ? 'bg-stone-100 border-stone-200 text-stone-400' : 'bg-white border-primary text-primary active:scale-95'}`}
                      >
                         {isSaving ? <Loader2 className="animate-spin mb-1" /> : hasSaved ? <Check className="mb-1" /> : <Save className="mb-1" />}
                         {isSaving ? '保存中...' : hasSaved ? 'アプリに保存済' : 'アプリに保存'}
                      </button>

                      <button 
                        onClick={handleDirectShare}
                        disabled={isSharing || !previewBlob || !image}
                        className={`w-full min-h-[64px] h-auto py-2 text-sm font-black rounded-[24px] shadow-lg transition-all flex flex-col items-center justify-center border-2 ${(!previewBlob || !image) ? 'bg-stone-100 border-stone-200 text-stone-400' : 'bg-secondary border-secondary text-white active:scale-95'}`}
                      >
                         {isSharing ? <Loader2 className="animate-spin mb-1" /> : <Share2 className="mb-1" />}
                         {isSharing ? '作成中...' : 'シェアする'}
                      </button>
                  </div>

                  <div className="text-center">
                      <p className="text-[9px] font-bold text-stone-400">
                          {image ? "※「アプリに保存」を押すと、スマホのギャラリーにも画像が保存されます。" : "※手入力モードのため、写真は保存されません。"}
                      </p>
                  </div>

                  {hasSaved && (
                    <Button 
                      variant="cancel"
                      onClick={onClose} 
                      className="w-full min-h-[56px] h-auto py-2 text-lg font-black rounded-[28px] shadow-sm transition-all flex items-center justify-center border-2 active:scale-95"
                    >
                       とじる
                    </Button>
                  )}
              </div>
            </div>
          </div>
        )}
      </main>
    </div>
  );
};

export default MealView;

