export default MealView;

import { Camera, CameraResultType, CameraSource, CameraDirection } from '@capacitor/camera';
import { Capacitor } from '@capacitor/core';
import { Filesystem } from '@capacitor/filesystem';

export interface PhotoResult {
  base64: string;
  mimeType: string;
  format: string;
  source: 'camera' | 'file';
  width: number;
  height: number;
}

// 履歴の高速表示と保存容量の最小化、AI解析の高速化のためにサイズを制限
// 低スペック端末のメモリ不足対策として640に縮小 (1024 -> 640)
const MAX_LONG_SIDE = 640; 

/**
 * 画像を指定サイズ以下にリサイズしBase64で返却
 */
const processImage = (img: HTMLImageElement, source: 'camera' | 'file'): PhotoResult => {
  let width = img.width;
  let height = img.height;

  if (width > height) {
    if (width > MAX_LONG_SIDE) {
      height = Math.round((height * MAX_LONG_SIDE) / width);
      width = MAX_LONG_SIDE;
    }
  } else {
    if (height > MAX_LONG_SIDE) {
      width = Math.round((width * MAX_LONG_SIDE) / height);
      height = MAX_LONG_SIDE;
    }
  }

  const canvas = document.createElement('canvas');
  canvas.width = width;
  canvas.height = height;
  const ctx = canvas.getContext('2d');
  if (!ctx) throw new Error("Canvas context creation failed");

  ctx.drawImage(img, 0, 0, width, height);
  const mimeType = 'image/jpeg';
  // 圧縮率を0.3に設定。実機テストで十分な視認性と最小のデータ量を両立。
  const dataUrl = canvas.toDataURL(mimeType, 0.3);
  const base64 = dataUrl.split(',')[1];

  return {
    base64,
    mimeType,
    format: 'jpeg',
    source,
    width,
    height
  };
};

/**
 * Base64画像を圧縮して再取得するユーティリティ
 * FileInputからの画像など、未圧縮のデータを小さくするために使用
 */
export const compressImage = (base64: string): Promise<string> => {
  return new Promise((resolve, reject) => {
    const img = new Image();
    img.onload = () => {
      try {
        const res = processImage(img, 'file');
        resolve(res.base64);
      } catch (e) {
        reject(e);
      }
    };
    img.onerror = () => reject(new Error("Image processing failed"));
    img.src = base64.startsWith('data:') ? base64 : `data:image/jpeg;base64,${base64}`;
  });
};

/**
 * タイムアウト付きFetch
 */
const fetchWithTimeout = (url: string, ms: number): Promise<Blob> => {
    return new Promise((resolve, reject) => {
        const controller = new AbortController();
        const timeoutId = setTimeout(() => {
            controller.abort();
            reject(new Error("Fetch timeout"));
        }, ms);

        fetch(url, { signal: controller.signal })
            .then(res => {
                if (!res.ok) throw new Error(`Fetch error: ${res.status}`);
                return res.blob();
            })
            .then(blob => {
                clearTimeout(timeoutId);
                resolve(blob);
            })
            .catch(err => {
                clearTimeout(timeoutId);
                reject(err);
            });
    });
};

/**
 * Blobから画像を処理
 */
const processBlobToResult = (blob: Blob, source: 'camera' | 'file'): Promise<PhotoResult> => {
    return new Promise((resolve, reject) => {
        const img = new Image();
        const objectUrl = URL.createObjectURL(blob);
        img.onload = () => {
            URL.revokeObjectURL(objectUrl);
            try {
                const res = processImage(img, source);
                resolve(res);
            } catch (err) {
                reject(err);
            }
        };
        img.onerror = (err) => {
            URL.revokeObjectURL(objectUrl);
            reject(new Error("Failed to load image from blob"));
        };
        img.src = objectUrl;
    });
};

/**
 * 写真を撮影または選択
 * 堅牢性向上のため、Uriモードで失敗・タイムアウトした場合はBase64モードにフォールバックする
 */
export const takePhoto = async (source: CameraSource = CameraSource.Prompt, direction: 'front' | 'rear' = 'rear'): Promise<PhotoResult> => {
  // 1. まずはUriモードで試みる（高画質・低メモリ）
  try {
    const image = await Camera.getPhoto({
      quality: 50,
      allowEditing: false,
      resultType: CameraResultType.Uri,
      source: source,
      direction: direction === 'front' ? CameraDirection.Front : CameraDirection.Rear,
      correctOrientation: true,
      width: 640, // 低メモリ端末向けに縮小 (1024 -> 640)
    });

    const imagePath = image.webPath || image.path;
    if (imagePath) {
      let blob: Blob;

      // Androidでの安定化対策: content:// URI等のfetch失敗を防ぐためFilesystemを使用
      if (Capacitor.getPlatform() === 'android' && image.path) {
          try {
            const file = await Filesystem.readFile({
                path: image.path,
            });
            // dataはBase64文字列として返る
            const base64Data = file.data as string;
            const byteCharacters = atob(base64Data);
            const byteNumbers = new Array(byteCharacters.length);
            for (let i = 0; i < byteCharacters.length; i++) {
                byteNumbers[i] = byteCharacters.charCodeAt(i);
            }
            const byteArray = new Uint8Array(byteNumbers);
            blob = new Blob([byteArray], { type: "image/jpeg" });
          } catch (e) {
            console.warn("Filesystem read failed, fallback to fetch", e);
            // 失敗したら従来のfetchを試みる (タイムアウト延長 12000ms)
            blob = await fetchWithTimeout(imagePath, 12000);
          }
      } else {
          // iOS / Web / Android Fallback
          // タイムアウト付きでBlob取得を試みる (6000ms -> 12000ms)
          // 低スペ端末のWebViewでfetchが固まる現象への対策
          blob = await fetchWithTimeout(imagePath, 12000);
      }

      return await processBlobToResult(blob, 'camera');
    }
  } catch (e: any) {
    // ユーザーキャンセル時は即終了（フォールバックしない）
    if (e.message?.includes("User cancelled") || e.message === "CANCELLED") {
       throw new Error("CANCELLED");
    }
    // それ以外のエラー（タイムアウト含む）はログを出してBase64フォールバックへ
    console.warn("Uri mode failed or timed out, falling back to Base64:", e);
  }

  // 2. Base64モードでのフォールバック (低スペ端末・WebView不調時用)
  try {
    const image = await Camera.getPhoto({
      quality: 50, // 画質は維持
      allowEditing: false,
      resultType: CameraResultType.Base64,
      source: source,
      direction: direction === 'front' ? CameraDirection.Front : CameraDirection.Rear,
      correctOrientation: true,
      width: 640, // Base64転送負荷軽減のためサイズダウン (1024 -> 640)
    });

    if (image.base64String) {
      return new Promise((resolve, reject) => {
        const img = new Image();
        img.onload = () => {
            try {
                resolve(processImage(img, 'camera'));
            } catch (pErr) {
                reject(pErr);
            }
        };
        img.onerror = () => reject(new Error("Image processing failed (Base64)."));
        img.src = `data:image/${image.format};base64,${image.base64String}`;
      });
    }
  } catch (e: any) {
    if (e.message?.includes("User cancelled") || e.message === "CANCELLED") {
        throw new Error("CANCELLED");
    }
    throw new Error(`Camera Error (Backup): ${e.message}`);
  }

  throw new Error("No image data returned.");
};

import { MealAnalysis } from '../../types';
import { PFC_COLORS } from '../../utils';

export const CANVAS_WIDTH = 1080;
export const CANVAS_HEIGHT = 1440;
const SAFE_MARGIN = 72;

const loadImage = (src: string): Promise<HTMLImageElement> => {
    return new Promise((resolve, reject) => {
        const img = new Image();
        img.crossOrigin = 'anonymous';
        img.onload = () => resolve(img);
        // エラー時はrejectして呼び出し元でキャッチできるように変更
        img.onerror = () => reject(new Error("IMAGE_LOAD_FAILED"));
        img.src = src;
    });
};

/**
 * イラスト風の背景を描画する関数
 * (水玉 + ステッチ枠のみ。絵文字・イラストなし)
 */
const drawIllustrationBackground = (ctx: CanvasRenderingContext2D, width: number, height: number) => {
    // 1. ベースカラー (アプリ共通のベージュ #FDFBF7)
    ctx.fillStyle = '#FDFBF7'; 
    ctx.fillRect(0, 0, width, height);

    // 2. パステル水玉パターン
    const dotColors = ['#FFE0B2', '#D1C4E9', '#B2DFDB', '#FFCDD2', '#F0F4C3']; 
    const spacing = 180;

    ctx.save();
    for (let y = 0; y < height + spacing; y += spacing) {
        const xOffset = (y / spacing) % 2 === 0 ? 0 : spacing / 2;
        for (let x = -spacing; x < width + spacing; x += spacing) {
            const cx = x + xOffset;
            const cy = y;
            const colorIndex = (Math.floor(cx) + Math.floor(cy)) % dotColors.length;

            ctx.beginPath();
            ctx.arc(cx, cy, 22, 0, Math.PI * 2);
            ctx.fillStyle = dotColors[colorIndex];
            ctx.globalAlpha = 0.5;
            ctx.fill();
        }
    }
    ctx.restore();

    // 3. 全体を囲むステッチ（点線枠）
    const borderPadding = 40;
    ctx.save();
    ctx.strokeStyle = '#A0937D'; // 茶色っぽいグレー
    ctx.lineWidth = 5;
    ctx.setLineDash([20, 20]); // 点線
    ctx.beginPath();
    ctx.roundRect(
        borderPadding, 
        borderPadding, 
        width - (borderPadding * 2), 
        height - (borderPadding * 2), 
        60
    );

    // 内側を同じベージュで塗りつぶし (#FDFBF7)
    // 背景と一体化させつつ、枠線だけでエリアを示す
    ctx.fillStyle = '#FDFBF7';
    ctx.fill();
    ctx.stroke();
    ctx.restore();

    // 絵文字・野菜イラストの描画処理は完全に削除
};

export const renderMealResultToCanvas = async (
    canvas: HTMLCanvasElement,
    photoBase64: string,
    meal: MealAnalysis,
    date: string,
    options: { showMascot?: boolean, avatarBase64?: string } = {}
) => {
    // 1. フォント読み込み待機
    try { await document.fonts.ready; } catch(e) {}

    const ctx = canvas.getContext('2d');
    if (!ctx) return;

    // 2. 画像読み込み (メイン写真 & アバター)
    const photoImgPromise = loadImage(
        photoBase64.startsWith('data:') || photoBase64.startsWith('file:') || photoBase64.startsWith('http') 
        ? photoBase64 
        : `data:image/jpeg;base64,${photoBase64}`
    );

    let avatarImgPromise: Promise<HTMLImageElement | null> = Promise.resolve(null);
    if (options.avatarBase64 && options.showMascot !== false) {
        const src = options.avatarBase64.startsWith('data:') 
            ? options.avatarBase64 
            : `data:image/png;base64,${options.avatarBase64}`;
        avatarImgPromise = loadImage(src).catch(() => null);
    }

    const [photoImg, avatarImg] = await Promise.all([photoImgPromise, avatarImgPromise]);

    // 3. キャンバス初期化
    ctx.setTransform(1, 0, 0, 1, 0, 0);
    ctx.clearRect(0, 0, CANVAS_WIDTH, CANVAS_HEIGHT);

    // 4. イラスト風背景描画 (絵文字なし、背景ベージュ統一)
    drawIllustrationBackground(ctx, CANVAS_WIDTH, CANVAS_HEIGHT);

    // 5. ヘッダー (ロゴ + 日付)
    const contentStartY = 80;
    const headerY = contentStartY + 60;

    // アイコン (アバターがあればアバター、なければデフォルト)
    const iconX = SAFE_MARGIN + 60;

    if (avatarImg) {
        ctx.save();
        ctx.beginPath();
        ctx.arc(iconX, headerY, 40, 0, Math.PI * 2);
        ctx.clip();
        ctx.fillStyle = '#FFF'; // アバター背景
        ctx.fill();
        // アバターを描画 (カバー)
        ctx.drawImage(avatarImg, iconX - 40, headerY - 40, 80, 80);
        ctx.restore();

        // アバターの枠線
        ctx.beginPath();
        ctx.arc(iconX, headerY, 40, 0, Math.PI * 2);
        ctx.strokeStyle = '#F88D8D';
        ctx.lineWidth = 4;
        ctx.stroke();
    } else {
        // デフォルトアイコン
        ctx.beginPath();
        ctx.arc(iconX, headerY, 40, 0, Math.PI * 2);
        ctx.fillStyle = '#FFF0F0';
        ctx.fill();
        ctx.beginPath();
        ctx.arc(iconX, headerY + 10, 25, 0, Math.PI, false);
        ctx.fillStyle = '#F88D8D';
        ctx.fill();
    }

    // タイトル
    ctx.fillStyle = '#5D5745';
    ctx.font = '900 64px "Zen Maru Gothic"';
    ctx.textAlign = 'left';
    ctx.textBaseline = 'middle';
    ctx.fillText('たべとっと。', iconX + 60, headerY);

    // 日付
    ctx.fillStyle = '#5D5745';
    ctx.font = 'bold 48px "Zen Maru Gothic"';
    ctx.textAlign = 'right';
    ctx.fillText(date.replace(/-/g, '.'), CANVAS_WIDTH - SAFE_MARGIN - 40, headerY);

    // 6. 写真カードエリア
    const photoAreaY = headerY + 80;
    const photoAreaH = 800;
    const photoAreaW = CANVAS_WIDTH - (SAFE_MARGIN * 2) - 40; 
    const photoAreaX = SAFE_MARGIN + 20;

    // 写真の枠 (点線)
    ctx.save();
    ctx.strokeStyle = '#A0937D';
    ctx.lineWidth = 4;
    ctx.setLineDash([15, 15]);
    ctx.beginPath();
    ctx.roundRect(photoAreaX, photoAreaY, photoAreaW, photoAreaH, 40);
    ctx.stroke();
    ctx.restore();

    // 写真本体
    const innerMargin = 25;
    const imgX = photoAreaX + innerMargin;
    const imgY = photoAreaY + innerMargin;
    const imgW = photoAreaW - (innerMargin * 2);
    const imgH = photoAreaH - (innerMargin * 2);
    const radius = 30;

    ctx.save();
    ctx.beginPath();
    ctx.roundRect(imgX, imgY, imgW, imgH, radius);
    ctx.clip();

    // 写真を描画 (Cover fit)
    const imgAspect = photoImg.width / photoImg.height;
    const areaAspect = imgW / imgH;
    let rW, rH, rX, rY;
    if (imgAspect > areaAspect) {
        rH = imgH;
        rW = imgH * imgAspect;
        rX = imgX + (imgW - rW) / 2;
        rY = imgY;
    } else {
        rW = imgW;
        rH = imgW / imgAspect;
        rY = imgY + (imgH - rH) / 2;
        rX = imgX;
    }
    ctx.filter = 'saturate(1.2) contrast(1.05) brightness(1.02)';
    ctx.drawImage(photoImg, rX, rY, rW, rH);
    ctx.restore();

    // 写真の白フチ
    ctx.strokeStyle = '#FFFFFF';
    ctx.lineWidth = 12;
    ctx.beginPath();
    ctx.roundRect(imgX, imgY, imgW, imgH, radius);
    ctx.stroke();

    // 7. カロリーバッジ
    const badgeW = 360;
    const badgeH = 140;
    const badgeX = photoAreaX + photoAreaW - badgeW + 20; 
    const badgeY = photoAreaY + photoAreaH - badgeH + 30;

    ctx.save();
    ctx.shadowColor = 'rgba(0,0,0,0.15)';
    ctx.shadowBlur = 20;
    ctx.shadowOffsetY = 10;

    // 背景
    ctx.fillStyle = '#FFFFFF';
    ctx.beginPath();
    ctx.roundRect(badgeX, badgeY, badgeW, badgeH, 40);
    ctx.fill();

    // 黄色枠
    ctx.shadowColor = 'transparent';
    ctx.strokeStyle = '#FFD93D';
    ctx.lineWidth = 10;
    ctx.stroke();

    // テキスト
    const kcalStr = String(Math.round(meal.numericCalories));
    ctx.fillStyle = '#F88D8D';
    ctx.font = '900 100px "Zen Maru Gothic"';
    ctx.textAlign = 'right';
    ctx.textBaseline = 'alphabetic';
    ctx.fillText(kcalStr, badgeX + badgeW - 100, badgeY + 105);

    ctx.fillStyle = '#5D5745';
    ctx.font = '900 38px "Zen Maru Gothic"';
    ctx.fillText('kcal', badgeX + badgeW - 30, badgeY + 100);
    ctx.restore();

    // 8. フッター (メニュー名 & PFCチャート)
    const footerY = 1140; 
    const chartCenterX = CANVAS_WIDTH - SAFE_MARGIN - 140; 
    const chartCenterY = footerY + 120;
    const chartRadius = 115;

    // --- メニュー名 (左側) ---
    // 4文字まで: 特大 (110px)
    // 5文字以上: 標準 (70px) + 7文字で改行 (要望対応)

    const rawName = meal.menuName || "";
    const isShortName = rawName.length <= 4;

    let nameFontSize = 70;
    let lineHeight = 85;
    let menuNameLines: string[] = [];

    if (isShortName) {
        // 4文字以内は特大
        nameFontSize = 110;
        menuNameLines = [rawName];
    } else {
        // 5文字以上は7文字で改行
        const MAX_CHARS_PER_LINE = 7;
        for (let i = 0; i < rawName.length; i += MAX_CHARS_PER_LINE) {
            menuNameLines.push(rawName.substring(i, i + MAX_CHARS_PER_LINE));
        }
    }

    ctx.fillStyle = '#5D5745';
    ctx.textAlign = 'left';
    ctx.textBaseline = 'top';
    ctx.font = `900 ${nameFontSize}px "Zen Maru Gothic"`;

    // 描画位置
    const textStartX = SAFE_MARGIN + 40;
    let textCurrentY = isShortName ? footerY + 40 : footerY + 20;

    menuNameLines.forEach((line) => {
        ctx.fillText(line, textStartX, textCurrentY);
        textCurrentY += lineHeight;
    });

    // --- PFC チャート (右側) ---
    if (meal.pfcRatio) {
        const total = meal.pfcRatio.p + meal.pfcRatio.f + meal.pfcRatio.c;
        let startAngle = -Math.PI / 2;
        const holeRadius = 65;

        const drawSlice = (val: number, color: string) => {
            const angle = (val / total) * Math.PI * 2;
            ctx.beginPath();
            ctx.moveTo(chartCenterX, chartCenterY);
            ctx.arc(chartCenterX, chartCenterY, chartRadius, startAngle, startAngle + angle);
            ctx.closePath();
            ctx.fillStyle = color;
            ctx.fill();
            const mid = startAngle + angle / 2;
            startAngle += angle;
            return mid;
        };

        const pAngle = drawSlice(meal.pfcRatio.p, PFC_COLORS.p);
        const fAngle = drawSlice(meal.pfcRatio.f, PFC_COLORS.f);
        const cAngle = drawSlice(meal.pfcRatio.c, PFC_COLORS.c);

        // 中心穴
        ctx.beginPath();
        ctx.arc(chartCenterX, chartCenterY, holeRadius, 0, Math.PI * 2);
        ctx.fillStyle = '#FFFFFF';
        ctx.fill();

        // 中心テキスト
        ctx.fillStyle = '#5D5745';
        ctx.textAlign = 'center';
        ctx.textBaseline = 'middle';
        ctx.font = '900 26px "Zen Maru Gothic"';
        ctx.fillText('PFC', chartCenterX, chartCenterY - 12);
        ctx.font = '900 18px "Zen Maru Gothic"';
        ctx.fillText('バランス', chartCenterX, chartCenterY + 14);

        // ラベル (%, P/F/C)
        const labelR = chartRadius + 40;

        const drawLabel = (angle: number, val: number, label: string, color: string) => {
            const lx = chartCenterX + Math.cos(angle) * labelR;
            const ly = chartCenterY + Math.sin(angle) * labelR;

            ctx.beginPath();
            ctx.arc(lx, ly, 28, 0, Math.PI * 2);
            ctx.fillStyle = '#FFFFFF';
            ctx.fill();
            ctx.lineWidth = 3;
            ctx.strokeStyle = color;
            ctx.stroke();

            ctx.fillStyle = color;
            ctx.font = '900 24px "Zen Maru Gothic"';
            ctx.textAlign = 'center';
            ctx.textBaseline = 'middle';
            ctx.fillText(label, lx, ly);

            const isRight = Math.cos(angle) >= 0;
            const textX = lx + (isRight ? 35 : -35);
            const textY = ly;

            ctx.fillStyle = '#5D5745';
            ctx.font = '900 32px "Zen Maru Gothic"';
            ctx.textAlign = isRight ? 'left' : 'right';
            ctx.fillText(`${Math.round(val)}%`, textX, textY);
        };

        drawLabel(pAngle, meal.pfcRatio.p, 'P', PFC_COLORS.p);
        drawLabel(fAngle, meal.pfcRatio.f, 'F', PFC_COLORS.f);
        drawLabel(cAngle, meal.pfcRatio.c, 'C', PFC_COLORS.c);
    }
};

export const renderMealResultToBlob = async (
    photoBase64: string,
    meal: MealAnalysis,
    date: string,
    options?: { showMascot?: boolean, avatarBase64?: string }
): Promise<Blob | null> => {
    const canvas = document.createElement('canvas');
    canvas.width = CANVAS_WIDTH;
    canvas.height = CANVAS_HEIGHT;
    await renderMealResultToCanvas(canvas, photoBase64, meal, date, options);
    return new Promise(resolve => canvas.toBlob(resolve, 'image/jpeg', 0.95));
};

