  onBack: () => void;
  user: UserProfile;
  todayRecord: DailyRecord;
}

const ACTIVITIES = [
  { label: "散歩", met: 3.5 },
  { label: "早歩き", met: 4.3 },
  { label: "軽いジョグ", met: 6.0 },
  { label: "筋トレ", met: 5.5 },
  { label: "水泳", met: 6.0 },
  { label: "水泳（やや速い）", met: 8.0 },
  { label: "サイクリング", met: 7.0 },
  { label: "家事", met: 3.0 },
