interface PostureViewProps {
  tokens: number;
  useToken: () => boolean;
  restoreTokens: () => Promise<boolean>;
  lastAnalysis: PostureAnalysis | null;
  onSave: (photo: string, analysis: PostureAnalysis, date: string, sidePhoto?: string | null) => void;
  onClose: () => void;
  onShowPoints: () => void;
  todayWeight?: number;
  openCalendar: (initialDate: string, onConfirm: (date: string) => void) => void;
  onMenuOpen: () => void;
  onCompare?: () => void; 
  onOpenMoveGuide?: () => void; // Added
  isMenuOpen: boolean; 
}

const PostureView: React.FC<PostureViewProps> = ({ tokens, useToken, restoreTokens, lastAnalysis, onSave, onClose, onShowPoints, todayWeight, onMenuOpen, onCompare, onOpenMoveGuide, isMenuOpen }) => {
  const [step, setStep] = useState<'intro' | 'ad_wait' | 'side_wait' | 'analyze' | 'result'>('intro');
  const [frontImage, setFrontImage] = useState<string | null>(null);
  const [sideImage, setSideImage] = useState<string | null>(null);
  const [analysis, setAnalysis] = useState<PostureAnalysis | null>(null);
  const [isSaving, setIsSaving] = useState(false);
  const [hasSaved, setHasSaved] = useState(false);

  useEffect(() => {
    // メニューが開いているときはApp.tsxが全広告を消すので、ここでは何もしない
    if (isMenuOpen) return;

    // 画面状態に応じた広告制御
    if (step === 'analyze' || step === 'ad_wait' || step === 'side_wait') {
        hideBanner();
        hideMrec();
    } else if (step === 'result') {
        // 結果画面はMRECだとコンテンツを隠すため、通常バナーに戻す
        hideMrec();
        showBanner();
    } else {
        // intro (通常画面) は MRECを表示
        hideBanner();
        showMrec();
    }
  }, [step, isMenuOpen]);

  const handleStartFront = async () => {
    if (tokens <= 0) { setStep('ad_wait'); return; }
    await hideBanner();
    await hideMrec();
    try {
      const result = await takePhoto(CameraSource.Camera, 'rear');
      setFrontImage(result.base64);
      setStep('side_wait');
    } catch (e: any) { 
        if (e.message !== "CANCELLED") alert(e.message); 
        // キャンセル時はここから復帰しない（自動でuseEffectが走らない）場合もあるため
        // 必要ならStepをintroに戻すが、Camera APIはキャンセル時に戻り値を返さない場合もある
    }
  };

  const startAnalysis = async (sImg: string | null = null) => {
    if (!frontImage) return;
    if (!useToken()) { setStep('ad_wait'); return; }

    await hideBanner();
    await hideMrec();

    setSideImage(sImg);
    setStep('analyze');
    try {
      const result = await analyzePosture(frontImage, sImg);
      setAnalysis(result);
      setStep('result');
    } catch (e: any) {
      alert("解析に失敗しました。");
      setStep('intro');
    }
  };

  const handleStartSide = async () => {
    await hideBanner();
    await hideMrec();
    try {
      const result = await takePhoto(CameraSource.Camera, 'rear');
      startAnalysis(result.base64);
    } catch (e: any) { 
        if (e.message !== "CANCELLED") alert(e.message); 
    }
  };

  const handleRestore = async () => {
    await hideBanner();
    await hideMrec();
    const success = await restoreTokens();
    if (success) {
      setStep('intro');
    }
  };

  const handleSaveAll = async () => {
    if (frontImage && analysis && !isSaving && !hasSaved) {
      setIsSaving(true);
      try {
        const date = getTodayString();
        const fileName = `tabetotto_posture_${date.replace(/-/g, '')}_${Date.now()}.jpg`;

        let gallerySaved = false;
        if (Capacitor.getPlatform() === 'android') {
            try {
                const res = await GallerySaver.saveImage({
                    base64: frontImage,
                    fileName: fileName,
                    album: 'たべとっと。'
                });
                if (res.saved) gallerySaved = true;
            } catch (e) {
                console.warn("Gallery save failed:", e);
            }
        }

        if (!gallerySaved && Capacitor.isNativePlatform()) {
             try {
                await Filesystem.writeFile({
                    path: fileName,
                    data: frontImage,
                    directory: Directory.Documents,
                });
             } catch (fsError) {
                console.error("Device documents save failed", fsError);
             }
        }

        onSave(frontImage, analysis, date, sideImage);
        setHasSaved(true);
      } catch (e) {
        setIsSaving(false);
      } finally {
        setIsSaving(false);
      }
    }
  };

  return (
    <div className="flex flex-col min-h-screen pb-44 w-full no-scrollbar overflow-x-hidden relative">
      {/* Background Decor */}
      <div className="organic-blob w-80 h-80 top-20 -left-40 animate-float-slow will-change-transform" style={{ backgroundColor: THEME.colors.primaryLight }}></div>
      <div className="organic-blob w-64 h-64 bottom-60 -right-32 animate-float-slow will-change-transform" style={{ backgroundColor: THEME.colors.secondaryLight, animationDelay: '1s' }}></div>

      <header className="sticky top-0 z-[60] pt-safe backdrop-blur-md border-b w-full shadow-sm" style={{ backgroundColor: `${THEME.colors.bg}E6`, borderColor: THEME.colors.border }}>
        <div className="px-6 py-3 flex justify-between items-center w-full">
            <div className="flex items-center gap-2">
                <div className="w-11 h-11 rounded-full flex items-center justify-center shadow-[0_15px_35px_-8px_rgba(248,141,141,0.5)] animate-sway transition-transform will-change-transform" style={{ backgroundColor: THEME.colors.primary }}>
                    <ScanFace size={22} className="text-white" strokeWidth={3} />
                </div>
                <div className="flex flex-col">
                  <h1 className="text-xl font-black tracking-widest leading-none" style={{ color: THEME.colors.primary }}>たべとっと。</h1>
                  <span className="text-[8px] font-black tracking-tighter opacity-70" style={{ color: THEME.colors.primary }}>Posture Check</span>
                </div>
            </div>
            <button onClick={onMenuOpen} className="pl-4 pr-3 py-2 rounded-full shadow-md active:scale-95 transition-all flex items-center gap-2 border-2 border-white ring-2" style={{ backgroundColor: THEME.colors.primary, color: 'white', borderColor: 'white', ['--tw-ring-color' as any]: `${THEME.colors.primary}33` }}>
                <span className="text-sm font-black tracking-wide">Menu</span>
                <Menu size={20} strokeWidth={2.5} />
            </button>
        </div>
      </header>

