            {step === 'analyze' && (
                <div className="px-6 flex flex-col items-center justify-center space-y-12 py-32">
                    <Loader2 className="animate-spin" style={{ color: THEME.colors.primary }} size={80} />
                    <p className="font-black text-xl animate-bounce">AIが体型をチェック中...</p>
                </div>
            )}

            {step === 'result' && analysis && frontImage && (
                // バナー広告が下部に固定されるため、コンテンツが隠れないようにpadding-bottomを十分確保 (40=160px)
                <div className="animate-in zoom-in-95 pb-40">
                    <div className="px-6 space-y-6">
                      <PostureResultCarousel 
                          frontPhoto={frontImage} 
                          sidePhoto={sideImage} 
                          analysis={analysis} 
                          todayWeight={todayWeight}
                      />

                      <Card className="!p-6 bg-white border-2 border-dashed" style={{ borderColor: THEME.colors.border }}>
                          <p className="font-black text-xs mb-2 flex items-center" style={{ color: THEME.colors.primary }}>
                            <span className="mr-1">✨</span> 解析結果
                          </p>
                          <p className="text-xs font-bold leading-relaxed break-words whitespace-normal">{analysis.point}</p>
                      </Card>

                      {hasSaved && onCompare && (
                        <div className="flex flex-col items-end animate-in fade-in slide-in-from-bottom-2">
                           <div className="mb-2 text-[10px] font-bold text-primary animate-pulse">
                              前回と比べて、どう感じますか？
                           </div>
                           <Button onClick={onCompare} variant="outline" className="min-h-[48px] h-auto py-2 text-xs px-6 bg-white border-primary text-primary w-full shadow-sm">
                              <ArrowLeftRight size={16} className="mr-2 shrink-0" /> 前回と見比べる
                           </Button>
                        </div>
                      )}

                      <div className="space-y-4 pt-4">
                          <button 
                            onClick={handleSaveAll} 
                            disabled={isSaving || hasSaved}
                            className={`w-full min-h-[96px] h-auto py-2 text-2xl font-black rounded-[32px] shadow-2xl transition-all flex items-center justify-center ${hasSaved ? 'bg-secondary text-white' : 'bg-primary text-white active:scale-95'}`}
                            style={hasSaved ? { backgroundColor: THEME.colors.secondary } : { backgroundColor: THEME.colors.primary }}
                          >
                            {isSaving ? <Loader2 className="animate-spin mr-2 shrink-0" /> : hasSaved ? <Check className="mr-2 shrink-0" /> : null}
                            {isSaving ? '保存中...' : hasSaved ? '記録しました。✨' : 'アプリにきろくする ✨'}
                          </button>

                          <div className="grid grid-cols-2 gap-3">
                              <button onClick={() => addToCalendar('posture', getTodayString(), analysis)} className="flex flex-col items-center py-5 border-2 rounded-[28px] bg-white shadow-sm active:scale-95 transition-all" style={{ borderColor: THEME.colors.border }}>
                                  <CalendarPlus size={22} style={{ color: THEME.colors.secondary }} /><span className="text-[10px] font-black mt-1">カレンダー</span>
                              </button>
                              <button onClick={() => alert('Posture photos are private.')} className="flex flex-col items-center py-5 border-2 rounded-[28px] bg-white shadow-sm opacity-30" style={{ borderColor: THEME.colors.border }}>
                                  <Share2 size={22} /><span className="text-[10px] font-black mt-1">共有不可</span>
                              </button>
                          </div>

                          {hasSaved && (
                            <Button 
                              variant="cancel"
                              onClick={onClose} 
                              className="w-full min-h-[72px] h-auto py-2 text-xl font-black rounded-[28px] shadow-xl transition-all flex items-center justify-center border-2 active:scale-95"
                            >
                               とじる
                            </Button>
                          )}
                      </div>
                    </div>
                </div>
            )}
      </main>
    </div>
  );
};

export default PostureView;

import React, { useState, useEffect, useMemo, useCallback } from 'react';
import { UserProfile, DailyRecord, AppView, PostureAnalysis, MealAnalysis, PostureComparison } from './types';
import { CuteKeypad, CuteCalendar } from './components/UIComponents';
import SideMenu from './components/SideMenu';
import { PostureDetailModal, MealDetailModal, SharePreviewModal, CompareModal } from './components/SharedModals';
import { Menu, Utensils } from 'lucide-react';
import { AdBelt } from './components/AdComponents'; // AdBelt追加

// View Imports
import DashboardView from './components/views/DashboardView';
import MealView from './components/views/MealView';
import PostureView from './components/views/PostureView';
import HistoryView from './components/views/HistoryView';
import SettingsView from './components/views/SettingsView';
import PosturePointsView from './components/views/PosturePointsView';
import NutritionGuideView from './components/views/NutritionGuideView';
import MoveGuideView from './components/views/MoveGuideView';

import { 
  STORAGE_KEY_USER, 
  STORAGE_KEY_RECORDS, 
  STORAGE_KEY_TOKENS, 
  STORAGE_KEY_LAST_RECOVERY,
  getTodayString, 
  toLocalDateString,
  MAX_TOKENS, 
  AUTO_MAX_TOKENS,
  REWARD_TOKENS, 
  RECOVERY_TIME_MS 
} from './utils';
import { generateDailyAdvice } from './services/gemini/report';
import { initAdMob, showRewardedInterstitialAd, showBanner, hideBanner, hideMrec, showMrec } from './services/admobService';
import { THEME } from './theme';
import { Capacitor } from '@capacitor/core';

const App: React.FC = () => {
  const [view, setView] = useState<AppView>(AppView.DASHBOARD);
  const [user, setUser] = useState<UserProfile>({ 
    height: 160, 
    targetWeight: 50, 
    nickname: 'ゲスト', 
    theme: 'default', 
    showMascotOnShare: true 
  });
  const [records, setRecords] = useState<Record<string, DailyRecord>>({});
  const [isLoaded, setIsLoaded] = useState(false);

  const [tokens, setTokens] = useState<number>(MAX_TOKENS);
  const [lastRecovery, setLastRecovery] = useState<number>(Date.now());

  const [selectedMeal, setSelectedMeal] = useState<{ analysis: MealAnalysis, photo: string, date: string, index: number } | null>(null);
  const [shareModalOpen, setShareModalOpen] = useState(false);
  const [preGeneratedBlob, setPreGeneratedBlob] = useState<Blob | null>(null);

  const [isPostureModalOpen, setIsPostureModalOpen] = useState(false);
  const [showingPostureDate, setShowingPostureDate] = useState<string | null>(null);

  // Compare Modal
  const [isCompareModalOpen, setIsCompareModalOpen] = useState(false);
  const [comparingDate, setComparingDate] = useState<string | null>(null);

  const [dailyAdvice, setDailyAdvice] = useState("今日もバランスの良い食事と良い姿勢を意識しましょう！");

  const [isMenuOpen, setIsMenuOpen] = useState(false);
  const [touchStart, setTouchStart] = useState<{x: number, y: number} | null>(null);

  const [keypadConfig, setKeypadConfig] = useState<{
    initialValue: string;
    unit: string;
    onConfirm: (val: string) => void;
  } | null>(null);

  const [calendarConfig, setCalendarConfig] = useState<{
    initialDate: string;
    onConfirm: (date: string) => void;
  } | null>(null);

  const openKeypad = useCallback((initialValue: string, unit: string, onConfirm: (val: string) => void) => {
    setKeypadConfig({ initialValue, unit, onConfirm });
  }, []);

  const openCalendar = useCallback((initialDate: string, onConfirm: (date: string) => void) => {
    setCalendarConfig({ initialDate, onConfirm });
  }, []);

  useEffect(() => { 
    const initApp = async () => {
      try {
        // 広告初期化を待たずに開始する（並列処理）
        // admobService側でinitPromiseを管理しているため、showBannerはこれが完了するのを自動で待機する
        initAdMob(); 

        const loadedUser = localStorage.getItem(STORAGE_KEY_USER);
        if (loadedUser) setUser(JSON.parse(loadedUser));
        const loadedRecords = localStorage.getItem(STORAGE_KEY_RECORDS);
        if (loadedRecords) setRecords(JSON.parse(loadedRecords));
        const storedTokens = localStorage.getItem(STORAGE_KEY_TOKENS);
        const storedLastRecovery = localStorage.getItem(STORAGE_KEY_LAST_RECOVERY);
        if (storedTokens !== null && storedLastRecovery !== null) {
          let t = parseInt(storedTokens);
          let last = parseInt(storedLastRecovery);
          const now = Date.now();
          if (t < AUTO_MAX_TOKENS) {
            const elapsed = now - last;
            const recoveredAmount = Math.floor(elapsed / RECOVERY_TIME_MS);
            if (recoveredAmount > 0) {
              t = Math.min(AUTO_MAX_TOKENS, t + recoveredAmount);
              last = last + (recoveredAmount * RECOVERY_TIME_MS);
              if (t >= AUTO_MAX_TOKENS) last = now;
            }
          }
          setTokens(t);
          setLastRecovery(last);
        }
      } catch (e) {
        console.warn("Storage loading failed", e);
      } finally {
        setIsLoaded(true);
      }
    };
    initApp();
  }, []);

  // 広告制御: メニュー開閉時およびページ遷移時
  useEffect(() => {
    if (!Capacitor.isNativePlatform()) return;

    if (isMenuOpen) {
        // メニューが開いているときは全広告OFF
        hideBanner();
        hideMrec();
    } else {
        // メニューが閉じている時の制御
        if ([AppView.DASHBOARD, AppView.HISTORY, AppView.SETTINGS, AppView.NUTRITION_GUIDE, AppView.MOVE_GUIDE].includes(view)) {
            // Home / History / Settings / NutritionGuide / MoveGuide は通常バナー
            hideMrec();
            showBanner();
        } else if ([AppView.MEAL, AppView.POSTURE].includes(view)) {
            // Meal / Posture は MREC だが、step制御（撮影中など）が優先されるため、
            // ここで強制的に showMrec() を呼ぶとタイミングによっては不都合が生じる。
            // したがって、App.tsxでは「他画面のバナーを消す」処理までを行い、
            // 表示復帰は各Viewの useEffect（isMenuOpen依存）に任せる。
        }
    }
  }, [isMenuOpen, view]);

  useEffect(() => {
    document.documentElement.setAttribute('data-theme', user.theme || 'default');
  }, [user.theme]);

  const safeSaveRecords = (newRecords: Record<string, DailyRecord>) => {
    if (!isLoaded) return;

    // 10日以上前の写真データを削除する処理
    const CLEANUP_DAYS = 10;
    const now = new Date();
    const cutoffDate = new Date(now);
    cutoffDate.setDate(now.getDate() - CLEANUP_DAYS);
    // UTCではなくローカル時間基準の日付文字列を使用
    const cutoffStr = toLocalDateString(cutoffDate);

    const recordsToSave = { ...newRecords };

    Object.keys(recordsToSave).forEach(date => {
        if (date < cutoffStr) {
            const record = recordsToSave[date];
            let modified = false;

            if (record.mealPhotoUrls && record.mealPhotoUrls.some(url => url !== "")) {
                record.mealPhotoUrls = record.mealPhotoUrls.map(() => "");
                modified = true;
            }
            if (record.posturePhotoUrl) {
                record.posturePhotoUrl = undefined;
                modified = true;
            }
            if (record.postureSidePhotoUrl) {
                record.postureSidePhotoUrl = undefined;
                modified = true;
            }
        }
    });

    try {
      localStorage.setItem(STORAGE_KEY_RECORDS, JSON.stringify(recordsToSave));
    } catch (e: any) {
      if (e.name === 'QuotaExceededError' || e.name === 'NS_ERROR_DOM_QUOTA_REACHED') {
        const sortedDates = Object.keys(recordsToSave).sort();
        if (sortedDates.length > 3) { 
          sortedDates.slice(0, 5).forEach(date => {
            recordsToSave[date].mealPhotoUrls = recordsToSave[date].mealPhotoUrls.map(() => "");
            recordsToSave[date].posturePhotoUrl = undefined;
            recordsToSave[date].postureSidePhotoUrl = undefined;
          });
          try {
             localStorage.setItem(STORAGE_KEY_RECORDS, JSON.stringify(recordsToSave));
          } catch(retryE) {
             console.error("Storage full even after cleanup", retryE);
          }
        }
      }
    }
  };

  useEffect(() => {
    if (isLoaded) localStorage.setItem(STORAGE_KEY_USER, JSON.stringify(user));
  }, [user, isLoaded]);

  useEffect(() => {
    safeSaveRecords(records);
  }, [records]);

  useEffect(() => {
    if (isLoaded) {
      localStorage.setItem(STORAGE_KEY_TOKENS, tokens.toString());
      localStorage.setItem(STORAGE_KEY_LAST_RECOVERY, lastRecovery.toString());
    }
  }, [tokens, lastRecovery, isLoaded]);

  useEffect(() => {
    const timer = setInterval(() => {
      if (tokens < AUTO_MAX_TOKENS) {
        const now = Date.now();
        if (now - lastRecovery >= RECOVERY_TIME_MS) {
          setTokens(prev => Math.min(AUTO_MAX_TOKENS, prev + 1));
          setLastRecovery(prev => prev + RECOVERY_TIME_MS);
        }
      }
    }, 60000);
    return () => clearInterval(timer);
  }, [tokens, lastRecovery]);

  const handleTouchStart = (e: React.TouchEvent) => {
    setTouchStart({ x: e.touches[0].clientX, y: e.touches[0].clientY });
  };

  const handleTouchEnd = (e: React.TouchEvent) => {
    if (!touchStart) return;
    const endX = e.changedTouches[0].clientX;
    const endY = e.changedTouches[0].clientY;
    const diffX = touchStart.x - endX;
    const diffY = touchStart.y - endY;

    if (Math.abs(diffX) > 70 && Math.abs(diffY) < 50) {
      const mainViews = [AppView.DASHBOARD, AppView.HISTORY, AppView.MEAL, AppView.POSTURE, AppView.SETTINGS];
      const currentIndex = mainViews.indexOf(view);

      if (currentIndex !== -1) {
        if (diffX > 0) { 
           const next = mainViews[currentIndex + 1];
           if (next) setView(next);
        } else { 
           const prev = mainViews[currentIndex - 1];
           if (prev) setView(prev);
        }
      }
    }
    setTouchStart(null);
  };

  const useToken = useCallback((): boolean => {
    if (tokens > 0) {
      setTokens(prev => {
        const next = prev - 1;
        if (prev >= AUTO_MAX_TOKENS && next < AUTO_MAX_TOKENS) {
          setLastRecovery(Date.now());
        }
        return next;
      });
      return true;
    }
    return false;
  }, [tokens]);

  const restoreTokens = async (): Promise<boolean> => {
    const success = await showRewardedInterstitialAd();
    if (success) {
      setTokens(prev => Math.min(MAX_TOKENS, prev + REWARD_TOKENS));
      setLastRecovery(Date.now());
      return true;
    }
    return false;
  };

  const todayKey = getTodayString();
  const todayRecord = useMemo(() => records[todayKey] || { id: todayKey, date: todayKey, mealPhotoUrls: [], mealAnalyses: [] }, [records, todayKey]);

  useEffect(() => {
    if (!isLoaded) return;
    const fetchAdvice = async () => {
        try { const advice = await generateDailyAdvice(user, todayRecord); setDailyAdvice(advice); } catch (e) { }
    };
    fetchAdvice();
  }, [user.nickname, todayRecord.weight, todayRecord.mealAnalyses.length, isLoaded]);

  const lastPostureDate = useMemo(() => {
    const sortedDates = Object.keys(records).sort().reverse();
    for (const d of sortedDates) { if (records[d].postureAnalysis?.isAnalyzable) return d; }
    return null;
  }, [records]);

  const lastPostureRecord = lastPostureDate ? records[lastPostureDate] : null;

  const handleWeightUpdate = (weight: number) => {
    setRecords(prev => ({ ...prev, [todayKey]: { ...todayRecord, weight } }));
  };

  const handleMealSave = (analysis: MealAnalysis, photo: string, date: string) => {
    setRecords(prev => {
      const targetRecord = prev[date] || { id: date, date, mealPhotoUrls: [], mealAnalyses: [] };
      return { ...prev, [date]: { ...targetRecord, mealPhotoUrls: [...targetRecord.mealPhotoUrls, photo], mealAnalyses: [...targetRecord.mealAnalyses, analysis] } };
    });
  };

  const handleUpdateExternalUrl = (url: string) => {
    if (!selectedMeal) return;
    setRecords(prev => {
        const r = { ...prev[selectedMeal.date] };
        r.mealAnalyses[selectedMeal.index].externalUrl = url;
        return { ...prev, [selectedMeal.date]: r };
    });
  };

  const handlePostureSave = (photo: string, analysis: PostureAnalysis, date: string, sidePhoto?: string | null) => {
    setRecords(prev => {
      const targetRecord = prev[date] || { id: date, date: date, mealPhotoUrls: [], mealAnalyses: [] };
      return { ...prev, [date]: { ...targetRecord, posturePhotoUrl: photo, postureSidePhotoUrl: sidePhoto || undefined, postureAnalysis: analysis } };
    });
  };

  const handleComparisonSave = (comparison: PostureComparison) => {
    if (!comparingDate) return;
    setRecords(prev => {
        const targetRecord = prev[comparingDate];
        if (!targetRecord) return prev;
        return {
            ...prev,
            [comparingDate]: {
                ...targetRecord,
                postureComparison: comparison
            }
        };
    });
  };

  const renderContent = () => {
    if (!isLoaded) return (
      <div className="flex flex-col items-center justify-center h-screen space-y-4">
        <div className="w-16 h-16 bg-primary rounded-2xl animate-sway flex items-center justify-center text-white text-2xl font-black">🍱</div>
        <p className="font-black text-primary animate-pulse">読み込み中...</p>
      </div>
    );

    switch (view) {
      case AppView.DASHBOARD:
        return <DashboardView user={user} todayRecord={todayRecord} records={records} lastPostureDate={lastPostureDate} lastPosturePhoto={lastPostureRecord?.posturePhotoUrl || null} setView={setView} onWeightUpdate={handleWeightUpdate} dailyAdvice={dailyAdvice} onMealClick={(m, p, d, i) => { setPreGeneratedBlob(null); setSelectedMeal({ analysis: m, photo: p, date: d, index: i }); }} onPostureClick={() => lastPostureDate ? (setShowingPostureDate(lastPostureDate), setIsPostureModalOpen(true)) : setView(AppView.POSTURE)} openKeypad={openKeypad} tokens={tokens} />;
      case AppView.MEAL:
        return <MealView user={user} tokens={tokens} useToken={useToken} restoreTokens={restoreTokens} onSave={handleMealSave} onClose={() => setView(AppView.DASHBOARD)} onShareClick={(blob) => { setPreGeneratedBlob(blob || null); setShareModalOpen(true); }} openKeypad={openKeypad} openCalendar={openCalendar} onOpenGuide={() => setView(AppView.NUTRITION_GUIDE)} onMenuOpen={() => setIsMenuOpen(true)} isMenuOpen={isMenuOpen} />;
      case AppView.HISTORY:
        return <HistoryView records={Object.values(records)} user={user} onMealClick={(m, p, d, i) => { setPreGeneratedBlob(null); setSelectedMeal({ analysis: m, photo: p, date: d, index: i }); }} onPostureClick={(r) => { setShowingPostureDate(r.date); setIsPostureModalOpen(true); }} isMenuOpen={isMenuOpen} />;
      case AppView.POSTURE:
        return <PostureView tokens={tokens} useToken={useToken} restoreTokens={restoreTokens} lastAnalysis={lastPostureRecord?.postureAnalysis || null} onSave={handlePostureSave} onClose={() => setView(AppView.DASHBOARD)} onShowPoints={() => setView(AppView.POSTURE_POINTS)} todayWeight={todayRecord.weight} openCalendar={openCalendar} onMenuOpen={() => setIsMenuOpen(true)} onCompare={() => { setComparingDate(getTodayString()); setIsCompareModalOpen(true); }} onOpenMoveGuide={() => setView(AppView.MOVE_GUIDE)} isMenuOpen={isMenuOpen} />;
      case AppView.SETTINGS:
        return <SettingsView user={user} onSave={setUser} openKeypad={openKeypad} />;
      case AppView.POSTURE_POINTS:
        return <PosturePointsView onBack={() => setView(AppView.POSTURE)} />;
      case AppView.NUTRITION_GUIDE:
        return <NutritionGuideView onBack={() => setView(AppView.MEAL)} />;
      case AppView.MOVE_GUIDE:
        return <MoveGuideView onBack={() => setView(AppView.POSTURE)} user={user} todayRecord={todayRecord} />;
      default:
        return null;
    }
  };

  const showGlobalHeader = [AppView.DASHBOARD, AppView.HISTORY, AppView.SETTINGS].includes(view);

  return (
    <div 
        className="min-h-screen font-zen-maru pb-safe selection:text-white overflow-x-hidden relative w-full flex justify-center items-start" 
        style={{ color: THEME.colors.text, backgroundColor: THEME.colors.bg }}
        onTouchStart={handleTouchStart}
