import React, { useState, useMemo } from 'react';
import { ChevronLeft, Activity, Flame, Clock, Utensils, Target, Footprints, Info } from 'lucide-react';
import { THEME } from '../../theme';
import { Button, Card } from '../UIComponents';
import { UserProfile, DailyRecord } from '../../types';

interface MoveGuideViewProps {
  onBack: () => void;
  user: UserProfile;
  todayRecord: DailyRecord;
}

const ACTIVITIES = [
  { label: "散歩", met: 3.5 },
  { label: "早歩き", met: 4.3 },
  { label: "軽いジョグ", met: 6.0 },
  { label: "筋トレ", met: 5.5 },
  { label: "水泳", met: 6.0 },
  { label: "水泳（やや速い）", met: 8.0 },
  { label: "サイクリング", met: 7.0 },
  { label: "家事", met: 3.0 },
  { label: "掃除機がけ", met: 3.3 },
  { label: "床拭き", met: 3.8 },
  { label: "風呂掃除", met: 4.0 },
  { label: "テニス", met: 7.0 },
  { label: "サッカー", met: 7.0 },
  { label: "バスケットボール", met: 8.0 }
];

const MoveGuideView: React.FC<MoveGuideViewProps> = ({ onBack, user, todayRecord }) => {
  const [selectedActivityIndex, setSelectedActivityIndex] = useState(0);
  const [minutes, setMinutes] = useState(30);

  const weight = todayRecord.weight || user.targetWeight || 50; // 体重がない場合は目標体重または50kg仮定
  const activity = ACTIVITIES[selectedActivityIndex];

  // 今日の間食カロリー合計
  const snackCalories = useMemo(() => {
    return todayRecord.mealAnalyses
      .filter(m => m.mealType === 'snack')
      .reduce((acc, m) => acc + m.numericCalories, 0);
  }, [todayRecord]);

  // 消費カロリー計算: METs * kg * hour
  const burnedCalories = Math.round(activity.met * weight * (minutes / 60));

  // 間食分を消費するのに必要な時間 (分)
  // minutes = (kcal / (met * weight)) * 60
  // デフォルトは散歩(3.5METs)で計算
  const defaultWalkMet = 3.5;
  const minutesWalkToBurn = snackCalories > 0 
    ? Math.round((snackCalories / (defaultWalkMet * weight)) * 60) 
    : 0;

  const minutesToBurnSnack = snackCalories > 0 
    ? Math.round((snackCalories / (activity.met * weight)) * 60) 
    : 0;

  // ダイエット目標に基づく調整目安
  const dietAdvice = useMemo(() => {
    if (user.dietMode?.enabled && user.dietMode.goal === 'loss' && user.targetWeight && user.dietMode.targetDate && todayRecord.weight) {
        const diff = todayRecord.weight - user.targetWeight;
        if (diff <= 0) return null;

        const totalKcal = diff * 7200; // 脂肪1kg = 7200kcalで計算
        const today = new Date();
        const target = new Date(user.dietMode.targetDate);
        const daysLeft = Math.ceil((target.getTime() - today.getTime()) / (1000 * 60 * 60 * 24));

        // 残り日数が計算できない、または過ぎている場合は30日で計算
        const effectiveDays = daysLeft > 0 ? daysLeft : 30;
        const dailyBurn = Math.round(totalKcal / effectiveDays);

        return {
            dailyBurn,
            days: effectiveDays
        };
    }
    return null;
  }, [user, todayRecord.weight]);

  return (
    <div className="flex flex-col min-h-screen pb-44 w-full no-scrollbar overflow-x-hidden relative">
      {/* Background Decor */}
      <div className="organic-blob w-80 h-80 top-20 -right-40 animate-float-slow will-change-transform" style={{ backgroundColor: THEME.colors.primaryLight }}></div>
      <div className="organic-blob w-64 h-64 bottom-60 -left-32 animate-float-slow will-change-transform" style={{ backgroundColor: THEME.colors.secondaryLight, animationDelay: '2s' }}></div>

      <header className="sticky top-0 z-[60] pt-safe backdrop-blur-md border-b w-full shadow-sm" style={{ backgroundColor: `${THEME.colors.bg}E6`, borderColor: THEME.colors.border }}>
        <div className="px-6 py-3 flex items-center justify-between">
            <div className="flex items-center gap-2">
                <button onClick={onBack} className="p-2 -ml-2 rounded-full hover:bg-black/5" style={{ color: THEME.colors.text }}>
                    <ChevronLeft size={24} />
                </button>
                <div className="flex flex-col">
                    <span className="text-xs font-black tracking-widest leading-none" style={{ color: THEME.colors.primary }}>うごきの</span>
                    <h1 className="text-xl font-black tracking-widest leading-none" style={{ color: THEME.colors.primary }}>目安</h1>
                </div>
            </div>
        </div>
      </header>

      <main className="mt-8 px-6 space-y-8 animate-in slide-in-from-right duration-300 relative z-10">
         {/* トップ強調表示エリア */}
         <div className="bg-white p-6 rounded-[32px] border-2 shadow-sm relative overflow-hidden text-center space-y-4" style={{ borderColor: THEME.colors.border }}>
             <div className="absolute top-0 left-0 w-full h-2" style={{ backgroundColor: THEME.colors.secondary }}></div>

             {snackCalories > 0 ? (
                 <>
                     <div className="flex items-center justify-center gap-2">
                         <span className="text-2xl animate-bounce">🍰</span>
                         <span className="text-sm font-bold text-stone-500">今日の間食</span>
                     </div>
                     <div className="text-4xl font-black text-[#5D5745]">
                         {snackCalories} <span className="text-lg font-bold text-[#A0937D]">kcal</span>
                     </div>

                     <div className="flex items-center justify-center gap-4 text-stone-300">
                         <div className="h-[2px] w-8 bg-stone-200 rounded-full"></div>
                         <span className="text-xs font-black">IS EQUAL TO</span>
                         <div className="h-[2px] w-8 bg-stone-200 rounded-full"></div>
                     </div>

                     <div className="flex items-center justify-center gap-2">
                         <span className="text-2xl animate-sway">🚶</span>
                         <span className="text-sm font-bold text-stone-500">散歩なら</span>
                     </div>
                     <div className="text-4xl font-black" style={{ color: THEME.colors.secondary }}>
                         約 {minutesWalkToBurn} <span className="text-lg font-bold text-[#A0937D]">分</span>
                     </div>

                     <p className="text-[10px] font-bold text-stone-400 mt-2 bg-stone-50 py-2 px-4 rounded-xl inline-block">
                         ※この間食は、散歩約{minutesWalkToBurn}分くらいに相当します。<br/>
                         無理のない範囲で体を動かしてみましょう。
                     </p>
                 </>
             ) : (
                 <div className="py-4 space-y-3">
                     <Utensils size={32} className="mx-auto text-stone-300" />
                     <p className="text-sm font-bold text-stone-500">
                         まだ間食の記録がありません。<br/>
                         おやつを食べたら記録してみましょう！
                     </p>
                 </div>
             )}

             <p className="text-[9px] font-bold text-stone-300 absolute bottom-2 right-4">※目安です</p>
         </div>

         {/* シミュレーター */}
         <Card className="!p-6 bg-white border-2 space-y-6" style={{ borderColor: THEME.colors.border }}>
             <div className="flex items-center gap-2 mb-2">
                 <Activity size={20} className="text-[#6BC99D]" />
                 <h3 className="text-lg font-black" style={{ color: THEME.colors.text }}>活動量シミュレーター</h3>
             </div>

             <div className="space-y-4">
                 <div className="space-y-1">
                     <label className="text-[10px] font-black text-stone-400 uppercase tracking-wider ml-1">活動の種類</label>
                     <div className="relative">
                         <select 
                            value={selectedActivityIndex}
                            onChange={(e) => setSelectedActivityIndex(Number(e.target.value))}
                            className="w-full p-3 rounded-xl bg-stone-50 border-2 font-bold text-sm appearance-none outline-none focus:border-[#6BC99D]"
                            style={{ borderColor: THEME.colors.border, color: THEME.colors.text }}
                         >
                             {ACTIVITIES.map((act, idx) => (
                                 <option key={idx} value={idx}>{act.label}</option>
                             ))}
                         </select>
                         <div className="absolute right-3 top-1/2 -translate-y-1/2 pointer-events-none text-stone-400">▼</div>
                     </div>
                 </div>

                 <div className="space-y-1">
                     <label className="text-[10px] font-black text-stone-400 uppercase tracking-wider ml-1">時間: {minutes}分</label>
                     <input 
                        type="range" 
                        min="5" 
                        max="180" 
                        step="5" 
                        value={minutes} 
                        onChange={(e) => setMinutes(Number(e.target.value))}
                        className="w-full accent-[#6BC99D] h-2 bg-stone-100 rounded-lg appearance-none cursor-pointer"
                     />
                     <div className="flex justify-between text-[9px] font-bold text-stone-300 px-1">
                         <span>5分</span>
                         <span>60分</span>
                         <span>120分</span>
                         <span>180分</span>
                     </div>
                 </div>
             </div>

             <div className="p-4 rounded-2xl bg-[#F0FAF5] border border-[#B2DFDB] text-center space-y-1">
                 <p className="text-xs font-bold text-[#5A7F7F]">消費エネルギー</p>
                 <div className="flex items-baseline justify-center gap-1">
                     <span className="text-3xl font-black text-[#6BC99D]">約 {burnedCalories}</span>
                     <span className="text-sm font-bold text-[#5A7F7F]">kcal</span>
                 </div>
                 <p className="text-[9px] font-bold text-[#5A7F7F] opacity-70">※体重 {weight}kg で計算した目安です</p>
             </div>

             {snackCalories > 0 && (
                 <div className="pt-2 border-t border-dashed border-stone-200">
                     <div className="flex items-start gap-2">
                         <Info size={16} className="text-[#FF9800] shrink-0 mt-0.5" />
                         <p className="text-xs font-bold text-stone-600 leading-relaxed">
                             今日の間食 <span className="text-[#FF9800] font-black">{snackCalories}kcal</span> 分を消費するには、
                             <span className="text-[#6BC99D] font-black"> {activity.label}</span> なら
                             <span className="text-[#6BC99D] font-black text-base"> 約 {minutesToBurnSnack} 分</span> 相当の運動が必要です。
                         </p>
                     </div>
                 </div>
             )}
         </Card>

         {/* ダイエット目標アドバイス */}
         {dietAdvice && (
             <div className="bg-[#FFF8F0] p-6 rounded-[32px] border-2 border-[#FFE0B2] relative overflow-hidden">
                 <div className="absolute top-0 right-0 w-20 h-20 bg-[#FFECB3] rounded-bl-full opacity-30"></div>
                 <div className="relative z-10 space-y-3">
                     <div className="flex items-center gap-2">
                         <Target size={20} className="text-[#FFB74D]" />
                         <h3 className="text-sm font-black text-[#5D4037]">目標達成へのヒント</h3>
                     </div>
                     <p className="text-xs font-bold text-[#8D6E63] leading-relaxed">
                         目標体重に向けて、1日あたり<br/>
                         <span className="text-xl font-black text-[#FF9800]">約 {dietAdvice.dailyBurn} kcal</span><br/>
                         の調整（食事を減らす or 運動で消費）が目安です。
                     </p>
                     <p className="text-[9px] font-bold text-[#A1887F]">
                         ※残り{dietAdvice.days}日で計算した場合の単純計算値です。<br/>
                         体調に合わせて無理なく進めましょう。
                     </p>
                 </div>
             </div>
         )}

         <Button onClick={onBack} variant="cancel" className="w-full min-h-[64px] h-auto text-lg shadow-xl py-3 mt-4">
             もどる
         </Button>
      </main>
    </div>
  );
};

