import { GallerySaver } from '../../src/plugins/GallerySaver';
import { Capacitor } from '@capacitor/core';
import { Filesystem, Directory } from '@capacitor/filesystem';

interface PostureViewProps {
  tokens: number;
  useToken: () => boolean;
  restoreTokens: () => Promise<boolean>;
  lastAnalysis: PostureAnalysis | null;
  onSave: (photo: string, analysis: PostureAnalysis, date: string, sidePhoto?: string | null) => void;
  onClose: () => void;
  onShowPoints: () => void;
  todayWeight?: number;
  openCalendar: (initialDate: string, onConfirm: (date: string) => void) => void;
  onMenuOpen: () => void;
  onCompare?: () => void; 
  onOpenMoveGuide?: () => void;
  isMenuOpen: boolean; 
}

const PostureView: React.FC<PostureViewProps> = ({ tokens, useToken, restoreTokens, lastAnalysis, onSave, onClose, onShowPoints, todayWeight, onMenuOpen, onCompare, onOpenMoveGuide, isMenuOpen }) => {
  const [step, setStep] = useState<'intro' | 'ad_wait' | 'side_wait' | 'analyze' | 'result'>('intro');
  const [frontImage, setFrontImage] = useState<string | null>(null);
  const [sideImage, setSideImage] = useState<string | null>(null);
  const [analysis, setAnalysis] = useState<PostureAnalysis | null>(null);
  const [isSaving, setIsSaving] = useState(false);
  const [hasSaved, setHasSaved] = useState(false);

  useEffect(() => {
    if (isMenuOpen) return;

    if (step === 'analyze' || step === 'ad_wait' || step === 'side_wait') {
        hideBanner();
        hideMrec();
    } else if (step === 'result') {
        hideMrec();
        showBanner();
    } else {
        hideBanner();
        showMrec();
    }
  }, [step, isMenuOpen]);

  const handleStartFront = async () => {
    if (tokens <= 0) { setStep('ad_wait'); return; }
    await hideBanner();
    await hideMrec();
    try {
      const result = await takePhoto(CameraSource.Camera, 'rear');
      setFrontImage(result.base64);
      setStep('side_wait');
    } catch (e: any) { 
        if (e.message !== "CANCELLED") alert(e.message); 
    }
  };

  const startAnalysis = async (sImg: string | null = null) => {
    if (!frontImage) return;
    if (!useToken()) { setStep('ad_wait'); return; }

    await hideBanner();
    await hideMrec();

    setSideImage(sImg);
    setStep('analyze');
    try {
      const result = await analyzePosture(frontImage, sImg);
      setAnalysis(result);
      setStep('result');
    } catch (e: any) {
      alert("解析に失敗しました。");
      setStep('intro');
    }
  };

  const handleStartSide = async () => {
    await hideBanner();
    await hideMrec();
    try {
      const result = await takePhoto(CameraSource.Camera, 'rear');
      startAnalysis(result.base64);
    } catch (e: any) { 
        if (e.message !== "CANCELLED") alert(e.message); 
    }
  };

  const handleRestore = async () => {
    await hideBanner();
    await hideMrec();
    const success = await restoreTokens();
    if (success) {
      setStep('intro');
    }
  };

  const handleSaveAll = async () => {
    if (frontImage && analysis && !isSaving && !hasSaved) {
      setIsSaving(true);
      try {
        const date = getTodayString();
        const fileName = `tabetotto_posture_${date.replace(/-/g, '')}_${Date.now()}.jpg`;

        let gallerySaved = false;
        if (Capacitor.getPlatform() === 'android') {
            try {
                const res = await GallerySaver.saveImage({
                    base64: frontImage,
                    fileName: fileName,
                    album: 'たべとっと。'
                });
                if (res.saved) gallerySaved = true;
            } catch (e) {
                console.warn("Gallery save failed:", e);
            }
        }

        if (!gallerySaved && Capacitor.isNativePlatform()) {
             try {
                await Filesystem.writeFile({
                    path: fileName,
                    data: frontImage,
                    directory: Directory.Documents,
                });
             } catch (fsError) {
                console.error("Device documents save failed", fsError);
             }
        }

        onSave(frontImage, analysis, date, sideImage);
        setHasSaved(true);
      } catch (e) {
        setIsSaving(false);
      } finally {
        setIsSaving(false);
      }
    }
  };

  return (
    <div className="flex flex-col min-h-screen pb-44 w-full no-scrollbar overflow-x-hidden relative">
      {/* Background Decor */}
      <div className="organic-blob w-80 h-80 top-20 -left-40 animate-float-slow will-change-transform" style={{ backgroundColor: THEME.colors.primaryLight }}></div>
      <div className="organic-blob w-64 h-64 bottom-60 -right-32 animate-float-slow will-change-transform" style={{ backgroundColor: THEME.colors.secondaryLight, animationDelay: '1s' }}></div>

      <header className="sticky top-0 z-[60] pt-safe backdrop-blur-md border-b w-full shadow-sm" style={{ backgroundColor: `${THEME.colors.bg}E6`, borderColor: THEME.colors.border }}>
        <div className="px-6 py-3 flex justify-between items-center w-full">
            <div className="flex items-center gap-2">
                <div className="w-11 h-11 rounded-full flex items-center justify-center shadow-[0_15px_35px_-8px_rgba(248,141,141,0.5)] animate-sway transition-transform will-change-transform" style={{ backgroundColor: THEME.colors.primary }}>
                    <ScanFace size={22} className="text-white" strokeWidth={3} />
                </div>
                <div className="flex flex-col">
                  <h1 className="text-xl font-black tracking-widest leading-none" style={{ color: THEME.colors.primary }}>たべとっと。</h1>
                  <span className="text-[8px] font-black tracking-tighter opacity-70" style={{ color: THEME.colors.primary }}>Posture Check</span>
                </div>
            </div>
            <button onClick={onMenuOpen} className="pl-4 pr-3 py-2 rounded-full shadow-md active:scale-95 transition-all flex items-center gap-2 border-2 border-white ring-2" style={{ backgroundColor: THEME.colors.primary, color: 'white', borderColor: 'white', ['--tw-ring-color' as any]: `${THEME.colors.primary}33` }}>
                <span className="text-sm font-black tracking-wide">Menu</span>
                <Menu size={20} strokeWidth={2.5} />
            </button>
        </div>
      </header>

      <main className="mt-8 animate-in slide-in-from-bottom duration-300 relative z-10">
            {step === 'intro' && (
                <div className="px-6 flex flex-col items-center space-y-8 pt-4">
                  {/* アイコン（MealViewと高さを合わせるための余白調整含む） */}
                  <div className="flex items-center justify-center relative w-full mb-4">
                      <div className="relative">
                          <div className="w-24 h-24 rounded-full flex items-center justify-center bg-primary shadow-[0_20px_45px_-12px_rgba(248,141,141,0.6)] animate-sway relative group will-change-transform">
                            <ScanFace size={44} className="text-white" strokeWidth={3} />
                            <div className="absolute -bottom-1 -right-1 w-8 h-8 rounded-full bg-white flex items-center justify-center shadow-lg border-2 border-primary/20">
                              <Sparkles size={16} className="text-primary animate-pulse" />
                            </div>
                          </div>
                      </div>
                  </div>

                  <div className="flex flex-col items-center text-center space-y-2">
                     <h2 className="text-2xl font-black">今の自分を記録</h2>
                     <p className="text-xs font-bold opacity-50">AIが姿勢と体型をチェックします</p>
                     <p className="text-[10px] font-bold text-stone-400 mt-1">※壁を背にして、全身が写るように撮影してください</p>
                  </div>

                  {/* MealViewと同一構造のボタンレイアウト */}
                  <div className="w-full space-y-4 pt-4">
                    <div className="relative group">
                      <Button onClick={handleStartFront} className="w-full min-h-[80px] h-auto py-2 text-xl font-black shadow-xl overflow-hidden relative">
                        <div className="absolute top-0 left-0 w-full h-full bg-black/5 -skew-x-12 translate-x-4 pointer-events-none"></div>
                        <Camera size={26} className="mr-3 relative z-10 shrink-0" /> <span className="relative z-10">撮影をはじめる</span>
                      </Button>
                    </div>

                    <div className="grid grid-cols-2 gap-3">
                        <div className="relative group">
                            {onOpenMoveGuide ? (
                                <Button 
                                    variant="guide" 
                                    onClick={onOpenMoveGuide} 
                                    className="w-full h-full min-h-[64px] py-3"
                                >
                                    <Activity size={20} className="mr-2 shrink-0" />
                                    <span style={{ lineHeight: 1.2 }}>うごきの<br/>目安</span>
                                </Button>
                            ) : (
                                <div className="w-full h-full"></div>
                            )}
                        </div>
                        <div className="relative group">
                            <FileInput 
                                label="アルバム" 
                                onFileSelect={async (b64) => {
                                    try {
                                        const compressed = await compressImage(b64);
                                        setFrontImage(compressed); 
                                        setStep('side_wait');
                                    } catch (e) {
                                        alert("画像の読み込みに失敗しました");
                                    }
                                }} 
                                className="w-full h-full" 
                            />
                        </div>
                    </div>
                  </div>
                </div>
            )}

            {step === 'ad_wait' && (
              <div className="px-6 py-10 animate-in zoom-in-95">
                <div className="w-full p-8 rounded-[40px] bg-white border-4 shadow-xl relative overflow-hidden" style={{ borderColor: THEME.colors.border }}>
                    <div className="absolute top-0 left-0 w-full h-2" style={{ backgroundColor: THEME.colors.primary }}></div>
                    <button onClick={() => setStep('intro')} className="absolute top-4 right-4 p-2 text-stone-300"><X size={20}/></button>
                    <div className="flex flex-col items-center space-y-6 text-center">
                        <div className="w-20 h-20 rounded-3xl flex items-center justify-center shadow-lg transform rotate-3" style={{ backgroundColor: THEME.colors.primaryLight }}>
                            <Gift size={40} className="animate-bounce" style={{ color: THEME.colors.primary }} />
                        </div>
                        <div className="space-y-4">
                            <h3 className="text-xl font-black">チェック回数がゼロです</h3>
                            <div className="space-y-1">
                                <p className="text-xs font-bold text-stone-600">2時間待つと1回分回復（最大2回まで）</p>
                                <p className="text-xs font-bold text-stone-600">広告を見ると4回分まとめて回復（最大4回）</p>
                            </div>
                        </div>
                        <Button onClick={handleRestore} variant="primary" className="w-full min-h-[56px] h-auto py-3 shadow-lg font-black rounded-2xl">
                            <PlayCircle size={20} className="mr-2 shrink-0" /> 広告を見て回復
                        </Button>
                    </div>
                </div>
              </div>
            )}

            {step === 'side_wait' && (
                <div className="px-6 space-y-6 text-center pt-10 pb-20">
                    <div className="space-y-2">
                        <h3 className="text-2xl font-black">次は真横から 🧍</h3>
                        <p className="text-xs font-bold opacity-50">横からの姿勢もチェックしましょう</p>
                    </div>

                    <div className="w-full space-y-4 pt-2">
                        {/* カメラ撮影 */}
                        <div className="relative group">
                            <Button onClick={handleStartSide} className="w-full min-h-[80px] h-auto py-2 text-xl font-black shadow-xl overflow-hidden relative">
                                <div className="absolute top-0 left-0 w-full h-full bg-black/5 -skew-x-12 translate-x-4 pointer-events-none"></div>
                                <Camera size={26} className="mr-3 relative z-10 shrink-0" /> <span className="relative z-10">撮影する</span>
                            </Button>
                        </div>

                        {/* アルバム選択 */}
                        <div className="relative group">
                            <FileInput 
                                label="アルバムから選ぶ" 
                                onFileSelect={async (b64) => {
                                    try {
                                        const compressed = await compressImage(b64);
                                        startAnalysis(compressed);
                                    } catch(e) {
                                        alert("画像の読み込みに失敗しました");
                                    }
                                }} 
                                className="w-full" 
                            />
                        </div>
                    </div>

                    {/* 区切り線とスキップボタン */}
                    <div className="relative py-4">
                        <div className="absolute inset-0 flex items-center" aria-hidden="true">
                            <div className="w-full border-t border-stone-300 border-dashed"></div>
                        </div>
                        <div className="relative flex justify-center">
                            <span className="bg-[#fdfbf7] px-2 text-[10px] font-bold text-stone-400">または</span>
                        </div>
                    </div>

                    <Button 
                        onClick={() => startAnalysis(null)} 
                        variant="outline" 
                        className="w-full min-h-[64px] h-auto py-2 font-black text-stone-500 border-2 border-stone-300 bg-white"
                    >
                        スキップして解析へ進む
                    </Button>
                </div>
            )}

            {step === 'analyze' && (
                <div className="px-6 flex flex-col items-center justify-center space-y-12 py-32">
                    <Loader2 className="animate-spin" style={{ color: THEME.colors.primary }} size={80} />
                    <p className="font-black text-xl animate-bounce">AIが体型をチェック中...</p>
                </div>
            )}

            {step === 'result' && analysis && frontImage && (
                <div className="animate-in zoom-in-95 pb-40">
                    <div className="px-6 space-y-6">
                      <PostureResultCarousel 
                          frontPhoto={frontImage} 
                          sidePhoto={sideImage} 
                          analysis={analysis} 
                          todayWeight={todayWeight}
                      />

                      <Card className="!p-6 bg-white border-2 border-dashed" style={{ borderColor: THEME.colors.border }}>
                          <p className="font-black text-xs mb-2 flex items-center" style={{ color: THEME.colors.primary }}>
                            <span className="mr-1">✨</span> 解析結果
                          </p>
                          <p className="text-xs font-bold leading-relaxed break-words whitespace-normal">{analysis.point}</p>
                      </Card>

                      {hasSaved && onCompare && (
                        <div className="flex flex-col items-end animate-in fade-in slide-in-from-bottom-2">
                           <div className="mb-2 text-[10px] font-bold text-primary animate-pulse">
                              前回と比べて、どう感じますか？
                           </div>
                           <Button onClick={onCompare} variant="outline" className="min-h-[48px] h-auto py-2 text-xs px-6 bg-white border-primary text-primary w-full shadow-sm">
                              <ArrowLeftRight size={16} className="mr-2 shrink-0" /> 前回と見比べる
                           </Button>
                        </div>
                      )}

                      <div className="space-y-4 pt-4">
                          <button 
                            onClick={handleSaveAll} 
                            disabled={isSaving || hasSaved}
                            className={`w-full min-h-[96px] h-auto py-2 text-2xl font-black rounded-[32px] shadow-2xl transition-all flex items-center justify-center ${hasSaved ? 'bg-secondary text-white' : 'bg-primary text-white active:scale-95'}`}
                            style={hasSaved ? { backgroundColor: THEME.colors.secondary } : { backgroundColor: THEME.colors.primary }}
                          >
                            {isSaving ? <Loader2 className="animate-spin mr-2 shrink-0" /> : hasSaved ? <Check className="mr-2 shrink-0" /> : null}
                            {isSaving ? '保存中...' : hasSaved ? '記録しました。✨' : 'アプリにきろくする ✨'}
                          </button>

                          <div className="grid grid-cols-2 gap-3">
                              <button onClick={() => addToCalendar('posture', getTodayString(), analysis)} className="flex flex-col items-center py-5 border-2 rounded-[28px] bg-white shadow-sm active:scale-95 transition-all" style={{ borderColor: THEME.colors.border }}>
                                  <CalendarPlus size={22} style={{ color: THEME.colors.secondary }} /><span className="text-[10px] font-black mt-1">カレンダー</span>
                              </button>
                              <button onClick={() => alert('Posture photos are private.')} className="flex flex-col items-center py-5 border-2 rounded-[28px] bg-white shadow-sm opacity-30" style={{ borderColor: THEME.colors.border }}>
                                  <Share2 size={22} /><span className="text-[10px] font-black mt-1">共有不可</span>
                              </button>
                          </div>

                          {hasSaved && (
                            <Button 
                              variant="cancel"
                              onClick={onClose} 
                              className="w-full min-h-[72px] h-auto py-2 text-xl font-black rounded-[28px] shadow-xl transition-all flex items-center justify-center border-2 active:scale-95"
                            >
                               とじる
                            </Button>
                          )}
                      </div>
                    </div>
                </div>
            )}
      </main>
    </div>
  );
};

export default PostureView;

import React, { useState, useMemo } from 'react';
import { ChevronLeft, Activity, Utensils, Target, Info, AlertCircle } from 'lucide-react';
import { THEME } from '../../theme';
import { Button, Card } from '../UIComponents';
import { UserProfile, DailyRecord } from '../../types';

interface MoveGuideViewProps {
  onBack: () => void;
  user: UserProfile;
  todayRecord: DailyRecord;
  records: DailyRecord[];
}

const ACTIVITIES = [
  { label: "散歩", met: 3.5 },
  { label: "早歩き", met: 4.3 },
  { label: "軽いジョグ", met: 6.0 },
  { label: "筋トレ", met: 5.5 },
  { label: "水泳", met: 6.0 },
  { label: "水泳（やや速い）", met: 8.0 },
  { label: "サイクリング", met: 7.0 },
  { label: "家事", met: 3.0 },
  { label: "掃除機がけ", met: 3.3 },
  { label: "床拭き", met: 3.8 },
  { label: "風呂掃除", met: 4.0 },
  { label: "テニス", met: 7.0 },
  { label: "サッカー", met: 7.0 },
  { label: "バスケットボール", met: 8.0 }
];

const MoveGuideView: React.FC<MoveGuideViewProps> = ({ onBack, user, todayRecord, records }) => {
  const [selectedActivityIndex, setSelectedActivityIndex] = useState(0);
  const [minutes, setMinutes] = useState(30);

  // 体重取得ロジックの改善
  const { weight, isEstimated } = useMemo(() => {
      // 1. 今日の体重
      if (todayRecord.weight && todayRecord.weight > 0) {
          return { weight: todayRecord.weight, isEstimated: false };
      }

      // 2. 過去の最新体重
      // 日付降順にソートして探す
      const sorted = [...records].sort((a, b) => new Date(b.date).getTime() - new Date(a.date).getTime());
      const latest = sorted.find(r => r.weight !== undefined && r.weight > 0);
      if (latest && latest.weight) {
          return { weight: latest.weight, isEstimated: false };
      }

      // 3. 仮定 (50kg)
      return { weight: 50, isEstimated: true };
  }, [todayRecord.weight, records]);

  const activity = ACTIVITIES[selectedActivityIndex];

  // 今日の間食カロリー合計
  const snackCalories = useMemo(() => {
    return todayRecord.mealAnalyses
      .filter(m => m.mealType === 'snack')
      .reduce((acc, m) => acc + m.numericCalories, 0);
  }, [todayRecord]);

  // 消費カロリー計算: METs * kg * hour
  const burnedCalories = Math.round(activity.met * weight * (minutes / 60));

  // 間食分を消費するのに必要な時間 (分)
  const defaultWalkMet = 3.5;
  const minutesWalkToBurn = snackCalories > 0 
    ? Math.round((snackCalories / (defaultWalkMet * weight)) * 60) 
    : 0;

  const minutesToBurnSnack = snackCalories > 0 
    ? Math.round((snackCalories / (activity.met * weight)) * 60) 
    : 0;

  // ダイエット目標に基づく調整目安
  const dietAdvice = useMemo(() => {
    if (user.dietMode?.enabled && user.dietMode.goal === 'loss' && user.targetWeight && user.dietMode.targetDate && todayRecord.weight) {
        const diff = todayRecord.weight - user.targetWeight;
        if (diff <= 0) return null;

        const totalKcal = diff * 7200; // 脂肪1kg = 7200kcalで計算
        const today = new Date();
        const target = new Date(user.dietMode.targetDate);
        const daysLeft = Math.ceil((target.getTime() - today.getTime()) / (1000 * 60 * 60 * 24));

        // 残り日数が計算できない、または過ぎている場合は30日で計算
        const effectiveDays = daysLeft > 0 ? daysLeft : 30;
        const dailyBurn = Math.round(totalKcal / effectiveDays);

        return {
            dailyBurn,
            days: effectiveDays
        };
    }
    return null;
  }, [user, todayRecord.weight]);

  return (
    <div className="flex flex-col min-h-screen pb-44 w-full no-scrollbar overflow-x-hidden relative">
      {/* Background Decor */}
      <div className="organic-blob w-80 h-80 top-20 -right-40 animate-float-slow will-change-transform" style={{ backgroundColor: THEME.colors.primaryLight }}></div>
      <div className="organic-blob w-64 h-64 bottom-60 -left-32 animate-float-slow will-change-transform" style={{ backgroundColor: THEME.colors.secondaryLight, animationDelay: '2s' }}></div>

      <header className="sticky top-0 z-[60] pt-safe backdrop-blur-md border-b w-full shadow-sm" style={{ backgroundColor: `${THEME.colors.bg}E6`, borderColor: THEME.colors.border }}>
        <div className="px-6 py-3 flex items-center justify-between">
            <div className="flex items-center gap-2">
                <button onClick={onBack} className="p-2 -ml-2 rounded-full hover:bg-black/5" style={{ color: THEME.colors.text }}>
                    <ChevronLeft size={24} />
                </button>
                <div className="flex flex-col">
                    <span className="text-xs font-black tracking-widest leading-none" style={{ color: THEME.colors.primary }}>うごきの</span>
                    <h1 className="text-xl font-black tracking-widest leading-none" style={{ color: THEME.colors.primary }}>目安</h1>
                </div>
            </div>
        </div>
      </header>

      <main className="mt-8 px-6 space-y-8 animate-in slide-in-from-right duration-300 relative z-10">
         {/* トップ強調表示エリア */}
         <div className="bg-white p-6 rounded-[32px] border-2 shadow-sm relative overflow-hidden text-center space-y-4" style={{ borderColor: THEME.colors.border }}>
             <div className="absolute top-0 left-0 w-full h-2" style={{ backgroundColor: THEME.colors.secondary }}></div>

             {snackCalories > 0 ? (
                 <>
                     <div className="flex items-center justify-center gap-2">
                         <span className="text-2xl animate-bounce">🍰</span>
                         <span className="text-sm font-bold text-stone-500">今日の間食</span>
                     </div>
                     <div className="text-4xl font-black text-[#5D5745]">
                         {snackCalories} <span className="text-lg font-bold text-[#A0937D]">kcal</span>
                     </div>

                     <div className="flex items-center justify-center gap-4 text-stone-300">
                         <div className="h-[2px] w-8 bg-stone-200 rounded-full"></div>
                         <span className="text-xs font-black">IS EQUAL TO</span>
                         <div className="h-[2px] w-8 bg-stone-200 rounded-full"></div>
                     </div>

                     <div className="flex items-center justify-center gap-2">
                         <span className="text-2xl animate-sway">🚶</span>
                         <span className="text-sm font-bold text-stone-500">散歩なら</span>
                     </div>
                     <div className="text-4xl font-black" style={{ color: THEME.colors.secondary }}>
                         約 {minutesWalkToBurn} <span className="text-lg font-bold text-[#A0937D]">分</span>
                     </div>

                     <p className="text-[10px] font-bold text-stone-400 mt-2 bg-stone-50 py-2 px-4 rounded-xl inline-block">
                         ※この間食は、散歩約{minutesWalkToBurn}分くらいに相当します。<br/>
                         無理のない範囲で体を動かしてみましょう。
                     </p>
                 </>
             ) : (
                 <div className="py-4 space-y-3">
                     <Utensils size={32} className="mx-auto text-stone-300" />
                     <p className="text-sm font-bold text-stone-500">
                         まだ間食の記録がありません。<br/>
                         おやつを食べたら記録してみましょう！
                     </p>
                 </div>
             )}

             <p className="text-[9px] font-bold text-stone-300 absolute bottom-2 right-4">※目安です</p>
         </div>

         {/* シミュレーター */}
