const SideMenu: React.FC<SideMenuProps> = ({ isOpen, onClose, currentView, setView }) => {
  // メニュー構造：親項目(H2)の下に子項目(H3)を配置できるように拡張
  const menuItems = [
    { id: AppView.DASHBOARD, icon: LayoutGrid, label: 'ホーム' },
    { id: AppView.HISTORY, icon: History, label: '記録・グラフ' },
