             <div className="flex flex-col">
                <span className="font-zen-maru font-black text-xl tracking-widest" style={{ color: THEME.colors.primary }}>MENU</span>
             </div>
             <button onClick={onClose} className="p-2 rounded-full bg-stone-100 hover:bg-stone-200 transition-colors" style={{ color: THEME.colors.textLight }}>
                <X size={20} strokeWidth={3} />
