                                >
                                    {/* Connector Line */}
                                    <div className="absolute -left-3 top-1/2 w-3 h-[2px] bg-stone-200" />
                                    <div className="absolute -left-3 top-0 h-1/2 w-[2px] bg-stone-200" />

                                    <div className={`w-7 h-7 rounded-lg flex items-center justify-center shadow-sm ${isChildActive ? 'bg-[#6BC99D] text-white' : 'bg-white text-stone-400 border border-stone-100'}`}>
                                        <child.icon size={14} strokeWidth={2.5} />
                                    </div>
                                    <span className={`font-black text-xs ${isChildActive ? 'text-[#6BC99D]' : 'text-stone-500'}`}>{child.label}</span>

